INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜は〜です (topic + copula)', 'N は N/Adj です', 'X is Y — identifies or describes the topic', 'The は particle marks the sentence topic. です is the polite copula ''is/am/are''. This is the most fundamental Japanese sentence structure.', '[{"japanese":"これは本です。","reading":"これはほんです。","english":"This is a book."},{"japanese":"田中さんは学生です。","reading":"たなかさんはがくせいです。","english":"Tanaka-san is a student."},{"japanese":"私は日本人です。","reading":"わたしはにほんじんです。","english":"I am Japanese."}]', 'particle', 0, 1);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜は〜じゃありません (negative copula)', 'N は N/Adj じゃありません', 'X is not Y — polite negative identification', 'じゃありません (or ではありません in formal writing) is the polite negative form of です. Used to deny or contradict a statement about the topic.', '[{"japanese":"これは本じゃありません。","reading":"これはほんじゃありません。","english":"This is not a book."},{"japanese":"私は先生じゃありません。","reading":"わたしはせんせいじゃありません。","english":"I am not a teacher."},{"japanese":"田中さんは学生じゃありません。","reading":"たなかさんはがくせいじゃありません。","english":"Tanaka-san is not a student."}]', 'particle', 0, 2);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜でした / じゃありませんでした (past copula)', 'N/Adj でした / じゃありませんでした', 'Was / was not — past tense of the copula', 'でした is the polite past affirmative copula. じゃありませんでした is the polite past negative. Used to describe past states or identities.', '[{"japanese":"昨日は休みでした。","reading":"きのうはやすみでした。","english":"Yesterday was a holiday."},{"japanese":"子供の頃、元気じゃありませんでした。","reading":"こどものころ、げんきじゃありませんでした。","english":"I was not energetic as a child."},{"japanese":"彼は学生でした。","reading":"かれはがくせいでした。","english":"He was a student."}]', 'particle', 0, 3);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜が (subject marker)', 'N が V/Adj', 'Marks the grammatical subject, often with focus or new information', 'が marks the subject of a sentence and often carries a sense of emphasis or introduces new information. Contrasts with は which marks a known topic.', '[{"japanese":"猫がいます。","reading":"ねこがいます。","english":"There is a cat."},{"japanese":"雨が降っています。","reading":"あめがふっています。","english":"It is raining."},{"japanese":"誰が来ましたか。","reading":"だれがきましたか。","english":"Who came?"}]', 'particle', 0, 4);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜を (object marker)', 'N を V', 'Marks the direct object of a transitive verb', 'を marks what the action of the verb is directed at. It is always followed by a transitive verb and cannot be used with intransitive verbs.', '[{"japanese":"水を飲みます。","reading":"みずをのみます。","english":"I drink water."},{"japanese":"本を読みました。","reading":"ほんをよみました。","english":"I read a book."},{"japanese":"音楽を聴きます。","reading":"おんがくをききます。","english":"I listen to music."}]', 'particle', 0, 5);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜に (location / time / destination)', 'N に V (ある/いる/行く/来る etc.)', 'Marks location of existence, point in time, or destination', 'に has multiple uses: it marks the location where something exists (with あります/います), a specific point in time, or the destination of movement verbs like 行く and 来る.', '[{"japanese":"机の上に本があります。","reading":"つくえのうえにほんがあります。","english":"There is a book on the desk."},{"japanese":"三時に来てください。","reading":"さんじにきてください。","english":"Please come at three o''clock."},{"japanese":"学校に行きます。","reading":"がっこうにいきます。","english":"I go to school."}]', 'particle', 0, 6);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜で (location of action / means / reason)', 'N で V / N で N', 'Marks the place where an action occurs, the means used, or scope', 'で marks where an action takes place (contrasting with に which marks existence), the tool or means used to do something, or the scope within which something applies.', '[{"japanese":"図書館で勉強します。","reading":"としょかんでべんきょうします。","english":"I study at the library."},{"japanese":"バスで学校に行きます。","reading":"バスでがっこうにいきます。","english":"I go to school by bus."},{"japanese":"日本語で話してください。","reading":"にほんごではなしてください。","english":"Please speak in Japanese."}]', 'particle', 0, 7);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜へ (direction)', 'N へ V (行く/来る/帰る etc.)', 'Marks direction or destination of movement (interchangeable with に for destination)', 'へ indicates the direction toward which movement is heading. It emphasizes the direction rather than arrival, and is often interchangeable with に for destination but sounds slightly more literary.', '[{"japanese":"東京へ行きます。","reading":"とうきょうへいきます。","english":"I am going to Tokyo."},{"japanese":"家へ帰りました。","reading":"いえへかえりました。","english":"I went home."},{"japanese":"日本へようこそ。","reading":"にほんへようこそ。","english":"Welcome to Japan."}]', 'particle', 0, 8);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜と (and / with / quotation)', 'N と N / N と V / V と言う', 'Connects nouns exhaustively (''and''), marks a companion (''with''), or introduces a quote', 'と connects nouns as an exhaustive list (listing all items, unlike や which is partial). It also marks who an action is done together with, and introduces direct or indirect quotations.', '[{"japanese":"りんごとオレンジを買いました。","reading":"りんごとオレンジをかいました。","english":"I bought apples and oranges."},{"japanese":"友達と映画を見ました。","reading":"ともだちとえいがをみました。","english":"I watched a movie with a friend."},{"japanese":"彼は「行きます」と言いました。","reading":"かれは「いきます」といいました。","english":"He said ''I will go''."}]', 'particle', 0, 9);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜の (possessive / noun modifier)', 'N の N', 'Indicates possession, affiliation, or modifies the following noun', 'の links two nouns, showing that the first noun modifies or belongs to the second. It can indicate possession, material, category, or other attributive relationships.', '[{"japanese":"これは私の本です。","reading":"これはわたしのほんです。","english":"This is my book."},{"japanese":"日本語の先生はどこですか。","reading":"にほんごのせんせいはどこですか。","english":"Where is the Japanese teacher?"},{"japanese":"東京の大学に行きたいです。","reading":"とうきょうのだいがくにいきたいです。","english":"I want to go to a university in Tokyo."}]', 'particle', 0, 10);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜も (also / too / even)', 'N も V/Adj', 'Indicates ''also'' or ''too'', adding the marked item to what was already stated', 'も replaces は, が, or を to mean ''also'' or ''too''. When used with negatives it means ''either'' (〜もありません = there isn''t one either). It can also mean ''even'' for emphasis.', '[{"japanese":"私も日本語を勉強しています。","reading":"わたしもにほんごをべんきょうしています。","english":"I am also studying Japanese."},{"japanese":"コーヒーも紅茶もあります。","reading":"コーヒーもこうちゃもあります。","english":"There is both coffee and tea."},{"japanese":"彼女も来ませんでした。","reading":"かのじょもきませんでした。","english":"She didn''t come either."}]', 'particle', 0, 11);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜か (question particle)', 'S か', 'Turns a sentence into a yes/no question', 'か added at the end of a sentence with rising intonation forms a polite question. In casual speech, か alone can sound blunt, so か with ね or a rising tone is common.', '[{"japanese":"これは本ですか。","reading":"これはほんですか。","english":"Is this a book?"},{"japanese":"明日来ますか。","reading":"あしたきますか。","english":"Are you coming tomorrow?"},{"japanese":"日本語が話せますか。","reading":"にほんごがはなせますか。","english":"Can you speak Japanese?"}]', 'particle', 0, 12);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ね / 〜よ (sentence-final particles)', 'S ね / S よ', 'ね seeks agreement (''right?''); よ asserts new information (''you know'')', 'ね is used when seeking confirmation or sharing a feeling with the listener. よ asserts information the speaker believes the listener doesn''t know yet. Both soften the directness of a statement.', '[{"japanese":"いい天気ですね。","reading":"いいてんきですね。","english":"It''s nice weather, isn''t it?"},{"japanese":"このケーキはおいしいですよ。","reading":"このケーキはおいしいですよ。","english":"This cake is delicious, you know."},{"japanese":"明日は休みですね。","reading":"あしたはやすみですね。","english":"Tomorrow is a holiday, right?"}]', 'particle', 0, 13);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'Verb ます form (polite non-past)', 'V-ます', 'Polite present/future affirmative verb form', 'The ます form is the standard polite verb ending used in most daily conversation. It can express habitual actions, general truths, or future intentions depending on context.', '[{"japanese":"毎日学校に行きます。","reading":"まいにちがっこうにいきます。","english":"I go to school every day."},{"japanese":"明日映画を見ます。","reading":"あしたえいがをみます。","english":"I will watch a movie tomorrow."},{"japanese":"日本語を話します。","reading":"にほんごをはなします。","english":"I speak Japanese."}]', 'verb-form', 0, 14);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'Verb ません form (polite negative)', 'V-ません', 'Polite present/future negative verb form', 'ません is the polite negative non-past ending. It negates the action described by the verb. ませんか is also used to make polite invitations or suggestions.', '[{"japanese":"お酒を飲みません。","reading":"おさけをのみません。","english":"I don''t drink alcohol."},{"japanese":"日曜日は学校に行きません。","reading":"にちようびはがっこうにいきません。","english":"I don''t go to school on Sundays."},{"japanese":"分かりません。","reading":"わかりません。","english":"I don''t understand."}]', 'verb-form', 0, 15);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'Verb ました / ませんでした (polite past)', 'V-ました / V-ませんでした', 'Polite past affirmative and negative verb forms', 'ました is the polite past affirmative. ませんでした is the polite past negative. Both express completed actions or states in the past.', '[{"japanese":"昨日本を読みました。","reading":"きのうほんをよみました。","english":"I read a book yesterday."},{"japanese":"朝ごはんを食べませんでした。","reading":"あさごはんをたべませんでした。","english":"I didn''t eat breakfast."},{"japanese":"映画は面白かったですか。","reading":"えいがはおもしろかったですか。","english":"Was the movie interesting?"}]', 'verb-form', 0, 16);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'V て form (te-form)', 'V-て / V-で', 'Connects actions sequentially or serves as base for many grammatical structures', 'The て-form connects two or more actions in sequence. It is also the base for many important constructions: て+います, て+ください, て+もいい, etc. Its form varies by verb group.', '[{"japanese":"手を洗って、ご飯を食べます。","reading":"てをあらって、ごはんをたべます。","english":"I wash my hands and eat rice."},{"japanese":"ドアを開けて、入ってください。","reading":"ドアをあけて、はいってください。","english":"Please open the door and come in."},{"japanese":"起きて、シャワーを浴びました。","reading":"おきて、シャワーをあびました。","english":"I got up and took a shower."}]', 'verb-form', 0, 17);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ています (ongoing action / current state)', 'V-て + います', 'Expresses an ongoing action or a resulting state that continues', 'て+います has two core meanings: an action currently in progress (I am doing X), or a state that results from a past action and continues (the window is open). Context determines which applies.', '[{"japanese":"今、テレビを見ています。","reading":"いま、テレビをみています。","english":"I am watching TV now."},{"japanese":"窓が開いています。","reading":"まどがあいています。","english":"The window is open."},{"japanese":"彼は東京に住んでいます。","reading":"かれはとうきょうにすんでいます。","english":"He lives in Tokyo."}]', 'verb-form', 0, 18);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'い-adjective + です', 'Adj-い です', 'Polite sentence ending with an い-adjective', 'い-adjectives end in い and directly precede nouns or conclude sentences. Adding です makes the sentence polite. The い is part of the adjective, not added—e.g., 高い is already complete.', '[{"japanese":"この映画は面白いです。","reading":"このえいがはおもしろいです。","english":"This movie is interesting."},{"japanese":"今日は寒いですね。","reading":"きょうはさむいですね。","english":"It''s cold today, isn''t it?"},{"japanese":"そのケーキは甘いです。","reading":"そのケーキはあまいです。","english":"That cake is sweet."}]', 'verb-form', 0, 19);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'な-adjective + です', 'Adj-な です (drop な before です)', 'Polite sentence ending with a な-adjective', 'な-adjectives (also called nominal adjectives) require な when directly modifying a noun (静かな部屋) but drop it before です (部屋は静かです). They conjugate differently from い-adjectives.', '[{"japanese":"この公園は静かです。","reading":"このこうえんはしずかです。","english":"This park is quiet."},{"japanese":"彼女はとても親切です。","reading":"かのじょはとてもしんせつです。","english":"She is very kind."},{"japanese":"日本語の勉強は大変ですか。","reading":"にほんごのべんきょうはたいへんですか。","english":"Is studying Japanese hard?"}]', 'verb-form', 0, 20);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'い-adjective negative (〜くないです)', 'Adj-い → Adj-くないです', 'Polite negative form of い-adjectives', 'To negate an い-adjective, drop い and add くないです (or くありません in more formal speech). いい becomes よくない, not いくない — this is the one irregular case.', '[{"japanese":"今日はあまり寒くないです。","reading":"きょうはあまりさむくないです。","english":"It''s not very cold today."},{"japanese":"この映画は面白くないです。","reading":"このえいがはおもしろくないです。","english":"This movie is not interesting."},{"japanese":"この問題は難しくないです。","reading":"このもんだいはむずかしくないです。","english":"This problem is not difficult."}]', 'verb-form', 0, 21);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'い-adjective past (〜かったです)', 'Adj-い → Adj-かったです / くなかったです', 'Past tense of い-adjectives (was / was not)', 'To form the past of an い-adjective, drop い and add かったです (affirmative) or くなかったです (negative). いい becomes よかったです in the past.', '[{"japanese":"昨日は寒かったです。","reading":"きのうはさむかったです。","english":"It was cold yesterday."},{"japanese":"映画はあまり面白くなかったです。","reading":"えいがはあまりおもしろくなかったです。","english":"The movie wasn''t very interesting."},{"japanese":"テストは難しかったですか。","reading":"テストはむずかしかったですか。","english":"Was the test difficult?"}]', 'verb-form', 0, 22);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'な-adjective past (〜でした / じゃなかったです)', 'Adj-な → でした / じゃなかったです', 'Past tense of な-adjectives (was / was not)', 'な-adjectives use でした for the past affirmative and じゃなかったです (or ではありませんでした formally) for the past negative. They conjugate like nouns with the copula.', '[{"japanese":"その部屋は静かでした。","reading":"そのへやはしずかでした。","english":"That room was quiet."},{"japanese":"子供の頃は元気じゃなかったです。","reading":"こどものころはげんきじゃなかったです。","english":"I wasn''t energetic as a child."},{"japanese":"試験は大変でしたか。","reading":"しけんはたいへんでしたか。","english":"Was the exam tough?"}]', 'verb-form', 0, 23);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'これ / それ / あれ / どれ (demonstrative pronouns)', 'これ / それ / あれ / どれ', 'This / that (near listener) / that (far) / which — stand-alone demonstrative pronouns', 'これ refers to something near the speaker, それ to something near the listener, あれ to something far from both. どれ asks ''which one'' among three or more options.', '[{"japanese":"これは何ですか。","reading":"これはなんですか。","english":"What is this?"},{"japanese":"それは私のかばんです。","reading":"それはわたしのかばんです。","english":"That is my bag."},{"japanese":"あれはきれいですね。","reading":"あれはきれいですね。","english":"That (over there) is beautiful, isn''t it?"}]', 'expression', 0, 24);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'この / その / あの / どの + N (demonstrative adjectives)', 'この/その/あの/どの + N', 'This / that / that (far) / which — demonstratives that directly modify nouns', 'Unlike これ/それ/あれ which stand alone, この/その/あの/どの must directly precede a noun. The distance rules are the same: この = near speaker, その = near listener, あの = far from both.', '[{"japanese":"この本は面白いです。","reading":"このほんはおもしろいです。","english":"This book is interesting."},{"japanese":"その映画を見ましたか。","reading":"そのえいがをみましたか。","english":"Did you see that movie?"},{"japanese":"あの山は高いです。","reading":"あのやまはたかいです。","english":"That mountain is tall."}]', 'expression', 0, 25);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'ここ / そこ / あそこ / どこ (location demonstratives)', 'ここ / そこ / あそこ / どこ', 'Here / there (near listener) / over there / where', 'ここ, そこ, あそこ refer to locations using the same speaker/listener/far distance system as other demonstratives. どこ asks about location (''where?'').', '[{"japanese":"駅はここです。","reading":"えきはここです。","english":"The station is here."},{"japanese":"トイレはどこですか。","reading":"トイレはどこですか。","english":"Where is the restroom?"},{"japanese":"あそこに座りましょう。","reading":"あそこにすわりましょう。","english":"Let''s sit over there."}]', 'expression', 0, 26);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜から〜まで (from ... to ...)', 'N/時間 から N/時間 まで', 'From [point] to [point] — marking a range in time or space', 'から marks the starting point and まで marks the ending point. They can be used for time (9 o''clock to 5 o''clock) or place (Tokyo to Osaka). They can be used together or separately.', '[{"japanese":"9時から5時まで働きます。","reading":"くじからごじまではたらきます。","english":"I work from 9 o''clock to 5 o''clock."},{"japanese":"東京から大阪まで新幹線で行きます。","reading":"とうきょうからおおさかまでしんかんせんでいきます。","english":"I go from Tokyo to Osaka by Shinkansen."},{"japanese":"月曜日から金曜日まで学校があります。","reading":"げつようびからきんようびまでがっこうがあります。","english":"There is school from Monday to Friday."}]', 'conjunction', 0, 27);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜たい (want to do)', 'V-stem + たい', 'Expresses the speaker''s desire to do something', 'たい attaches to the verb stem to express a first-person desire. It conjugates like an い-adjective (たくない, たかった). It should not be used to describe a third person''s desire without qualification.', '[{"japanese":"日本に行きたいです。","reading":"にほんにいきたいです。","english":"I want to go to Japan."},{"japanese":"何を食べたいですか。","reading":"なにをたべたいですか。","english":"What do you want to eat?"},{"japanese":"早く家に帰りたいです。","reading":"はやくいえにかえりたいです。","english":"I want to go home soon."}]', 'auxiliary', 0, 28);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ましょう / 〜ましょうか (let''s / shall we?)', 'V-stem + ましょう / ましょうか', 'Proposes a shared action (''let''s do'') or offers to do something (''shall I?'')', 'ましょう is a volitional form expressing ''let''s do X together''. ましょうか softens it to a suggestion or offer, meaning ''shall we?'' or ''shall I?''.', '[{"japanese":"一緒に行きましょう。","reading":"いっしょにいきましょう。","english":"Let''s go together."},{"japanese":"昼ごはんを食べましょうか。","reading":"ひるごはんをたべましょうか。","english":"Shall we eat lunch?"},{"japanese":"始めましょう。","reading":"はじめましょう。","english":"Let''s begin."}]', 'verb-form', 0, 29);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ませんか (won''t you? / invitation)', 'V-stem + ませんか', 'Politely invites the listener to do something together', 'ませんか is used to make polite invitations or suggestions. It is more tentative and polite than ましょう since it asks for the listener''s preference rather than assuming agreement.', '[{"japanese":"一緒に映画を見ませんか。","reading":"いっしょにえいがをみませんか。","english":"Won''t you watch a movie with me?"},{"japanese":"コーヒーを飲みませんか。","reading":"コーヒーをのみませんか。","english":"Would you like to have some coffee?"},{"japanese":"公園を散歩しませんか。","reading":"こうえんをさんぽしませんか。","english":"Shall we take a walk in the park?"}]', 'verb-form', 0, 30);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜てください (please do)', 'V-て + ください', 'Politely requests that someone do something', 'て+ください is a polite request form. It is used to ask someone to do an action. For more formal situations, the plain imperative or お〜ください can be used instead.', '[{"japanese":"ここに座ってください。","reading":"ここにすわってください。","english":"Please sit here."},{"japanese":"名前を書いてください。","reading":"なまえをかいてください。","english":"Please write your name."},{"japanese":"ゆっくり話してください。","reading":"ゆっくりはなしてください。","english":"Please speak slowly."}]', 'expression', 0, 31);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ないでください (please don''t)', 'V-ない + でください', 'Politely requests that someone not do something', 'ないで+ください is formed by attaching でください to the plain negative form. It politely asks someone to refrain from an action. More direct than the formal negative imperative.', '[{"japanese":"ここで写真を撮らないでください。","reading":"ここでしゃしんをとらないでください。","english":"Please don''t take photos here."},{"japanese":"遅刻しないでください。","reading":"ちこくしないでください。","english":"Please don''t be late."},{"japanese":"心配しないでください。","reading":"しんぱいしないでください。","english":"Please don''t worry."}]', 'expression', 0, 32);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜が好き / 嫌い / 上手 / 下手 (likes and abilities)', 'N が 好き/嫌い/上手/下手 です', 'Like / dislike / good at / bad at — uses が to mark the object of feeling or skill', 'These expressions use が rather than を to mark their object. 好き and 嫌い express feelings toward something; 上手 and 下手 describe skill level. They are な-adjectives.', '[{"japanese":"音楽が好きです。","reading":"おんがくがすきです。","english":"I like music."},{"japanese":"料理が上手ですね。","reading":"りょうりがじょうずですね。","english":"You''re good at cooking, aren''t you?"},{"japanese":"虫が嫌いです。","reading":"むしがきらいです。","english":"I dislike insects."}]', 'expression', 0, 33);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ができる (can do / be able to)', 'N が できる / V (plain) + ことができる', 'Expresses ability or possibility — can do something', 'できる can follow a noun (料理ができる = can cook) or こと+が to nominalize a verb phrase (話すことができる = can speak). The noun version is more natural in daily speech.', '[{"japanese":"日本語が少しできます。","reading":"にほんごがすこしできます。","english":"I can speak a little Japanese."},{"japanese":"料理をすることができません。","reading":"りょうりをすることができません。","english":"I cannot cook."},{"japanese":"早く走ることができますか。","reading":"はやくはしることができますか。","english":"Can you run fast?"}]', 'expression', 0, 34);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜にあります / います (existence)', 'N に N が あります / います', 'There is / there are — あります for inanimate objects, います for living beings', 'あります is used for non-living things and abstract objects. います is used for people, animals, and other animate beings. Both use に to mark the location of existence.', '[{"japanese":"机の上に本があります。","reading":"つくえのうえにほんがあります。","english":"There is a book on the desk."},{"japanese":"公園に子供がいます。","reading":"こうえんにこどもがいます。","english":"There are children in the park."},{"japanese":"冷蔵庫にジュースがありますか。","reading":"れいぞうこにジュースがありますか。","english":"Is there any juice in the fridge?"}]', 'verb-form', 0, 35);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜ごろ / ぐらい / くらい (approximately)', '時間/数量 + ごろ / ぐらい / くらい', 'Around / about — approximate time or quantity', 'ごろ is used for approximate points in time (around 3 o''clock). ぐらい/くらい indicate approximate quantities, durations, or degrees (about 3 hours, about 5 people). They are interchangeable.', '[{"japanese":"三時ごろ来てください。","reading":"さんじごろきてください。","english":"Please come around 3 o''clock."},{"japanese":"一時間ぐらいかかります。","reading":"いちじかんぐらいかかります。","english":"It takes about an hour."},{"japanese":"五人くらい来ると思います。","reading":"ごにんくらいくるとおもいます。","english":"I think about 5 people will come."}]', 'expression', 0, 36);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜や〜など (non-exhaustive list)', 'N や N など', 'Things like X and Y — lists items as examples, implying more exist', 'や connects nouns in a partial list, implying other items also exist (unlike と which is exhaustive). など adds ''and so on'' or ''for example'' at the end to make the non-exhaustive nature explicit.', '[{"japanese":"りんごやバナナなどを買いました。","reading":"りんごやバナナなどをかいました。","english":"I bought things like apples and bananas."},{"japanese":"日本語や中国語などが話せます。","reading":"にほんごやちゅうごくごなどがはなせます。","english":"I can speak languages like Japanese and Chinese."},{"japanese":"公園や図書館などに行きました。","reading":"こうえんやとしょかんなどにいきました。","english":"I went to places like the park and library."}]', 'particle', 0, 37);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜前に (before doing)', 'V (plain non-past) + 前に / N の 前に', 'Before doing / before [noun]', '前に after a plain non-past verb means ''before doing that action''. After a noun + の, it means ''before [that thing]''. The verb before 前に does not change tense regardless of when the event happens.', '[{"japanese":"寝る前に歯を磨いてください。","reading":"ねるまえにはをみがいてください。","english":"Please brush your teeth before sleeping."},{"japanese":"食事の前に手を洗います。","reading":"しょくじのまえにてをあらいます。","english":"I wash my hands before meals."},{"japanese":"日本に来る前に日本語を勉強しました。","reading":"にほんにくるまえににほんごをべんきょうしました。","english":"I studied Japanese before coming to Japan."}]', 'conjunction', 0, 38);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', '〜後で (after doing)', 'V-た + 後で / N の 後で', 'After doing — marks a completed action that precedes another', '後で after a past-tense verb (た-form) means ''after doing''. It implies the first action is fully complete before the second begins, contrasting with てから which has a stronger sequential/causal connection.', '[{"japanese":"宿題をした後で、遊びます。","reading":"しゅくだいをしたあとで、あそびます。","english":"After doing homework, I will play."},{"japanese":"食事の後で、コーヒーを飲みます。","reading":"しょくじのあとで、コーヒーをのみます。","english":"I drink coffee after meals."},{"japanese":"仕事の後でどこかに行きますか。","reading":"しごとのあとでどこかにいきますか。","english":"Are you going somewhere after work?"}]', 'conjunction', 0, 39);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N5', 'Question words (いつ / どこ / だれ / なに)', 'いつ / どこ / だれ / なに + V/Adj/です', 'When / where / who / what — the core question words', 'Japanese question words do not move to the front of the sentence the way English ''wh-words'' do. They stay in the same position the answer would occupy. か at the end marks it as a question.', '[{"japanese":"誕生日はいつですか。","reading":"たんじょうびはいつですか。","english":"When is your birthday?"},{"japanese":"お手洗いはどこですか。","reading":"おてあらいはどこですか。","english":"Where is the restroom?"},{"japanese":"それは何ですか。","reading":"それはなんですか。","english":"What is that?"}]', 'expression', 0, 40);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', 'て-form + あげる / くれる / もらう (giving & receiving actions)', 'V-て + あげる / くれる / もらう', 'Do something for someone (giving/receiving the action as a favour)', 'あげる = speaker does for someone else; くれる = someone does for the speaker; もらう = speaker receives the action (often = ''have someone do for me''). Direction determines which to use.', '[{"japanese":"友達に本を貸してあげました。","reading":"ともだちにほんをかしてあげました。","english":"I lent a book to my friend (as a favour)."},{"japanese":"先生が漢字を教えてくれました。","reading":"せんせいがかんじをおしえてくれました。","english":"The teacher taught me kanji (for my benefit)."},{"japanese":"駅まで送ってもらいました。","reading":"えきまでおくってもらいました。","english":"I had someone take me to the station."}]', 'verb-form', 0, 1);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜てみる (try doing)', 'V-て + みる', 'Try doing something to see what happens', 'てみる (from みる ''to see'') expresses trying an action to experience the result. It implies the outcome is unknown and the speaker is attempting it. みる conjugates normally (みました, みてください, etc.).', '[{"japanese":"この料理を食べてみてください。","reading":"このりょうりをたべてみてください。","english":"Please try eating this dish."},{"japanese":"その映画を見てみました。","reading":"そのえいがをみてみました。","english":"I tried watching that movie."},{"japanese":"新しいカフェに行ってみます。","reading":"あたらしいカフェにいってみます。","english":"I''ll try going to the new café."}]', 'verb-form', 0, 2);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ておく (do in advance / preparation)', 'V-て + おく', 'Do something in advance and leave it ready for later', 'ておく expresses doing something as preparation or leaving a completed state. It implies foresight—you do it now so things are ready later. In casual speech it contracts to 〜とく.', '[{"japanese":"パーティーの前に料理を作っておきます。","reading":"パーティーのまえにりょうりをつくっておきます。","english":"I''ll prepare the food in advance for the party."},{"japanese":"旅行の前にホテルを予約しておきました。","reading":"りょこうのまえにホテルをよやくしておきました。","english":"I reserved the hotel in advance before the trip."},{"japanese":"資料を読んでおいてください。","reading":"しりょうをよんでおいてください。","english":"Please read the materials in advance."}]', 'verb-form', 0, 3);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜てしまう (completed / regretful action)', 'V-て + しまう', 'Completely finish doing / end up doing (often with regret or surprise)', 'てしまう expresses either a completed action (focus on finality) or an action that happened unintentionally or regrettably. In casual speech it contracts to 〜ちゃう / 〜じゃう.', '[{"japanese":"宿題を全部やってしまいました。","reading":"しゅくだいをぜんぶやってしまいました。","english":"I finished all the homework (completely)."},{"japanese":"財布を忘れてしまいました。","reading":"さいふをわすれてしまいました。","english":"I went and forgot my wallet."},{"japanese":"ケーキを全部食べてしまった。","reading":"ケーキをぜんぶたべてしまった。","english":"I ended up eating all the cake."}]', 'verb-form', 0, 4);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ていく / てくる (directional continuity)', 'V-て + いく / くる', 'Do and go away / do and come (expressing action continuing in a direction)', 'ていく expresses something moving away or a change progressing into the future. てくる expresses something coming toward the speaker, approaching, or a change coming up to now. Both describe direction of change.', '[{"japanese":"気温がどんどん上がっていきます。","reading":"きおんがどんどんあがっていきます。","english":"The temperature keeps rising (going forward)."},{"japanese":"日本語が少しずつ上手になってきました。","reading":"にほんごがすこしずつじょうずになってきました。","english":"My Japanese has gradually improved (up to now)."},{"japanese":"弁当を持っていきます。","reading":"べんとうをもっていきます。","english":"I''ll take a bento box with me."}]', 'verb-form', 0, 5);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', 'Potential form 〜られる / 〜える (can / be able to)', 'V → potential form (-られる / -える)', 'Express ability to do something — ''can do''', 'Group 1 verbs: replace る with られる (食べる→食べられる). Group 2 verbs: replace the final u sound with the eru form (書く→書ける). Irregular: する→できる, くる→こられる. Colloquially ら is often dropped from Group 1.', '[{"japanese":"日本語が少し話せます。","reading":"にほんごがすこしはなせます。","english":"I can speak a little Japanese."},{"japanese":"一人で料理が作れますか。","reading":"ひとりでりょうりがつくれますか。","english":"Can you cook by yourself?"},{"japanese":"辛い食べ物が食べられません。","reading":"からいたべものがたべられません。","english":"I cannot eat spicy food."}]', 'verb-form', 0, 6);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', 'Passive form 〜られる (be done to / passive)', 'V → passive form (-られる / -される)', 'The subject receives the action from someone else', 'Group 1: replace る with られる (食べられる = be eaten). Group 2: replace final u with される/われる etc. (書く→書かれる). The agent performing the action is marked by に. Used for direct harm, historical facts, and formal writing.', '[{"japanese":"先生に褒められました。","reading":"せんせいにほめられました。","english":"I was praised by the teacher."},{"japanese":"雨に降られて、濡れました。","reading":"あめにふられて、ぬれました。","english":"I got rained on and got wet."},{"japanese":"この小説は多くの人に読まれています。","reading":"このしょうせつはおおくのひとによまれています。","english":"This novel is read by many people."}]', 'verb-form', 0, 7);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', 'Causative form 〜させる (make / let someone do)', 'V → causative form (-させる / -せる)', 'Make or let someone do something', 'Group 1: replace る with させる. Group 2: replace final u vowel with aseru/seru. Irregular: する→させる, くる→こさせる. The person made to do something is marked by に (or を in some cases). Context determines ''make'' vs. ''let''.', '[{"japanese":"先生は学生に作文を書かせました。","reading":"せんせいはがくせいにさくぶんをかかせました。","english":"The teacher made the students write an essay."},{"japanese":"子供に好きなものを食べさせます。","reading":"こどもにすきなものをたべさせます。","english":"I let my child eat what they like."},{"japanese":"部下に残業させてしまいました。","reading":"ぶかにざんぎょうさせてしまいました。","english":"I ended up making my subordinates work overtime."}]', 'verb-form', 0, 8);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜と思います (I think that ...)', 'S (plain) + と思います', 'Express an opinion or conjecture — ''I think that ...''', 'と思います follows a plain-form clause to express the speaker''s personal opinion or guess. For negative opinions, ないと思います (think not) is more natural than と思いません.', '[{"japanese":"明日は晴れると思います。","reading":"あしたははれるとおもいます。","english":"I think it will be sunny tomorrow."},{"japanese":"彼は来ないと思います。","reading":"かれはこないとおもいます。","english":"I think he won''t come."},{"japanese":"この問題は難しいと思います。","reading":"このもんだいはむずかしいとおもいます。","english":"I think this problem is difficult."}]', 'expression', 0, 9);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜と言います / と言っていました (say / said)', '「quote」 と言います / S (plain) + と言っていました', 'Say / is called / said that — reporting speech', 'と言います reports direct or indirect speech. と言っていました reports what someone was saying (progressive past), often used for hearsay. いう can also mean ''be called'' (〜という = called/named).', '[{"japanese":"田中さんは「明日来ます」と言いました。","reading":"たなかさんは「あしたきます」といいました。","english":"Tanaka-san said ''I''ll come tomorrow''."},{"japanese":"これを何と言いますか。","reading":"これをなんといいますか。","english":"What do you call this?"},{"japanese":"先生は試験があると言っていました。","reading":"せんせいはしけんがあるといっていました。","english":"The teacher was saying there would be a test."}]', 'expression', 0, 10);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜そうです (looks like / I heard that)', 'V-stem / Adj-stem + そうです (appearance) / S (plain) + そうです (hearsay)', 'Looks like [visual inference] OR I heard that [reported information]', 'Two different そうです: (1) Appearance/visual: V-stem or adj-stem + そう (今にも雨が降りそう = looks like it''ll rain). (2) Hearsay: plain clause + そうです (田中さんが来るそうです = I heard Tanaka is coming). The forms are distinct.', '[{"japanese":"この料理はおいしそうですね。","reading":"このりょうりはおいしそうですね。","english":"This dish looks delicious."},{"japanese":"明日は雨が降るそうです。","reading":"あしたはあめがふるそうです。","english":"I heard it will rain tomorrow."},{"japanese":"彼女は忙しそうでした。","reading":"かのじょはいそがしそうでした。","english":"She looked busy."}]', 'expression', 0, 11);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜らしい (apparently / seems like)', 'S (plain) + らしい / N + らしい', 'Apparently / it seems — inference from evidence or hearsay, or ''typical of''', 'らしい has two meanings: (1) Evidential inference based on information (''apparently'', ''it seems like'') — similar to そうです (hearsay). (2) Typicality: N + らしい means ''typical of N'' or ''-like''. The context disambiguates.', '[{"japanese":"彼女は来ないらしいです。","reading":"かのじょはこないらしいです。","english":"It seems she''s not coming."},{"japanese":"あの人は有名な歌手らしいです。","reading":"あのひとはゆうめいなかしゅらしいです。","english":"Apparently that person is a famous singer."},{"japanese":"それは日本らしい風景ですね。","reading":"それはにほんらしいふうけいですね。","english":"That''s a very Japanese-like scenery, isn''t it?"}]', 'auxiliary', 0, 12);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ようです (appears to be / seems)', 'S (plain) + ようです / N の + ようです', 'It seems / appears — inference based on objective observation', 'ようです expresses an inference based on evidence observed by the speaker. It is more formal and objective than みたいです (the casual equivalent). It does not express hearsay like そうです.', '[{"japanese":"彼は怒っているようです。","reading":"かれはおこっているようです。","english":"He appears to be angry."},{"japanese":"今日の試験は難しかったようですね。","reading":"きょうのしけんはむずかしかったようですね。","english":"Today''s exam seems to have been difficult."},{"japanese":"外は雨のようです。","reading":"そとはあめのようです。","english":"It appears to be raining outside."}]', 'auxiliary', 0, 13);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ために (in order to / because of)', 'V (plain non-past) + ために [purpose] / N の + ために [cause or benefit]', 'For the purpose of / for the sake of / because of', 'ために after a plain verb expresses purpose (in order to do). After a noun + の or plain past verb it can express cause (because of) or beneficiary (for the sake of). Subject of main and subordinate clauses must usually differ for purpose use.', '[{"japanese":"日本語を学ぶために日本に来ました。","reading":"にほんごをまなぶためににほんにきました。","english":"I came to Japan in order to learn Japanese."},{"japanese":"家族のために働いています。","reading":"かぞくのためにはたらいています。","english":"I work for the sake of my family."},{"japanese":"病気のために学校を休みました。","reading":"びょうきのためにがっこうをやすみました。","english":"I was absent from school because of illness."}]', 'conjunction', 0, 14);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ように (so that / in order to)', 'V (plain) + ように V (intentional)', 'So that / in order that — expresses a goal the speaker works toward', 'ように is used when the goal is a state or condition (often using verbs like なる, できる, or potential forms) rather than a direct action. It implies the main action is done so the ように clause becomes true.', '[{"japanese":"聞こえるように大きな声で話してください。","reading":"きこえるようにおおきなこえではなしてください。","english":"Please speak loudly so that I can hear you."},{"japanese":"忘れないようにメモしました。","reading":"わすれないようにメモしました。","english":"I made a note so that I wouldn''t forget."},{"japanese":"日本語が話せるように練習しています。","reading":"にほんごがはなせるようにれんしゅうしています。","english":"I''m practicing so that I can speak Japanese."}]', 'conjunction', 0, 15);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ようになる (come to / reach a state where)', 'V (plain) + ようになる / V-potential + ようになる', 'Come to do / reach a point where — marks a change of state over time', 'ようになる expresses a gradual or eventual change: something that wasn''t possible or happening before now is. Often used with potential forms or verbs of perception to describe acquired abilities or habits.', '[{"japanese":"日本語で夢を見るようになりました。","reading":"にほんごでゆめをみるようになりました。","english":"I''ve come to dream in Japanese."},{"japanese":"辛い食べ物が食べられるようになりました。","reading":"からいたべものがたべられるようになりました。","english":"I''ve come to be able to eat spicy food."},{"japanese":"毎朝走るようになりました。","reading":"まいあさはしるようになりました。","english":"I''ve started running every morning."}]', 'expression', 0, 16);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜なければならない (must / have to)', 'V-なければ + ならない / いけない', 'Must do / have to do — obligation', 'なければならない expresses strong obligation. The casual form is なきゃ (ならない). ないといけない is an alternative. The choice between ならない and いけない is a matter of style; ならない is slightly more formal.', '[{"japanese":"毎日薬を飲まなければなりません。","reading":"まいにちくすりをのまなければなりません。","english":"I have to take medicine every day."},{"japanese":"もっと勉強しなければならないと思います。","reading":"もっとべんきょうしなければならないとおもいます。","english":"I think I have to study more."},{"japanese":"明日早く起きなければいけません。","reading":"あしたはやくおきなければいけません。","english":"I have to get up early tomorrow."}]', 'expression', 0, 17);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜てもいいです (it is okay to / may)', 'V-て + もいいです', 'Permission — it is okay/allowed to do something', 'てもいいです grants or asks for permission to do something. The question form てもいいですか is very common for requesting permission. It can be made stronger with かまいません (''I don''t mind'').', '[{"japanese":"ここに座ってもいいですか。","reading":"ここにすわってもいいですか。","english":"May I sit here?"},{"japanese":"写真を撮ってもいいですよ。","reading":"しゃしんをとってもいいですよ。","english":"You may take photos."},{"japanese":"帰ってもいいです。","reading":"かえってもいいです。","english":"You may go home."}]', 'expression', 0, 18);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜てはいけません (must not / prohibited)', 'V-て + はいけません / はだめです', 'Must not do — prohibition', 'てはいけません is a polite prohibition. The casual form is てはだめ or ちゃだめ. It is typically used by authority figures or in rules. It is stronger than ないでください (please don''t).', '[{"japanese":"ここでタバコを吸ってはいけません。","reading":"ここでタバコをすってはいけません。","english":"You must not smoke here."},{"japanese":"試験中に話してはいけません。","reading":"しけんちゅうにはなしてはいけません。","english":"You must not talk during the exam."},{"japanese":"嘘をついてはだめですよ。","reading":"うそをついてはだめですよ。","english":"You mustn''t tell lies."}]', 'expression', 0, 19);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜たほうがいい (had better / should)', 'V-た + ほうがいい (affirmative advice) / V-ない + ほうがいい (negative advice)', 'Had better do / you should — giving advice', 'たほうがいい (past plain form + ほうがいい) gives advice that something is recommended. For negative advice, use ないほうがいい (shouldn''t do). Both are softer than must/have-to expressions.', '[{"japanese":"早く寝たほうがいいですよ。","reading":"はやくねたほうがいいですよ。","english":"You had better go to sleep early."},{"japanese":"無理をしないほうがいいと思います。","reading":"むりをしないほうがいいとおもいます。","english":"I think you shouldn''t push yourself too hard."},{"japanese":"医者に行ったほうがいいですよ。","reading":"いしゃにいったほうがいいですよ。","english":"You should go to the doctor."}]', 'expression', 0, 20);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜なくてもいいです (don''t have to)', 'V-なくて + もいいです', 'Don''t have to / need not — absence of obligation', 'なくてもいいです says that something is not required. It is the opposite of なければならない. The casual form is なくていい. Often used to give the listener relief from an expected obligation.', '[{"japanese":"明日は来なくてもいいです。","reading":"あしたはこなくてもいいです。","english":"You don''t have to come tomorrow."},{"japanese":"全部食べなくてもいいですよ。","reading":"ぜんぶたべなくてもいいですよ。","english":"You don''t have to eat everything."},{"japanese":"スーツを着なくてもいいですか。","reading":"スーツをきなくてもいいですか。","english":"Is it okay if I don''t wear a suit?"}]', 'expression', 0, 21);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜かもしれません (might / maybe)', 'S (plain) + かもしれません', 'Might / maybe / possibly — expressing uncertainty', 'かもしれません expresses possibility without strong confidence. The plain form is かもしれない (casual: かも). It does not indicate probability as high as でしょう or はずです. Can follow plain-form clauses of any tense.', '[{"japanese":"明日は雨が降るかもしれません。","reading":"あしたはあめがふるかもしれません。","english":"It might rain tomorrow."},{"japanese":"彼女はもう帰ったかもしれない。","reading":"かのじょはもうかえったかもしれない。","english":"She might have already gone home."},{"japanese":"この薬は効かないかもしれません。","reading":"このくすりはきかないかもしれません。","english":"This medicine might not work."}]', 'auxiliary', 0, 22);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜でしょう / だろう (probably / right?)', 'S (plain) + でしょう / だろう', 'Probably / I expect — conjecture, or seeks confirmation (rising intonation)', 'でしょう / だろう express the speaker''s confident conjecture. With rising intonation (でしょう?), it seeks the listener''s agreement. It is more confident than かもしれない. だろう is the plain/casual equivalent.', '[{"japanese":"明日は晴れるでしょう。","reading":"あしたははれるでしょう。","english":"It will probably be sunny tomorrow."},{"japanese":"彼は知っているでしょう？","reading":"かれはしっているでしょう？","english":"He probably knows, right?"},{"japanese":"試験は難しかっただろう。","reading":"しけんはむずかしかっただろう。","english":"The exam was probably difficult."}]', 'auxiliary', 0, 23);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ば conditional (if)', 'V-ば / Adj-ければ / N + であれば', 'If [condition], [result] — general or hypothetical conditional', 'ば expresses a general or hypothetical condition: ''if A, then B''. Both the condition and result can be hypothetical. It often implies the result naturally follows from the condition. Not used for habitual conditions (use と) or one-time future events as naturally as たら.', '[{"japanese":"安ければ買います。","reading":"やすければかいます。","english":"If it''s cheap, I''ll buy it."},{"japanese":"時間があれば手伝います。","reading":"じかんがあればてつだいます。","english":"If I have time, I''ll help."},{"japanese":"この薬を飲めば治るでしょう。","reading":"このくすりをのめばなおるでしょう。","english":"If you take this medicine, you''ll probably get better."}]', 'conditional', 0, 24);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜たら conditional (when/if — after completion)', 'V-たら / Adj-かったら / N + だったら', 'When/if [action or state is completed], then — sequential or hypothetical', 'たら is the most versatile conditional. It can express: (1) sequence: ''once A happens, B''; (2) hypothetical: ''if A were the case, B''; (3) discovery: ''when I did A, I found B''. It focuses on the completion of the condition.', '[{"japanese":"家に着いたら電話してください。","reading":"いえについたらでんわしてください。","english":"Please call me when you get home."},{"japanese":"お金があったら旅行したいです。","reading":"おかねがあったらりょこうしたいです。","english":"If I had money, I''d want to travel."},{"japanese":"窓を開けたら、鳥が入ってきました。","reading":"まどをあけたら、とりがはいってきました。","english":"When I opened the window, a bird came in."}]', 'conditional', 0, 25);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜なら conditional (if that''s the case)', 'S (plain) + なら / N + なら', 'If that is the case / if we''re talking about — contextual conditional', 'なら is used when the condition is something already known from context, the conversation, or what the listener said. It means ''if what you say is true / given that context''. It is not used for things the speaker discovers independently.', '[{"japanese":"東京に行くなら、スカイツリーを見てください。","reading":"とうきょうにいくなら、スカイツリーをみてください。","english":"If you''re going to Tokyo, please see the Sky Tree."},{"japanese":"日本語が難しいなら、一緒に勉強しましょう。","reading":"にほんごがむずかしいなら、いっしょにべんきょうしましょう。","english":"If Japanese is difficult, let''s study together."},{"japanese":"彼女が行かないなら、私も行きません。","reading":"かのじょがいかないなら、わたしもいきません。","english":"If she''s not going, I won''t go either."}]', 'conditional', 0, 26);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ても (even if / even though)', 'V-て + も / Adj-くても / N + でも', 'Even if / even though — the main clause holds regardless of the condition', 'ても indicates a concessive condition: regardless of A, B still holds. It is used for hypothetical situations (even if X happens, Y is still the case) and actual concessions (even though X is happening, Y).', '[{"japanese":"雨が降っても、試合は続けます。","reading":"あめがふっても、しあいはつづけます。","english":"Even if it rains, we''ll continue the game."},{"japanese":"高くても、買いたいです。","reading":"たかくても、かいたいです。","english":"Even if it''s expensive, I want to buy it."},{"japanese":"疲れていても、仕事をしなければなりません。","reading":"つかれていても、しごとをしなければなりません。","english":"Even though I''m tired, I have to work."}]', 'conditional', 0, 27);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜のに (even though — unexpected / regret)', 'S (plain) + のに', 'Even though / despite — expresses surprise, dissatisfaction, or regret', 'のに is a concessive that carries emotional weight: the speaker finds the result unexpected, disappointing, or contrary to what they expected. It differs from ても in that ても is neutral while のに implies the speaker''s feelings.', '[{"japanese":"たくさん勉強したのに、試験に落ちました。","reading":"たくさんべんきょうしたのに、しけんにおちました。","english":"Even though I studied a lot, I failed the exam."},{"japanese":"せっかく来たのに、彼女はいませんでした。","reading":"せっかくきたのに、かのじょはいませんでした。","english":"I went to all the trouble of coming, but she wasn''t there."},{"japanese":"あんなに練習したのに、うまくできませんでした。","reading":"あんなにれんしゅうしたのに、うまくできませんでした。","english":"Despite all that practice, I couldn''t do it well."}]', 'conjunction', 0, 28);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜から (because — reason/cause)', 'S (plain/polite) + から', 'Because / since — states a reason for the main clause', 'から gives a reason or cause. It can follow plain or polite forms (both are acceptable). The reason clause comes first. It is more subjective and direct than ので, and can follow complete sentences.', '[{"japanese":"眠いから、早く寝ます。","reading":"ねむいから、はやくねます。","english":"I''ll go to bed early because I''m sleepy."},{"japanese":"お腹が空いているから、何か食べましょう。","reading":"おなかがすいているから、なにかたべましょう。","english":"Since I''m hungry, let''s eat something."},{"japanese":"日本語が好きだから、毎日勉強しています。","reading":"にほんごがすきだから、まいにちべんきょうしています。","english":"Because I like Japanese, I study every day."}]', 'conjunction', 0, 29);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ので (because — softer reason)', 'S (plain) + ので / Adj-な + なので / N + なので', 'Because / since — gives a reason with softer, more polite tone', 'ので is similar to から but carries a softer, more objective tone. It sounds less assertive and is preferred in formal/polite contexts. な-adjectives and nouns use なので before it.', '[{"japanese":"体調が悪いので、早退してもいいですか。","reading":"たいちょうがわるいので、そうたいしてもいいですか。","english":"May I leave early since I''m not feeling well?"},{"japanese":"明日試験があるので、今夜は勉強します。","reading":"あしたしけんがあるので、こんやはべんきょうします。","english":"I''ll study tonight because there''s an exam tomorrow."},{"japanese":"雨なので、傘を持って行ってください。","reading":"あめなので、かさをもっていってください。","english":"Please bring an umbrella since it''s raining."}]', 'conjunction', 0, 30);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜時 (when / at the time of)', 'V (plain) / Adj / N の + 時', 'When / at the time of — marks a point in time or circumstance', '時 follows a clause to mean ''when A [happens/happened]''. If the 時 clause uses the same tense as the main clause, they are simultaneous. The relationship between tenses of 時 clause and main clause conveys important timing nuance.', '[{"japanese":"子供の時、よく海で泳ぎました。","reading":"こどものとき、よくうみでおよぎました。","english":"When I was a child, I often swam in the sea."},{"japanese":"困った時は、相談してください。","reading":"こまったときは、そうだんしてください。","english":"When you''re in trouble, please consult me."},{"japanese":"日本に来る時、何を持ってきましたか。","reading":"にほんにくるとき、なにをもってきましたか。","english":"What did you bring when you came to Japan?"}]', 'conjunction', 0, 31);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜てから (after doing — emphasising sequence)', 'V-て + から', 'After doing — emphasises a strict temporal sequence', 'てから is stronger than 後で: it emphasises that the first action must be fully completed before the second begins. 後で can be separated in time; てから implies immediate succession or strict ordering.', '[{"japanese":"手を洗ってから、食べます。","reading":"てをあらってから、たべます。","english":"After washing my hands, I''ll eat."},{"japanese":"よく考えてから、決めてください。","reading":"よくかんがえてから、きめてください。","english":"Please decide after thinking it through carefully."},{"japanese":"大学を卒業してから、就職しました。","reading":"だいがくをそつぎょうしてから、しゅうしょくしました。","english":"After graduating from university, I found a job."}]', 'conjunction', 0, 32);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜という N (a N called / which says)', '「word/S」 + という + N', 'A [N] called / known as / which says — attaches a name or description to a noun', 'という connects a quoted name, description, or reported content to a following noun. 「東京」という都市 = ''a city called Tokyo''. It can also quote the content of a sentence: 「明日来る」という連絡 = ''a message saying he''ll come tomorrow''.', '[{"japanese":"「さくら」という名前の犬を飼っています。","reading":「「さくら」というなまえのいぬをかっています。","english":"I have a dog named Sakura."},{"japanese":"「JLPT」という試験を知っていますか。","reading":"「JLPT」というしけんをしっていますか。","english":"Do you know the exam called JLPT?"},{"japanese":"明日休むという連絡が来ました。","reading":"あしたやすむというれんらくがきました。","english":"A message came saying he''ll be absent tomorrow."}]', 'expression', 0, 33);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ことができる (can do — formal ability)', 'V (plain non-past) + ことができる', 'Can / be able to — more formal than the potential verb form', 'ことができる is the formal/written equivalent of the potential verb form. It nominalizes the verb with こと and then applies できる. It is more verbose but used in formal writing, contracts, and set expressions.', '[{"japanese":"日本語で手紙を書くことができます。","reading":"にほんごでてがみをかくことができます。","english":"I am able to write a letter in Japanese."},{"japanese":"この建物に入ることができません。","reading":"このたてもののにはいることができません。","english":"You cannot enter this building."},{"japanese":"一人で料理することができますか。","reading":"ひとりでりょうりすることができますか。","english":"Can you cook by yourself?"}]', 'expression', 0, 34);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ことがある (there are times when / have done before)', 'V (plain non-past) + ことがある [sometimes] / V-た + ことがある [experience]', 'Sometimes do / have ever done — habitual or experiential', 'Non-past + ことがある = ''there are times when I do X / I sometimes do X''. Past + ことがある = ''I have the experience of doing X (at least once)''. The tense of the verb before こと is key.', '[{"japanese":"電車の中で眠ってしまうことがあります。","reading":"でんしゃのなかでねむってしまうことがあります。","english":"There are times when I fall asleep on the train."},{"japanese":"富士山に登ったことがありますか。","reading":"ふじさんにのぼったことがありますか。","english":"Have you ever climbed Mt. Fuji?"},{"japanese":"日本語で夢を見ることがあります。","reading":"にほんごでゆめをみることがあります。","english":"I sometimes dream in Japanese."}]', 'expression', 0, 35);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ことにする (decide to)', 'V (plain) + ことにする', 'Decide to do — marks a personal decision', 'ことにする indicates a decision or resolution made by the speaker. ことにしている (habitual form) means ''I make it a rule to / I always do X''. It focuses on the decision-making moment, not an already existing rule.', '[{"japanese":"毎朝ジョギングすることにしました。","reading":"まいあさジョギングすることにしました。","english":"I have decided to jog every morning."},{"japanese":"お酒を飲まないことにしました。","reading":"おさけをのまないことにしました。","english":"I''ve decided not to drink alcohol."},{"japanese":"健康のために野菜を食べることにしています。","reading":"けんこうのためにやさいをたべることにしています。","english":"I make it a rule to eat vegetables for my health."}]', 'expression', 0, 36);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ことになる (it has been decided that)', 'V (plain) + ことになる / ことになっている', 'It has been decided / it turns out that — external decision or established rule', 'ことになる expresses an outcome that was decided by external circumstances or others (not the speaker''s personal decision — that is ことにする). ことになっている means ''it has been arranged that / it is a rule that''.', '[{"japanese":"来月から東京で働くことになりました。","reading":"らいげつからとうきょうではたらくことになりました。","english":"It has been decided that I''ll work in Tokyo from next month."},{"japanese":"この道は夜間通行禁止ということになっています。","reading":"このみちはやかんつうこうきんしということになっています。","english":"It is an established rule that this road is off-limits at night."},{"japanese":"会議は毎週月曜日に行うことになっています。","reading":"かいぎはまいしゅうげつようびにおこなうことになっています。","english":"Meetings are scheduled to be held every Monday."}]', 'expression', 0, 37);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜だけ (only / just)', 'N / V (plain) + だけ', 'Only / just — limits the scope to the item or action mentioned', 'だけ marks a limit: ''only X, nothing else''. It can modify nouns, plain-form verbs, and adjectives. It is more neutral in tone than しか〜ない (which always appears with a negative and implies insufficiency).', '[{"japanese":"一つだけ質問があります。","reading":"ひとつだけしつもんがあります。","english":"I only have one question."},{"japanese":"できるだけ早く来てください。","reading":"できるだけはやくきてください。","english":"Please come as quickly as possible."},{"japanese":"見るだけで、買いません。","reading":"みるだけで、かいません。","english":"I''ll just look; I won''t buy anything."}]', 'particle', 0, 38);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜しか〜ない (nothing but / only — with negative)', 'N / V + しか + negative verb', 'Only (with negative) — emphasises insufficiency or restriction', 'しか must always be paired with a negative verb. It implies that the amount or option is insufficient or exclusive: ''there is nothing but X'' or ''I can only do X (and that''s not enough)''. More emphatic than だけ.', '[{"japanese":"財布に100円しかありません。","reading":"さいふに100えんしかありません。","english":"I only have 100 yen in my wallet."},{"japanese":"ここにはお茶しかありませんよ。","reading":"ここにはおちゃしかありませんよ。","english":"There''s only tea here."},{"japanese":"日本語は少ししか話せません。","reading":"にほんごはすこししかはなせません。","english":"I can only speak a little Japanese."}]', 'particle', 0, 39);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ばかり (nothing but / just did / full of)', 'V-た + ばかり [just did] / N + ばかり [nothing but] / V + ばかりいる [do nothing but]', 'Just did / nothing but / full of — various senses of exclusivity or recency', 'ばかり has multiple uses: (1) V-た + ばかり = just finished (very recently). (2) N + ばかり = nothing but, only (disparaging). (3) V + ばかりいる = does nothing but. Context determines which meaning applies.', '[{"japanese":"今日本に着いたばかりです。","reading":"いまにほんについたばかりです。","english":"I just arrived in Japan."},{"japanese":"彼はゲームばかりしています。","reading":"かれはゲームばかりしています。","english":"He does nothing but play games."},{"japanese":"この店は外国人ばかりです。","reading":"このみせはがいこくじんばかりです。","english":"This shop is full of foreigners."}]', 'particle', 0, 40);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜間に (while / during — a change occurs)', 'V-ている + 間に / N の 間に', 'While / during — something else happens in that interval', '間に (あいだに) expresses that a separate event occurs during the time span of another. The main clause action often happens without the subject''s awareness or as a separate event. Different from 〜ながら which requires the same subject.', '[{"japanese":"先生が話している間に、メモを取りました。","reading":"せんせいがはなしているあいだに、メモをとりました。","english":"While the teacher was talking, I took notes."},{"japanese":"休みの間に、本を10冊読みました。","reading":"やすみのあいだに、ほんを10さつよみました。","english":"During the break, I read 10 books."},{"japanese":"出かけている間に、荷物が届きました。","reading":"でかけているあいだに、にもつがとどきました。","english":"While I was out, a package arrived."}]', 'conjunction', 0, 41);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ながら (while doing two things simultaneously)', 'V-stem + ながら + V (main action)', 'While doing — two actions performed simultaneously by the same subject', 'ながら connects two actions done by the same person at the same time. The main action is the second verb; ながら modifies it. It cannot be used when the subject is different or when actions are sequential.', '[{"japanese":"音楽を聴きながら勉強します。","reading":"おんがくをききながらべんきょうします。","english":"I study while listening to music."},{"japanese":"歩きながら話しましょう。","reading":"あるきながらはなしましょう。","english":"Let''s talk while walking."},{"japanese":"コーヒーを飲みながら、本を読みました。","reading":"コーヒーをのみながら、ほんをよみました。","english":"I read a book while drinking coffee."}]', 'conjunction', 0, 42);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜まで (until / as far as)', 'N / V (plain) + まで', 'Until / up to / as far as — endpoint in time, place, or degree', 'まで marks an endpoint: until a time, up to a place, or to the extent that. Combined with から it creates from...to ranges. Also used in expressions like こんなに...まで (to such an extent as this).', '[{"japanese":"駅まで歩きます。","reading":"えきまであるきます。","english":"I''ll walk as far as the station."},{"japanese":"試験が終わるまで、ここにいてください。","reading":"しけんがおわるまで、ここにいてください。","english":"Please stay here until the exam ends."},{"japanese":"夜中まで働きました。","reading":"よなかまではたらきました。","english":"I worked until the middle of the night."}]', 'particle', 0, 43);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜でも (even / or something — softening)', 'N + でも / V-て + も + even sense', 'Even [N] / [N] or something — softens suggestions or marks an extreme case', 'でも after a noun means ''even'' (extreme case) or ''or something'' (softening a suggestion). コーヒーでも飲みましょう = ''Let''s have some coffee or something''. It does not mean ''but'' in this construction.', '[{"japanese":"コーヒーでも飲みましょうか。","reading":"コーヒーでものみましょうか。","english":"Shall we have some coffee or something?"},{"japanese":"子供でもできる問題です。","reading":"こどもでもできるもんだいです。","english":"It''s a problem even a child can solve."},{"japanese":"散歩でもしませんか。","reading":"さんぽでもしませんか。","english":"How about taking a walk or something?"}]', 'particle', 0, 44);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜し〜し (listing reasons / and besides)', 'S (plain) + し、S (plain) + し', 'And besides / for one thing ... for another — lists multiple reasons or qualities', 'し connects multiple reasons or qualities, implying there are more than just those listed. It adds a cumulative or enumerative tone. Often used to justify a conclusion by stacking evidence.', '[{"japanese":"安いし、おいしいし、また行きたいです。","reading":"やすいし、おいしいし、またいきたいです。","english":"It''s cheap, it''s delicious, and I want to go again."},{"japanese":"彼は頭がいいし、優しいし、人気があります。","reading":"かれはあたまがいいし、やさしいし、にんきがあります。","english":"He''s smart, kind, and popular."},{"japanese":"疲れているし、眠いし、もう帰ります。","reading":"つかれているし、ねむいし、もうかえります。","english":"I''m tired and sleepy, so I''m going home."}]', 'conjunction', 0, 45);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜によると (according to)', 'N + によると / によれば', 'According to [source] — introduces reported information', 'によると introduces information attributed to a source. It is followed by そうです or similar hearsay expressions. によれば is slightly more formal. The speaker does not personally verify the information.', '[{"japanese":"天気予報によると、明日は雨だそうです。","reading":"てんきよほうによると、あしたはあめだそうです。","english":"According to the weather forecast, it will rain tomorrow."},{"japanese":"彼によると、パーティーは中止だそうです。","reading":"かれによると、パーティーはちゅうしだそうです。","english":"According to him, the party has been cancelled."},{"japanese":"ニュースによれば、事故があったそうです。","reading":"ニュースによれば、じこがあったそうです。","english":"According to the news, there was an accident."}]', 'expression', 0, 46);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜について (about / concerning)', 'N + について / についての + N', 'About / concerning / regarding [topic]', 'について marks the topic of discussion, thinking, writing, or research. についての modifies a following noun (a report about/on...). It is neutral in formality and widely used in both spoken and written Japanese.', '[{"japanese":"日本の文化について話しました。","reading":"にほんのぶんかについてはなしました。","english":"We talked about Japanese culture."},{"japanese":"この問題についてどう思いますか。","reading":"このもんだいについてどうおもいますか。","english":"What do you think about this issue?"},{"japanese":"日本語についての本を読んでいます。","reading":"にほんごについてのほんをよんでいます。","english":"I''m reading a book about the Japanese language."}]', 'expression', 0, 47);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ほうがいい vs 〜ほうが (comparison)', 'N/V + のほうが + Adj / A より B のほうが', 'B is more [adj] than A — comparative structure', '〜より〜のほうが is the standard comparative: ''B is more [adj] than A''. より marks the reference point (the lesser of the two), and ほうが marks what''s being compared favourably.', '[{"japanese":"バスより電車のほうが速いです。","reading":"バスよりでんしゃのほうがはやいです。","english":"The train is faster than the bus."},{"japanese":"一人より友達と行ったほうが楽しいです。","reading":"ひとりよりともだちといったほうがたのしいです。","english":"It''s more fun to go with friends than alone."},{"japanese":"夏より冬のほうが好きです。","reading":"なつよりふゆのほうがすきです。","english":"I prefer winter to summer."}]', 'comparison', 0, 48);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜させていただく (humbly do — formal request)', 'V-causative + いただく', 'Humbly allow me to do / I will humbly do — formal/polite action request', 'させていただく combines the causative (させる = be made/allowed to do) with いただく (humble form of もらう). It humbly requests permission for an action or announces one''s own action politely. Very common in formal and business contexts.', '[{"japanese":"では、説明させていただきます。","reading":"では、せつめいさせていただきます。","english":"Well then, allow me to explain."},{"japanese":"本日は早退させていただきます。","reading":"ほんじつはそうたいさせていただきます。","english":"I will humbly take my leave early today."},{"japanese":"少し考えさせていただけますか。","reading":"すこしかんがえさせていただけますか。","english":"Would you allow me a moment to think about it?"}]', 'honorific', 1, 49);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N4', '〜ていただけますか (would you please — polite request)', 'V-て + いただけますか / もらえますか', 'Could you please do — polite/humble request for someone to do something', 'ていただけますか is the polite request form combining te-form + いただく (humble ''receive'') + potential + question. More polite than てください. Used when asking someone of higher status or a stranger to do something.', '[{"japanese":"もう一度説明していただけますか。","reading":"もういちどせつめいしていただけますか。","english":"Could you please explain that once more?"},{"japanese":"こちらにサインしていただけますか。","reading":"こちらにサインしていただけますか。","english":"Could you please sign here?"},{"japanese":"少し待っていただけますか。","reading":"すこしまっていただけますか。","english":"Could you please wait a moment?"}]', 'honorific', 1, 50);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜てしまう / 〜ちゃう (regret or completion)', 'V-て + しまう / ちゃう (casual)', 'Ended up doing / completely did — often with regret or unintended nuance', 'てしまう expresses completion with finality or regret. In casual speech it contracts to ちゃう (for て-form) or じゃう (for で-form). Context determines whether the nuance is pure completion or unfortunate outcome.', '[{"japanese":"また遅刻してしまいました。","reading":"またちこくしてしまいました。","english":"I went and was late again."},{"japanese":"ケーキを全部食べちゃった。","reading":"ケーキをぜんぶたべちゃった。","english":"I ended up eating all the cake."},{"japanese":"大切な書類をなくしてしまいました。","reading":"たいせつなしょるいをなくしてしまいました。","english":"I went and lost the important documents."}]', 'verb-form', 0, 1);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜たまま (remaining in a state)', 'V-た + まま / N の + まま', 'Leaving something in the state it was — without changing it back', 'たまま expresses that a state resulting from an action remains unchanged. Often implies negligence or a state persisting longer than expected. The clause before まま uses the た-form.', '[{"japanese":"電気をつけたまま寝てしまいました。","reading":"でんきをつけたままねてしまいました。","english":"I fell asleep with the light still on."},{"japanese":"靴を履いたまま部屋に入らないでください。","reading":"くつをはいたままへやにはいらないでください。","english":"Please don''t enter the room with your shoes on."},{"japanese":"窓が開いたままになっています。","reading":"まどがあいたままになっています。","english":"The window has been left open."}]', 'expression', 0, 2);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ずに / 〜ないで (without doing)', 'V-ず + に / V-ない + で', 'Without doing — performs main action while omitting the subsidiary action', 'ずに is the classical/formal equivalent of ないで, both meaning ''without doing X''. ずに sounds slightly more formal or literary. Both indicate the main action is performed while X is not done. する becomes せずに.', '[{"japanese":"朝ごはんを食べずに学校に行きました。","reading":"あさごはんをたべずにがっこうにいきました。","english":"I went to school without eating breakfast."},{"japanese":"何も言わずに帰ってしまいました。","reading":"なにもいわずにかえってしまいました。","english":"He left without saying anything."},{"japanese":"傘を持たないで出かけました。","reading":"かさをもたないででかけました。","english":"I went out without bringing an umbrella."}]', 'conjunction', 0, 3);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜てばかりいる (doing nothing but)', 'V-て + ばかりいる', 'Do nothing but — criticism that someone only ever does one thing', 'てばかりいる combines てform + ばかり (nothing but) + いる (ongoing state). It carries a critical or lamenting tone, implying the person should be doing other things instead.', '[{"japanese":"彼はゲームばかりしていて、勉強しない。","reading":"かれはゲームばかりしていて、べんきょうしない。","english":"He does nothing but play games and won''t study."},{"japanese":"泣いてばかりいないで、前を向こう。","reading":"ないてばかりいないで、まえをむこう。","english":"Stop just crying and look forward."},{"japanese":"食べてばかりいると太りますよ。","reading":"たべてばかりいるとふとりますよ。","english":"If you do nothing but eat, you''ll gain weight."}]', 'expression', 0, 4);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜てしかたがない / てたまらない (unbearably / can''t help but feel)', 'V-て / Adj-くて + しかたがない / たまらない', 'Unbearably / so X that one can''t stand it — strong emotional or physical sensation', 'Both expressions convey an overwhelming feeling or sensation the speaker cannot control. たまらない is stronger and can also mean ''can''t resist / love it''. しかたがない is more neutral (can''t be helped).', '[{"japanese":"この映画は面白くてたまりません。","reading":"このえいがはおもしろくてたまりません。","english":"This movie is so interesting I can''t stand it."},{"japanese":"試験が心配でしかたがないです。","reading":"しけんがしんぱいでしかたがないです。","english":"I can''t help worrying about the exam."},{"japanese":"辛いものが食べたくてたまらない。","reading":"からいものがたべたくてたまらない。","english":"I can''t resist wanting to eat spicy food."}]', 'expression', 0, 5);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜させてもらう / させてくれる (allow me to)', 'V-causative + もらう / くれる', 'Allow me to do / let me do — asking or being given permission', 'させてもらう (humble: I receive permission to do) and させてくれる (someone kindly lets me do) are used to request or express gratitude for being allowed to do something. Common in polite or business contexts.', '[{"japanese":"少し休ませてもらえますか。","reading":"すこしやすませてもらえますか。","english":"Would you let me rest a little?"},{"japanese":"先生が発表させてくれました。","reading":"せんせいがはっぴょうさせてくれました。","english":"The teacher let me give the presentation."},{"japanese":"このプロジェクトに参加させてください。","reading":"このプロジェクトにさんかさせてください。","english":"Please let me participate in this project."}]', 'verb-form', 0, 6);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜させられる (involuntary causative-passive)', 'V-causative-passive (-させられる / -される)', 'Be made to do — the subject is forced by someone else to do something', 'The causative-passive combines causative (させる) and passive (られる). It means the subject is compelled by someone else to perform the action, often against their will. Group 2 verbs contract: 食べさせられる, 飲まされる.', '[{"japanese":"子供の頃、野菜を食べさせられました。","reading":"こどものころ、やさいをたべさせられました。","english":"As a child, I was made to eat vegetables."},{"japanese":"毎日残業させられて、疲れました。","reading":"まいにちざんぎょうさせられて、つかれました。","english":"I''ve been made to work overtime every day and I''m exhausted."},{"japanese":"先生に廊下に立たされました。","reading":"せんせいにろうかにたたされました。","english":"I was made to stand in the hallway by the teacher."}]', 'verb-form', 0, 7);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜らしい (typical of / -like)', 'N + らしい (typicality sense)', 'Typical of / befitting — something is characteristic or expected of its category', 'This is the typicality sense of らしい (distinct from its evidential sense). N + らしい means ''typical of N'' or ''like what N should be''. 男らしい = manly/masculine, 日本らしい = typically Japanese.', '[{"japanese":"それは彼らしい答えですね。","reading":"それはかれらしいこたえですね。","english":"That''s a very typical answer for him."},{"japanese":"春らしい暖かい日が続いています。","reading":"はるらしいあたたかいひがつづいています。","english":"Warm days typical of spring continue."},{"japanese":"女性らしい優しい気遣いに感動しました。","reading":"じょせいらしいやさしいきづかいにかんどうしました。","english":"I was moved by her characteristically feminine gentle consideration."}]', 'auxiliary', 0, 8);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜みたいだ (seems like / like — casual)', 'V/Adj (plain) + みたいだ / N + みたいだ', 'Seems like / looks like / like — casual inference or comparison', 'みたいだ is the casual equivalent of ようだ for expressing inference or comparison. みたいな can modify nouns (子供みたいな行動 = child-like behavior). It is not used in formal writing.', '[{"japanese":"彼は怒っているみたいですね。","reading":"かれはおこっているみたいですね。","english":"He seems angry."},{"japanese":"まるで夢みたいな話ですね。","reading":"まるでゆめみたいなはなしですね。","english":"It sounds like a dream."},{"japanese":"外は雨が降っているみたいです。","reading":"そとはあめがふっているみたいです。","english":"It looks like it''s raining outside."}]', 'auxiliary', 0, 9);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜はずだ (should be / expected to)', 'V/Adj (plain) + はずだ / N の + はずだ', 'Should be / expected to be — logical expectation based on knowledge', 'はずだ expresses the speaker''s strong expectation based on knowledge or reasoning. It is more confident than かもしれない and implies there is a logical basis. はずだったのに expresses unfulfilled expectation with disappointment.', '[{"japanese":"彼はもう着いているはずです。","reading":"かれはもうついているはずです。","english":"He should have arrived by now."},{"japanese":"この薬を飲めば治るはずです。","reading":"このくすりをのめばなおるはずです。","english":"If you take this medicine, you should recover."},{"japanese":"鍵はここにあるはずなのに、見つかりません。","reading":"かぎはここにあるはずなのに、みつかりません。","english":"The key should be here, but I can''t find it."}]', 'auxiliary', 0, 10);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜わけだ (that''s why / it means that)', 'S (plain) + わけだ', 'That''s why / it makes sense that — logical conclusion from facts', 'わけだ presents a natural conclusion following from given information. It expresses that something makes sense or is understandable given the circumstances. Different from はずだ (expectation) — わけだ is a logical derivation.', '[{"japanese":"10年間日本に住んでいたわけだから、日本語が上手なわけだ。","reading":"10ねんかんにほんにすんでいたわけだから、にほんごがじょうずなわけだ。","english":"He lived in Japan for 10 years, so of course his Japanese is good."},{"japanese":"昨日何も食べなかったわけだから、お腹が空くわけです。","reading":"きのうなにもたべなかったわけだから、おなかがすくわけです。","english":"I didn''t eat anything yesterday, so naturally I''m hungry."},{"japanese":"なるほど、そういうわけだったんですね。","reading":"なるほど、そういうわけだったんですね。","english":"I see, so that''s what it was all about."}]', 'expression', 0, 11);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜わけではない (it doesn''t mean that)', 'S (plain) + わけではない / わけじゃない', 'It''s not the case that / it doesn''t mean — partial negation or clarification', 'わけではない partially negates: it doesn''t mean X (but it could partially be true). Used to soften or clarify. Different from ではない (flat denial) — わけではない says ''don''t take it that far''.', '[{"japanese":"嫌いなわけではないけど、得意じゃないです。","reading":"きらいなわけではないけど、とくいじゃないです。","english":"It''s not that I dislike it, I''m just not good at it."},{"japanese":"忙しくないわけではないんですが、行けます。","reading":"いそがしくないわけではないんですが、いけます。","english":"It''s not that I''m not busy, but I can go."},{"japanese":"諦めたわけじゃない。","reading":"あきらめたわけじゃない。","english":"It doesn''t mean I''ve given up."}]', 'expression', 0, 12);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に違いない (must be / no doubt)', 'S (plain) + に違いない', 'Must be / certainly — strong conviction based on reasoning', 'に違いない expresses near-certainty based on the speaker''s reasoning or observation. It is stronger than はずだ and implies the speaker is very confident. Cannot be used when the speaker has direct evidence (use だ then).', '[{"japanese":"こんなに疲れているから、昨日はよく眠れなかったに違いない。","reading":"こんなにつかれているから、きのうはよくねむれなかったにちがいない。","english":"He must not have slept well last night since he''s so tired."},{"japanese":"あの二人は知り合いに違いありません。","reading":"あのふたりはしりあいにちがいありません。","english":"Those two must know each other."},{"japanese":"彼女は合格したに違いない。","reading":"かのじょはごうかくしたにちがいない。","english":"She must have passed."}]', 'auxiliary', 0, 13);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜によって (depending on / by means of)', 'N + によって / による + N', 'By / depending on / due to — marks agent, means, or variation by factor', 'によって has multiple uses: (1) passive agent (written/formal alternative to に); (2) means or method; (3) variation depending on a factor. による is the attributive form (preceding a noun).', '[{"japanese":"この小説はその作家によって書かれました。","reading":"このしょうせつはそのさっかによってかかれました。","english":"This novel was written by that author."},{"japanese":"結果は努力によって変わります。","reading":"けっかはどりょくによってかわります。","english":"Results change depending on effort."},{"japanese":"地震による被害が出ています。","reading":"じしんによるひがいがでています。","english":"Damage caused by the earthquake is being reported."}]', 'expression', 0, 14);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に対して (toward / in contrast to)', 'N + に対して / に対する + N', 'Toward / against / in contrast to — marks target of action or feeling, or contrast', 'に対して marks the target or recipient of an action, attitude, or feeling. It can also mean ''in contrast to / whereas'' when comparing two things. に対する is the attributive form.', '[{"japanese":"先生に対して失礼なことを言ってしまいました。","reading":"せんせいにたいしてしつれいなことをいってしまいました。","english":"I said something rude toward the teacher."},{"japanese":"弟は内向的なのに対して、姉は社交的です。","reading":"おとうとはないこうてきなのにたいして、あねはしゃこうてきです。","english":"My brother is introverted, whereas my sister is sociable."},{"japanese":"環境問題に対する意識が高まっています。","reading":"かんきょうもんだいにたいするいしきがたかまっています。","english":"Awareness toward environmental issues is growing."}]', 'expression', 0, 15);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜として (as / in the role of)', 'N + として', 'As / in the capacity of / treating as — marks a role, function, or classification', 'として marks the role, capacity, or category in which something acts or is treated. 友達として = as a friend; 問題として取り上げる = take up as a problem. It can also mean ''as'' in comparisons (standard/basis).', '[{"japanese":"彼は代表として会議に出席しました。","reading":"かれはだいひょうとしてかいぎにしゅっせきしました。","english":"He attended the meeting as a representative."},{"japanese":"それは問題として取り上げるべきです。","reading":"それはもんだいとしてとりあげるべきです。","english":"That should be taken up as an issue."},{"japanese":"友達として言うけど、少し休んだほうがいいよ。","reading":"ともだちとしていうけど、すこしやすんだほうがいいよ。","english":"As a friend I''m telling you, you should rest a bit."}]', 'expression', 0, 16);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜にとって (for / from the standpoint of)', 'N + にとって', 'For / from the perspective of — marks who experiences or judges something', 'にとって marks whose perspective or interest is relevant: ''for [person], this is...''. It differs from のために (purpose/benefit) — にとって is about perspective and assessment, not action.', '[{"japanese":"この仕事は私にとって大切な経験です。","reading":"このしごとはわたしにとってたいせつなけいけんです。","english":"This job is an important experience for me."},{"japanese":"子供にとって遊びは学習の一部です。","reading":"こどもにとってあそびはがくしゅうのいちぶです。","english":"For children, play is part of learning."},{"japanese":"外国語の習得は誰にとっても難しいです。","reading":"がいこくごのしゅうとくはだれにとってもむずかしいです。","english":"Acquiring a foreign language is difficult for anyone."}]', 'expression', 0, 17);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜だけでなく〜も (not only ... but also)', 'N / V (plain) + だけでなく + N / S + も', 'Not only ... but also — adds an additional unexpected element', 'だけでなく〜も indicates that something applies not only to the first element but also to the second. The second element (marked by も) is usually more surprising or significant. ばかりでなく is a near-synonym.', '[{"japanese":"彼女は歌が上手なだけでなく、ダンスも得意です。","reading":"かのじょはうたがじょうずなだけでなく、ダンスもとくいです。","english":"Not only is she good at singing, but she''s also good at dancing."},{"japanese":"この店は安いだけでなく、品質も高いです。","reading":"このみせはやすいだけでなく、ひんしつもたかいです。","english":"This shop is not only cheap but also high quality."},{"japanese":"日本語だけでなく、中国語も話せます。","reading":"にほんごだけでなく、ちゅうごくごもはなせます。","english":"I can speak not only Japanese but also Chinese."}]', 'conjunction', 0, 18);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ほど (to the degree that / the more ... the more)', 'N + ほど / V (plain) + ほど / 〜ば〜ほど', 'To the extent of / the more X the more Y — degree or proportional correlation', 'ほど indicates degree or extent. With a negative it means ''not as X as'': 思ったほどじゃない = not as much as I thought. 〜ば〜ほど is the ''the more...the more'' pattern expressing proportional increase.', '[{"japanese":"勉強すればするほど、上手になります。","reading":"べんきょうすればするほど、じょうずになります。","english":"The more you study, the better you get."},{"japanese":"思ったほど難しくなかったです。","reading":"おもったほどむずかしくなかったです。","english":"It wasn''t as difficult as I thought."},{"japanese":"命の危険を感じるほどの寒さでした。","reading":"いのちのきけんをかんじるほどのさむさでした。","english":"It was so cold I felt my life was in danger."}]', 'comparison', 0, 19);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜さえ〜ば (if only / as long as)', 'N + さえ + V-ば / N + さえあれば', 'If only / as long as — marks the single sufficient condition', 'さえ〜ば indicates that X is the only thing needed for Y to occur. It highlights the minimum or sole condition. さえ can also mean ''even'' when not combined with ば (emphasising an extreme case).', '[{"japanese":"お金さえあれば、旅行に行けます。","reading":"おかねさえあれば、りょこうにいけます。","english":"As long as I have money, I can travel."},{"japanese":"健康でさえあれば、それで十分です。","reading":"けんこうでさえあれば、それでじゅうぶんです。","english":"As long as you''re healthy, that''s enough."},{"japanese":"君さえいれば、他には何もいらない。","reading":"きみさえいれば、ほかにはなにもいらない。","english":"As long as I have you, I need nothing else."}]', 'conditional', 0, 20);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜上に (in addition to / moreover)', 'V/Adj (plain) + 上に / N の + 上に', 'In addition to / on top of that — adds something to an already existing quality', '上に stacks two qualities or facts, with the second reinforcing or compounding the first. Often both elements are in the same direction (both positive or both negative). More emphatic than だけでなく.', '[{"japanese":"この店は安い上に、サービスもいいです。","reading":"このみせはやすいうえに、サービスもいいです。","english":"This shop is cheap, and on top of that the service is good."},{"japanese":"今日は仕事が忙しい上に、残業まである。","reading":"きょうはしごとがいそがしいうえに、ざんぎょうまである。","english":"Today work is busy, and on top of that there''s overtime."},{"japanese":"彼女は美人な上に、頭もいいです。","reading":"かのじょはびじんなうえに、あたまもいいです。","english":"She is beautiful and smart on top of that."}]', 'conjunction', 0, 21);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜せいで (because of — negative cause)', 'V-た / Adj (plain) + せいで / N の + せいで', 'Because of / due to — blames something as the cause of a bad result', 'せいで attributes blame for a negative outcome. It is always used for unfavourable results. Contrasts with おかげで (positive results). Can express self-blame or blaming others/circumstances.', '[{"japanese":"寝坊したせいで、電車に乗り遅れました。","reading":"ねぼうしたせいで、でんしゃにのりおくれました。","english":"Because I overslept, I missed the train."},{"japanese":"雨のせいで、試合が中止になりました。","reading":"あめのせいで、しあいがちゅうしになりました。","english":"Due to the rain, the match was cancelled."},{"japanese":"あなたのせいじゃないですよ。","reading":"あなたのせいじゃないですよ。","english":"It''s not your fault."}]', 'conjunction', 0, 22);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜おかげで (thanks to — positive cause)', 'V-た / Adj (plain) + おかげで / N の + おかげで', 'Thanks to / owing to — attributes a positive result to a cause', 'おかげで is the positive counterpart of せいで. It credits something (a person, condition, action) for a good outcome. Can be used sarcastically to express an unexpectedly bad result from something supposedly good.', '[{"japanese":"先生のおかげで、試験に合格しました。","reading":"せんせいのおかげで、しけんにごうかくしました。","english":"Thanks to my teacher, I passed the exam."},{"japanese":"毎日練習したおかげで、上手になりました。","reading":"まいにちれんしゅうしたおかげで、じょうずになりました。","english":"Thanks to practicing every day, I improved."},{"japanese":"おかげさまで、元気になりました。","reading":"おかげさまで、げんきになりました。","english":"Thanks to everyone, I''ve recovered."}]', 'conjunction', 0, 23);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ように言う (tell someone to)', 'V (plain non-past / ない) + ように言う / 伝える', 'Tell / ask someone to do or not do something — indirect command', 'ように言う reports an instruction or request given to someone. It softens a command into a request form. Used to relay instructions from one person to another (indirect speech). ように頼む = ask to.', '[{"japanese":"先生は学生に静かにするように言いました。","reading":"せんせいはがくせいにしずかにするようにいいました。","english":"The teacher told the students to be quiet."},{"japanese":"医者に無理をしないように言われました。","reading":"いしゃにむりをしないようにいわれました。","english":"The doctor told me not to push myself."},{"japanese":"早く来るように伝えてください。","reading":"はやくくるようにつたえてください。","english":"Please tell him to come quickly."}]', 'expression', 0, 24);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ものだ (it''s natural / used to / should)', 'V/Adj (plain) + ものだ', 'It''s natural that / used to / one should — general truths, past habits, or norms', 'ものだ has several uses: (1) stating a general truth or natural state of affairs; (2) recalling past habits (〜たものだ = used to); (3) stating what should be done (social norm). Context distinguishes them.', '[{"japanese":"子供は元気なものだ。","reading":"こどもはげんきなものだ。","english":"Children are naturally energetic."},{"japanese":"子供の頃よく川で遊んだものです。","reading":"こどものころよくかわであそんだものです。","english":"I used to play by the river as a child."},{"japanese":"人に会ったら挨拶するものです。","reading":"ひとにあったらあいさつするものです。","english":"One should greet people when meeting them."}]', 'expression', 0, 25);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ものの (although / but)', 'V/Adj (plain) + ものの', 'Although / even though — concession where the expected result doesn''t follow', 'ものの presents a concession: although the first clause is true, it doesn''t lead to the expected result. It carries a nuance of the speaker''s dissatisfaction or the unexpected gap between expectation and reality. More formal than が or けど.', '[{"japanese":"日本語を3年勉強したものの、まだ話せません。","reading":"にほんごを3ねんべんきょうしたものの、まだはなせません。","english":"Although I''ve studied Japanese for 3 years, I still can''t speak it."},{"japanese":"買ったものの、結局使いませんでした。","reading":"かったものの、けっきょくつかいませんでした。","english":"Although I bought it, I ended up not using it."},{"japanese":"行きたいとは思うものの、時間がありません。","reading":"いきたいとはおもうものの、じかんがありません。","english":"Although I want to go, I don''t have time."}]', 'conjunction', 0, 26);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ところだ (just about to / just did / in the middle of)', 'V (non-past) + ところだ / V-て + いるところだ / V-た + ところだ', 'Just about to / in the middle of / just finished — precise timing', 'ところ with different verb forms expresses precise timing: non-past + ところ = about to do; ている + ところ = in the middle of doing; た + ところ = just finished. Very useful for explaining current state.', '[{"japanese":"今から出かけるところです。","reading":"いまからでかけるところです。","english":"I''m just about to go out."},{"japanese":"今、ご飯を食べているところです。","reading":"いま、ごはんをたべているところです。","english":"I''m in the middle of eating right now."},{"japanese":"今ちょうど帰ってきたところです。","reading":"いまちょうどかえってきたところです。","english":"I just got home right now."}]', 'expression', 0, 27);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜場合は (in the case that / if)', 'V/Adj (plain) + 場合は / N の + 場合は', 'In the case of / if — presents a scenario and describes what applies in that case', '場合は presents a hypothetical or specific scenario and then states what should be done or what follows. It is more formal than たら and often appears in instructions, manuals, and rules.', '[{"japanese":"緊急の場合は、このボタンを押してください。","reading":"きんきゅうのばあいは、このボタンをおしてください。","english":"In case of emergency, press this button."},{"japanese":"参加できない場合は、ご連絡ください。","reading":"さんかできないばあいは、ごれんらくください。","english":"If you cannot participate, please contact us."},{"japanese":"天気が悪い場合は、イベントを中止します。","reading":"てんきがわるいばあいは、イベントをちゅうしします。","english":"In the event of bad weather, we will cancel the event."}]', 'conjunction', 0, 28);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜たびに (every time / whenever)', 'V (plain non-past) + たびに / N の + たびに', 'Every time / whenever — marks a recurring situation and its consistent result', 'たびに means something happens every single time the first condition occurs. It emphasises regularity and often a consistent emotional or physical reaction. Different from 〜と (which states automatic consequences).', '[{"japanese":"この歌を聴くたびに、故郷を思い出します。","reading":"このうたをきくたびに、こきょうをおもいだします。","english":"Every time I hear this song, I''m reminded of my hometown."},{"japanese":"会うたびに、背が高くなっていますね。","reading":"あうたびに、せがたかくなっていますね。","english":"Every time we meet, you''ve gotten taller."},{"japanese":"旅行のたびに、お土産を買います。","reading":"りょこうのたびに、おみやげをかいます。","english":"Every time I travel, I buy souvenirs."}]', 'conjunction', 0, 29);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ことから (from the fact that)', 'V/Adj (plain) + ことから', 'From the fact that / because of — draws a conclusion or derives a name/nickname from evidence', 'ことから states the basis or reason from which a conclusion, name, or deduction arises. Often used in explanations of why something is called what it is, or in reasoning chains.', '[{"japanese":"桜の花が美しいことから、日本の国花とされています。","reading":"さくらのはながうつくしいことから、にほんのこっかとされています。","english":"From the fact that cherry blossoms are beautiful, they are considered Japan''s national flower."},{"japanese":"彼が遅刻ばかりすることから、時間を守らない人だと思われています。","reading":"かれがちこくばかりすることから、じかんをまもらないひとだとおもわれています。","english":"From the fact that he''s always late, he is thought of as someone who doesn''t keep time."},{"japanese":"その川が青く見えることから、「青川」と呼ばれています。","reading":"そのかわがあおくみえることから、「あおかわ」とよばれています。","english":"Because the river looks blue, it is called ''Blue River''."}]', 'conjunction', 0, 30);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ことで (by doing / through)', 'V (plain) + ことで', 'By doing / through — marks the means or method that leads to the result', 'ことで nominalises the verb phrase and marks it as the method or means. Similar to によって but more action-focused. Often used in set phrases or formal explanations of how something is achieved.', '[{"japanese":"毎日練習することで、技術が上がります。","reading":"まいにちれんしゅうすることで、ぎじゅつがあがります。","english":"By practicing every day, your skills improve."},{"japanese":"対話することで、誤解が解けました。","reading":"たいわすることで、ごかいがとけました。","english":"Through dialogue, the misunderstanding was resolved."},{"japanese":"食事を改善することで、健康になりました。","reading":"しょくじをかいぜんすることで、けんこうになりました。","english":"By improving my diet, I became healthier."}]', 'conjunction', 0, 31);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜のに (in order to — purpose with effort)', 'V (plain non-past) + のに + required resource/effort', 'To do / for doing — marks what is needed or required for a purpose', 'This のに (different from the concessive のに) expresses what is necessary or used for a purpose. Similar to ために but more focused on requirements or suitability: このカードはお金を引き出すのに使います.', '[{"japanese":"この薬は頭痛を治すのに効果があります。","reading":"このくすりはずつうをなおすのにこうかがあります。","english":"This medicine is effective for treating headaches."},{"japanese":"パソコンはレポートを書くのに必要です。","reading":"パソコンはレポートをかくのにひつようです。","english":"A computer is necessary for writing reports."},{"japanese":"この道具は何に使うのですか。","reading":"このどうぐはなににつかうのですか。","english":"What is this tool used for?"}]', 'conjunction', 0, 32);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ものだから (because — emphatic/excuse)', 'V/Adj (plain) + ものだから / もんだから (casual)', 'Because (emphatic) — gives a reason as an explanation or excuse', 'ものだから (and its casual form もんだから) gives a reason with a tone of explanation or justification. The speaker uses it to explain why something happened, often as an excuse. Stronger and more personal than ので.', '[{"japanese":"電車が遅れたものだから、遅刻してしまいました。","reading":"でんしゃがおくれたものだから、ちこくしてしまいました。","english":"Because the train was delayed, I ended up being late."},{"japanese":"急いでいたもんだから、財布を忘れてしまいました。","reading":"いそいでいたもんだから、さいふをわすれてしまいました。","english":"Because I was in a hurry, I forgot my wallet."},{"japanese":"嬉しかったものだから、つい大声で叫んでしまいました。","reading":"うれしかったものだから、ついおおごえでさけんでしまいました。","english":"Because I was so happy, I ended up shouting out loud."}]', 'conjunction', 0, 33);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ところで (even if — futility)', 'V-た + ところで', 'Even if I were to do — it would be pointless/futile', 'たところで expresses futility: even if the action in the first clause were taken, it would not change anything or achieve the desired result. Different from ても (which is neutral) — たところで emphasises uselessness.', '[{"japanese":"今更謝ったところで、遅すぎます。","reading":"いまさらあやまったところで、おそすぎます。","english":"Even if I were to apologise now, it''s too late."},{"japanese":"一人で反対したところで、何も変わりません。","reading":"ひとりでわはんたいしたところで、なにもかわりません。","english":"Even if I were to oppose it alone, nothing would change."},{"japanese":"聞いたところで、分からないと思います。","reading":"きいたところで、わからないとおもいます。","english":"Even if I asked, I don''t think I''d understand."}]', 'conditional', 0, 34);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ということだ (it means that / I heard that)', 'S (plain) + ということだ / ということです', 'It means that / I hear that — explains meaning or reports information', 'ということだ summarises or restates the meaning of something (in other words, what it means). It is also used to report hearsay formally, similar to そうだ. The casual contraction is ってことだ.', '[{"japanese":"彼が来ないということは、会議は中止ということですか。","reading":"かれがこないということは、かいぎはちゅうしということですか。","english":"Does the fact that he''s not coming mean the meeting is cancelled?"},{"japanese":"つまり、もう諦めたということですか。","reading":"つまり、もうあきらめたということですか。","english":"In other words, does it mean you''ve already given up?"},{"japanese":"噂では、来月引っ越すということです。","reading":"うわさでは、らいげつひっこすということです。","english":"I hear (by rumour) that she''s moving next month."}]', 'expression', 0, 35);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜にしたがって (as / in accordance with)', 'V (plain non-past) + にしたがって / N + にしたがって', 'As / following — parallel progression or acting in accordance with something', 'にしたがって has two senses: (1) as X increases/progresses, Y changes proportionally; (2) acting in accordance with rules, orders, or someone''s lead. Both involve following or going along with something.', '[{"japanese":"年をとるにしたがって、体力が落ちていきます。","reading":"としをとるにしたがって、たいりょくがおちていきます。","english":"As one gets older, physical strength declines."},{"japanese":"規則にしたがって行動してください。","reading":"きそくにしたがってこうどうしてください。","english":"Please act in accordance with the rules."},{"japanese":"季節の変化にしたがって、景色も変わります。","reading":"きせつのへんかにしたがって、けしきもかわります。","english":"As the seasons change, the scenery changes too."}]', 'expression', 0, 36);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜を通して / を通じて (through / throughout)', 'N + を通して / を通じて', 'Through / throughout / by means of — marks a medium, channel, or entire period', 'を通して and を通じて are largely interchangeable. Both mean ''through (a medium or channel)'' or ''throughout (a time period)''. を通じて can feel slightly more formal or literary.', '[{"japanese":"インターネットを通じて、世界中の人と話せます。","reading":"インターネットをつうじて、せかいじゅうのひととはなせます。","english":"Through the internet, I can talk to people around the world."},{"japanese":"一年を通して、観光客が来ます。","reading":"いちねんをとおして、かんこうきゃくがきます。","english":"Tourists come throughout the year."},{"japanese":"この経験を通して、多くのことを学びました。","reading":"このけいけんをとおして、おおくのことをまなびました。","english":"Through this experience, I learned a lot."}]', 'expression', 0, 37);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜向けに / 向けの (aimed at / for)', 'N + 向けに / 向けの + N', 'Aimed at / designed for / intended for — marks the target audience or purpose', '向けに marks the intended recipient or target of something. 向けの modifies a following noun. It is common in product descriptions, publications, and services: 子供向けの本 = a book for children.', '[{"japanese":"この教材は初心者向けに作られています。","reading":"このきょうざいはしょしんしゃむけにつくられています。","english":"This material was made for beginners."},{"japanese":"外国人観光客向けのサービスを提供しています。","reading":"がいこくじんかんこうきゃくむけのサービスをていきょうしています。","english":"We provide services aimed at foreign tourists."},{"japanese":"子供向けに書かれた本です。","reading":"こどもむけにかかれたほんです。","english":"It is a book written for children."}]', 'expression', 0, 38);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜次第で (depending on)', 'N + 次第で / 次第では', 'Depending on — outcome varies based on the preceding factor', '次第で (or 次第では) expresses that the result depends on the preceding noun. 次第 alone (after a verb stem) means ''as soon as''. The two uses are distinct — context clarifies which applies.', '[{"japanese":"努力次第で、誰でも成功できます。","reading":"どりょくしだいで、だれでもせいこうできます。","english":"Depending on your effort, anyone can succeed."},{"japanese":"天気次第では、予定を変更するかもしれません。","reading":"てんきしだいでは、よていをへんこうするかもしれません。","english":"Depending on the weather, we might change the plan."},{"japanese":"やり方次第で、結果は大きく変わります。","reading":"やりかたしだいで、けっかはおおきくかわります。","english":"Depending on how you do it, results can vary greatly."}]', 'expression', 0, 39);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜とともに (together with / as ... so)', 'V (plain non-past) + とともに / N + とともに', 'Together with / along with / as X, so Y — simultaneous change or accompaniment', 'とともに has two uses: (1) accompaniment — together with someone; (2) parallel change — as one thing changes, another changes simultaneously. Similar to につれて but more formal and broader in use.', '[{"japanese":"時代の変化とともに、言葉も変わっていきます。","reading":"じだいのへんかとともに、ことばもかわっていきます。","english":"Along with changes in the era, language also changes."},{"japanese":"彼は家族とともに外国に移りました。","reading":"かれはかぞくとともにがいこくにうつりました。","english":"He moved abroad together with his family."},{"japanese":"春の訪れとともに、花が咲き始めます。","reading":"はるのおとずれとともに、はながさきはじめます。","english":"Along with the arrival of spring, flowers start to bloom."}]', 'conjunction', 0, 40);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜につれて (as ... / in proportion to)', 'V (plain non-past) + につれて / N + につれて', 'As / in proportion to — one change accompanies or causes another proportionally', 'につれて expresses proportional or parallel change: as A changes, B changes correspondingly. Usually describes gradual, natural progression. The subjects of both clauses often differ.', '[{"japanese":"春になるにつれて、だんだん暖かくなってきます。","reading":"はるになるにつれて、だんだんあたたかくなってきます。","english":"As spring arrives, it gradually gets warmer."},{"japanese":"慣れるにつれて、仕事が楽になりました。","reading":"なれるにつれて、しごとがらくになりました。","english":"As I got used to it, the work became easier."},{"japanese":"年をとるにつれて、好みが変わります。","reading":"としをとるにつれて、このみがかわります。","english":"As you age, your preferences change."}]', 'conjunction', 0, 41);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜おそれがある (there is a risk/fear that)', 'V (plain non-past) + おそれがある / N の + おそれがある', 'There is a risk / fear that — expresses potential negative outcome', 'おそれがある is a formal expression indicating a risk or possibility of something negative occurring. Common in news, weather reports, and official warnings. The written form uses 恐れ; more formal than かもしれない for negative events.', '[{"japanese":"台風が上陸するおそれがあります。","reading":"たいふうがじょうりくするおそれがあります。","english":"There is a risk that the typhoon will make landfall."},{"japanese":"このままでは失敗するおそれがあります。","reading":"このままではしっぱいするおそれがあります。","english":"There is a risk of failure if things continue like this."},{"japanese":"感染のおそれがあるため、マスクをしてください。","reading":"かんせんのおそれがあるため、マスクをしてください。","english":"Please wear a mask as there is a risk of infection."}]', 'expression', 0, 42);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜がちだ (tend to / prone to)', 'V-stem + がちだ / N + がちだ', 'Tend to / be prone to — habitual tendency, often negative', 'がちだ expresses a tendency or inclination, usually for negative or undesirable things. 病気がち = prone to illness; 忘れがち = tend to forget. It implies this happens more than it should.', '[{"japanese":"冬は風邪をひきがちです。","reading":"ふゆはかぜをひきがちです。","english":"I tend to catch colds in winter."},{"japanese":"忙しいと食事を抜きがちになります。","reading":"いそがしいとしょくじをぬきがちになります。","english":"When busy, I tend to skip meals."},{"japanese":"最近、曇りがちな天気が続いています。","reading":"さいきん、くもりがちなてんきがつづいています。","english":"Recently we''ve been having mostly cloudy weather."}]', 'auxiliary', 0, 43);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜気味だ (slightly / a bit — tendency)', 'V-stem / N + 気味だ', 'A little / slightly — slight tendency or inclination, often physical or negative', '気味だ (ぎみ) indicates a slight tendency or slight degree of something, usually physical states or situations. 疲れ気味 = a bit tired; 風邪気味 = coming down with a cold. Less strong than がちだ.', '[{"japanese":"最近、疲れ気味です。","reading":"さいきん、つかれぎみです。","english":"I''ve been feeling a bit tired lately."},{"japanese":"今日は風邪気味なので、早めに帰ります。","reading":"きょうはかぜぎみなので、はやめにかえります。","english":"I''m coming down with a cold today, so I''ll leave early."},{"japanese":"最近、少し太り気味です。","reading":"さいきん、すこしふとりぎみです。","english":"I''ve been putting on a little weight lately."}]', 'auxiliary', 0, 44);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜てこそ (only because / precisely because)', 'V-て + こそ', 'Only because / precisely because — emphasises the indispensable condition', 'てこそ means ''it is only through/because of X that Y is possible''. It stresses that X is the essential condition — without it, Y cannot happen. Carries a strong emphasis or assertion.', '[{"japanese":"失敗してこそ、本当の成長がある。","reading":"しっぱいしてこそ、ほんとうのせいちょうがある。","english":"It is only through failure that true growth occurs."},{"japanese":"努力してこそ、成功の価値がある。","reading":"どりょくしてこそ、せいこうのかちがある。","english":"Success only has value when achieved through effort."},{"japanese":"健康であってこそ、何でもできる。","reading":"けんこうであってこそ、なんでもできる。","english":"Only when you are healthy can you do anything."}]', 'conjunction', 0, 45);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜にしては (for / considering that)', 'N / V (plain) + にしては', 'For / considering — the result is unexpected given the standard or type', 'にしては expresses that something is unexpected given the category or standard it belongs to. It often implies the result is better or worse than typical for that category. Similar to ''for someone like...'' or ''considering...''.', '[{"japanese":"初心者にしては、上手ですね。","reading":"しょしんしゃにしては、じょうずですね。","english":"For a beginner, you''re quite good."},{"japanese":"今日は春にしては寒いですね。","reading":"きょうははるにしてはさむいですね。","english":"It''s cold today, considering it''s spring."},{"japanese":"値段にしては、品質がよくないですね。","reading":"ねだんにしては、ひんしつがよくないですね。","english":"Considering the price, the quality isn''t great."}]', 'expression', 0, 46);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に限って (only ... / especially when)', 'N + に限って', 'Especially / just when — ironic: a certain person/thing does something unexpectedly', 'に限って expresses that something happens specifically (and usually ironically or unfairly) with/to the marked noun. 私に限って = not me of all people / just when it''s me it happens. Often carries a nuance of surprise or complaint.', '[{"japanese":"私に限ってそんなことはしません。","reading":"わたしにかぎってそんなことはしません。","english":"Someone like me would never do such a thing."},{"japanese":"急いでいる時に限って、電車が遅れる。","reading":"いそいでいるときにかぎって、でんしゃがおくれる。","english":"Just when I''m in a hurry, the train is always late."},{"japanese":"大事な試合に限って、雨が降るんだよな。","reading":"だいじなしあいにかぎって、あめがふるんだよな。","english":"It always rains specifically during the important matches."}]', 'expression', 0, 47);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜はもちろん / はもとより (of course / not to mention)', 'N + はもちろん / はもとより + も', 'Of course / let alone / not to mention — X is obvious, and Y is also true', 'はもちろん means ''of course X, but also Y''. The first item is taken for granted; the second is the added point. はもとより is the more formal/literary version, often used in formal writing.', '[{"japanese":"英語はもちろん、フランス語も話せます。","reading":"えいごはもちろん、フランスごもはなせます。","english":"Of course she speaks English, and French too."},{"japanese":"健康はもちろん、安全も大切です。","reading":"けんこうはもちろん、あんぜんもたいせつです。","english":"Of course health is important, but safety is too."},{"japanese":"この本は専門家はもとより、一般の方にも役立ちます。","reading":"このほんはせんもんかはもとより、いっぱんのかたにもやくだちます。","english":"This book is useful not only to experts but also to general readers."}]', 'expression', 0, 48);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ついでに (while one is at it / taking the opportunity)', 'V (plain non-past / た) + ついでに / N の + ついでに', 'While you''re at it / taking the opportunity — doing a secondary action alongside the primary one', 'ついでに means to take advantage of an opportunity (an already-planned action) to also do something else. The secondary action (after ついでに) is done conveniently alongside the main activity.', '[{"japanese":"買い物のついでに、郵便局に寄ります。","reading":"かいもののついでに、ゆうびんきょくによります。","english":"While I''m out shopping, I''ll stop by the post office."},{"japanese":"図書館に行くついでに、本を返しておきます。","reading":"としょかんにいくついでに、ほんをかえしておきます。","english":"Since I''m going to the library anyway, I''ll return the books."},{"japanese":"散歩のついでに、コンビニで買い物しました。","reading":"さんぽのついでに、コンビニでかいものしました。","english":"While I was taking a walk, I stopped at the convenience store."}]', 'expression', 0, 49);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜さえ (even — extreme case marker)', 'N + さえ / V-stem + さえ + する', 'Even — marks an extreme or unexpected case', 'さえ (without ば) marks an extreme case: ''even X (which you wouldn''t expect)''. It highlights a surprising example. Can follow nouns, verb stems, or て-forms. This is distinct from さえ〜ば (sufficient condition).', '[{"japanese":"子供でさえ知っていることです。","reading":"こどもでさえしっていることです。","english":"Even a child knows this."},{"japanese":"彼は食事さえせずに働いていました。","reading":"かれはしょくじさえせずにはたらいていました。","english":"He was working without even eating."},{"japanese":"挨拶さえしてくれれば、それでいいです。","reading":"あいさつさえしてくれれば、それでいいです。","english":"As long as you at least greet me, that''s fine."}]', 'particle', 0, 50);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜ばよかった (should have / wish I had)', 'V-ば + よかった', 'I should have / I wish I had — expresses regret about a past action', 'ばよかった (or なければよかった for the negative) expresses regret. The speaker wishes they had done (or not done) something differently. The ば-form + よかった is the standard structure for this regret pattern.', '[{"japanese":"もっと早く起きればよかった。","reading":"もっとはやくおきればよかった。","english":"I should have gotten up earlier."},{"japanese":"あの映画を見なければよかったです。","reading":"あのえいがをみなければよかったです。","english":"I wish I hadn''t watched that movie."},{"japanese":"傘を持ってくればよかった。","reading":"かさをもってくればよかった。","english":"I should have brought an umbrella."}]', 'conditional', 0, 51);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に応じて (in response to / according to)', 'N + に応じて / に応じた + N', 'In response to / according to — adjusts or varies based on the situation', 'に応じて expresses adjustment or response to a given condition. It implies flexibility: the response or outcome changes to match the situation. に応じた modifies a following noun attributively.', '[{"japanese":"状況に応じて対応を変えてください。","reading":"じょうきょうにおうじてたいおうをかえてください。","english":"Please change your response according to the situation."},{"japanese":"能力に応じた仕事を任せます。","reading":"のうりょくにおうじたしごとをまかせます。","english":"I''ll assign work according to ability."},{"japanese":"ニーズに応じてサービスをカスタマイズします。","reading":"ニーズにおうじてサービスをカスタマイズします。","english":"We will customise the service according to your needs."}]', 'expression', 0, 52);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜とか〜とか (things like / such as)', 'N/V (plain) + とか + N/V (plain) + とか', 'Things like / such as — non-exhaustive list with casual, approximate nuance', 'とか〜とか lists examples in a casual way, implying there are other items too (like や but more colloquial). Can list nouns, verbs, or quoted speech. Sounds more conversational than や〜など.', '[{"japanese":"週末はゲームをするとか、映画を見るとかします。","reading":"しゅうまつはゲームをするとか、えいがをみるとかします。","english":"On weekends I do things like playing games and watching movies."},{"japanese":"果物とか野菜とかが好きです。","reading":"くだものとかやさいとかがすきです。","english":"I like things like fruits and vegetables."},{"japanese":"「疲れた」とか「もう無理」とか言っていました。","reading":"「つかれた」とか「もうむり」とかいっていました。","english":"She was saying things like ''I''m tired'' and ''I can''t go on''."}]', 'particle', 0, 53);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜にもかかわらず (despite / in spite of)', 'V/Adj (plain) + にもかかわらず / N + にもかかわらず', 'Despite / in spite of / regardless of — formal concession', 'にもかかわらず is a formal concessive conjunction meaning ''despite'' or ''in spite of''. The result is contrary to what the first clause would suggest. More formal than のに or ても.', '[{"japanese":"雨にもかかわらず、大勢の人が来ました。","reading":"あめにもかかわらず、おおぜいのひとがきました。","english":"Despite the rain, many people came."},{"japanese":"努力したにもかかわらず、失敗しました。","reading":"どりょくしたにもかかわらず、しっぱいしました。","english":"Despite making an effort, I failed."},{"japanese":"注意したにもかかわらず、同じミスを繰り返しました。","reading":"ちゅういしたにもかかわらず、おなじミスをくりかえしました。","english":"Despite being warned, he repeated the same mistake."}]', 'conjunction', 0, 54);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜という点で (in terms of the point that)', 'S (plain) + という点で / という点では', 'In terms of / from the perspective that — evaluation based on a specific criterion', 'という点で frames a comparison or evaluation using a specific criterion or aspect. Often used in more analytical or formal speech. 点 (point/aspect) makes the basis of judgement explicit.', '[{"japanese":"コストという点では、A案のほうが優れています。","reading":"コストというてんでは、Aあんのほうがすぐれています。","english":"In terms of cost, Plan A is superior."},{"japanese":"使いやすさという点で、このアプリは優秀です。","reading":"つかいやすさというてんで、このアプリはゆうしゅうです。","english":"In terms of ease of use, this app is excellent."},{"japanese":"安全という点では問題ありません。","reading":"あんぜんというてんでは問題ありません。","english":"There is no problem in terms of safety."}]', 'expression', 0, 55);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に加えて (in addition to)', 'N + に加えて / に加え', 'In addition to — adds a further element on top of what was already stated', 'に加えて introduces an additional factor, item, or quality. Similar to 上に but more neutral in tone (doesn''t imply compounding the same direction). に加え is the slightly more formal variant.', '[{"japanese":"英語に加えて、スペイン語も勉強しています。","reading":"えいごにくわえて、スペインごもべんきょうしています。","english":"In addition to English, I''m also studying Spanish."},{"japanese":"給料に加えて、ボーナスも出ました。","reading":"きゅうりょうにくわえて、ボーナスもでました。","english":"In addition to the salary, a bonus was also given."},{"japanese":"経験に加えて、資格も必要です。","reading":"けいけんにくわえて、しかくもひつようです。","english":"In addition to experience, qualifications are also required."}]', 'conjunction', 0, 56);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜のではないか / んじゃないか (I wonder if / don''t you think)', 'V/Adj (plain) + のではないか / んじゃないか', 'Don''t you think / I wonder if — indirect conjecture or soft assertion', 'のではないか presents a conjecture with less force than だろう — it invites the listener''s agreement rather than asserting. んじゃないか is the casual form. Often used when the speaker has some evidence but isn''t certain.', '[{"japanese":"彼はもう知っているのではないかと思います。","reading":"かれはもうしっているのではないかとおもいます。","english":"I wonder if he doesn''t already know."},{"japanese":"この方法は間違っているんじゃないですか。","reading":"このほうほうはまちがっているんじゃないですか。","english":"Don''t you think this method is wrong?"},{"japanese":"もう少し考えたほうがいいんじゃないでしょうか。","reading":"もうすこしかんがえたほうがいいんじゃないでしょうか。","english":"Don''t you think it would be better to think about it a bit more?"}]', 'expression', 0, 57);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜に関して / に関する (concerning / regarding)', 'N + に関して / に関する + N', 'Concerning / regarding — marks the subject matter of discussion or inquiry', 'に関して is a formal way to mark the topic of a statement, question, or action. に関する precedes a noun (a question regarding...). It is more formal than について and common in academic, business, and official contexts.', '[{"japanese":"この件に関してご意見をお聞かせください。","reading":"このけんにかんしてごいけんをおきかせください。","english":"Please share your opinion regarding this matter."},{"japanese":"環境問題に関する報告書を読みました。","reading":"かんきょうもんだいにかんするほうこくしょをよみました。","english":"I read a report concerning environmental issues."},{"japanese":"契約に関してご不明な点はありますか。","reading":"けいやくにかんしてごふめいなてんはありますか。","english":"Do you have any unclear points regarding the contract?"}]', 'expression', 0, 58);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜をもとに (based on)', 'N + をもとに / をもとにした + N', 'Based on / drawing from — marks the source material or foundation', 'をもとに marks what something is based on, derived from, or drawn from. Used when creating, designing, or deciding something using existing information as a foundation. をもとにした modifies a following noun.', '[{"japanese":"実際の事件をもとにした映画です。","reading":"じっさいのじけんをもとにしたえいがです。","english":"It''s a film based on a real incident."},{"japanese":"アンケート結果をもとに、計画を立てました。","reading":"アンケートけっかをもとに、けいかくをたてました。","english":"We drew up a plan based on the survey results."},{"japanese":"データをもとにして分析します。","reading":"データをもとにしてぶんせきします。","english":"I will analyse based on the data."}]', 'expression', 0, 59);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N3', '〜わけにはいかない (can''t / must not — social/moral constraint)', 'V (plain non-past) + わけにはいかない / V-ない + わけにはいかない', 'Can''t bring myself to / can''t afford to — socially or morally can''t do (or not do)', 'わけにはいかない expresses that despite wanting to, social norms, obligations, or consequences make it impossible. 〜ないわけにはいかない = can''t avoid doing (obligated). The constraint is external/social, not just personal ability.', '[{"japanese":"上司に嘘をつくわけにはいきません。","reading":"じょうしにうそをつくわけにはいきません。","english":"I can''t bring myself to lie to my boss."},{"japanese":"ここで諦めるわけにはいかない。","reading":"ここであきらめるわけにはいかない。","english":"I can''t afford to give up here."},{"japanese":"お世話になった人の頼みを断るわけにはいきません。","reading":"おせわになったひとのたのみをことわるわけにはいきません。","english":"I can''t bring myself to refuse a request from someone who has helped me."}]', 'expression', 0, 60);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜上で (after doing / in terms of)', 'V-た + 上で / N の + 上で', 'After doing / on the basis of — marks a prerequisite action before the main one', '上で after a past-tense verb means ''after doing X (as a prerequisite), then Y''. After a noun it can mean ''in terms of'' or ''regarding''. It implies the first action is completed and its result informs the second.', '[{"japanese":"よく考えた上で、決断しました。","reading":"よくかんがえたうえで、けつだんしました。","english":"I made my decision after careful consideration."},{"japanese":"内容を確認した上で、サインしてください。","reading":"ないようをかくにんしたうえで、サインしてください。","english":"Please sign after confirming the contents."},{"japanese":"ビジネスの上で大切なのは信頼です。","reading":"ビジネスのうえでたいせつなのはしんらいです。","english":"What is important in terms of business is trust."}]', 'conjunction', 0, 1);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にわたって / にわたる (over / spanning — range)', 'N + にわたって / にわたる + N', 'Over / spanning / throughout — covers a period of time or range of items', 'にわたって expresses that something extends over a range or period. The range can be time (3 years), area, or scope (many topics). にわたる is the attributive form modifying a following noun.', '[{"japanese":"会議は3時間にわたって続きました。","reading":"かいぎは3じかんにわたってつづきました。","english":"The meeting continued for over 3 hours."},{"japanese":"広い範囲にわたる調査が行われました。","reading":"ひろいはんいにわたるちょうさがおこなわれました。","english":"A survey spanning a wide range was conducted."},{"japanese":"長年にわたって研究を続けてきました。","reading":"ながねんにわたってけんきゅうをつづけてきました。","english":"I have continued research over many years."}]', 'expression', 0, 2);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に関わらず (regardless of)', 'N / V (plain) + に関わらず / にかかわらず', 'Regardless of / irrespective of — outcome is the same no matter the condition', 'にかかわらず states that the main clause holds regardless of the condition. It is formal and often appears in official statements, rules, or policies. Can follow nouns or plain-form verbs.', '[{"japanese":"経験の有無に関わらず、応募できます。","reading":"けいけんのうむにかかわらず、おうぼできます。","english":"You can apply regardless of whether you have experience."},{"japanese":"天気に関わらず、イベントは開催します。","reading":"てんきにかかわらず、イベントはかいさいします。","english":"The event will be held regardless of the weather."},{"japanese":"結果に関わらず、全力を尽くします。","reading":"けっかにかかわらず、ぜんりょくをつくします。","english":"Regardless of the result, I will give my all."}]', 'expression', 0, 3);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に反して (contrary to / against)', 'N + に反して / に反する + N', 'Contrary to / against — the result goes against an expectation, wish, or rule', 'に反して expresses that something goes contrary to a norm, expectation, or wish. The preceding noun is often 予想, 期待, 規則, or 意志. に反する is the attributive form.', '[{"japanese":"予想に反して、試験は簡単でした。","reading":"よそうにはんして、しけんはかんたんでした。","english":"Contrary to expectations, the exam was easy."},{"japanese":"規則に反する行為は禁止されています。","reading":"きそくにはんするこういはきんしされています。","english":"Acts contrary to the rules are prohibited."},{"japanese":"父の意志に反して、芸術の道を選びました。","reading":"ちちのいしにはんして、げいじゅつのみちをえらびました。","english":"Contrary to my father''s wishes, I chose the path of art."}]', 'expression', 0, 4);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に際して (on the occasion of / when doing — formal)', 'V (plain non-past) + に際して / N + に際して', 'On the occasion of / when — formal marker for an important occasion or action', 'に際して is a formal expression marking an important occasion, ceremony, or significant moment. It is used in speeches, official documents, and formal situations. Similar to にあたって but often for more public events.', '[{"japanese":"入学に際して、注意事項をご確認ください。","reading":"にゅうがくにさいして、ちゅういじこうをごかくにんください。","english":"Upon enrollment, please confirm the precautions."},{"japanese":"契約を結ぶに際して、内容をよく読んでください。","reading":"けいやくをむすぶにさいして、ないようをよくよんでください。","english":"When signing a contract, please read the contents carefully."},{"japanese":"オリンピック開催に際して、多くの準備が必要でした。","reading":"オリンピックかいさいにさいして、おおくのじゅんびがひつようでした。","english":"Preparations were needed on the occasion of hosting the Olympics."}]', 'formal', 0, 5);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に先立って (prior to / in advance of)', 'V (plain non-past) + に先立って / N + に先立って', 'Prior to / before — marks a preparatory or preceding formal action', 'に先立って indicates something done in advance or beforehand as a preparation for what follows. It is formal and often appears in official announcements, ceremonies, or preparations for significant events.', '[{"japanese":"本日の講演に先立って、ご挨拶申し上げます。","reading":"ほんじつのこうえんにさきだって、ごあいさつもうしあげます。","english":"Prior to today''s lecture, allow me to offer a greeting."},{"japanese":"発売に先立って、プレビューイベントを開催します。","reading":"はつばいにさきだって、プレビューイベントをかいさいします。","english":"Prior to the sale, we will hold a preview event."},{"japanese":"工事を始めるに先立って、住民に説明しました。","reading":"こうじをはじめるにさきだって、じゅうみんにせつめいしました。","english":"Prior to starting construction, we explained to the residents."}]', 'formal', 0, 6);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜をはじめ (starting with / including)', 'N + をはじめ / をはじめとして', 'Starting with / including — marks the leading example of a group', 'をはじめ introduces the most representative or notable member of a group, with others following. をはじめとする/として is the attributive form. It implies there are many more examples beyond the one mentioned.', '[{"japanese":"東京をはじめ、多くの都市で開催されます。","reading":"とうきょうをはじめ、おおくのとしでかいさいされます。","english":"It will be held in many cities, starting with Tokyo."},{"japanese":"田中先生をはじめとする先生方に感謝します。","reading":"たなかせんせいをはじめとするせんせいがたにかんしゃします。","english":"I am grateful to the teachers, starting with Tanaka-sensei."},{"japanese":"日本語をはじめ、多くの言語が話されています。","reading":"にほんごをはじめ、おおくのげんごがはなされています。","english":"Many languages are spoken, including Japanese."}]', 'expression', 0, 7);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜をめぐって (surrounding / over the issue of)', 'N + をめぐって / をめぐる + N', 'Surrounding / over / regarding — marks a contested or debated topic', 'をめぐって marks the subject around which a dispute, debate, or competition revolves. It implies multiple perspectives or parties involved. をめぐる is the attributive form.', '[{"japanese":"その問題をめぐって激しい議論が行われました。","reading":"そのもんだいをめぐってはげしいぎろんがおこなわれました。","english":"Fierce debate was conducted surrounding that issue."},{"japanese":"遺産をめぐる家族の争いが続いています。","reading":"いさんをめぐるかぞくのあらそいがつづいています。","english":"The family dispute over the inheritance continues."},{"japanese":"政策をめぐって、賛否両論があります。","reading":"せいさくをめぐって、さんぴりょうろんがあります。","english":"There are opinions both for and against the policy."}]', 'expression', 0, 8);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を除いて (excluding / except for)', 'N + を除いて / を除く + N', 'Excluding / except for — marks what is left out of a group or statement', 'を除いて marks an exception. It is formal and more precise than 〜以外. を除く is the attributive form. Often used in official contexts, lists, and formal descriptions.', '[{"japanese":"土日を除いて、毎日営業しています。","reading":"どにちをのぞいて、まいにちえいぎょうしています。","english":"We are open every day except weekends."},{"japanese":"彼を除いて、全員賛成しました。","reading":"かれをのぞいて、ぜんいんさんせいしました。","english":"Everyone except him agreed."},{"japanese":"特別な場合を除いて、変更はできません。","reading":"とくべつなばあいをのぞいて、へんこうはできません。","english":"Changes cannot be made except in special cases."}]', 'expression', 0, 9);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜次第 (as soon as / depending on — after verb stem)', 'V-stem + 次第 (as soon as) / N + 次第 (depending on / up to)', 'As soon as / depending on / up to — triggers the next action or marks dependency', 'V-stem + 次第 means ''as soon as [action is complete]''. Different from 次第で/次第では (depending on). The verb-stem usage is common in business Japanese for expressing prompt follow-through.', '[{"japanese":"準備ができ次第、ご連絡します。","reading":"じゅんびができしだい、ごれんらくします。","english":"I will contact you as soon as preparations are complete."},{"japanese":"到着し次第、会議を始めましょう。","reading":"とうちゃくししだい、かいぎをはじめましょう。","english":"Let''s begin the meeting as soon as everyone arrives."},{"japanese":"確認でき次第、お知らせします。","reading":"かくにんできしだい、おしらせします。","english":"I will let you know as soon as I can confirm."}]', 'expression', 0, 10);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜かねない (might / could — negative potential)', 'V-stem + かねない', 'Might / could possibly (do something bad) — risk of negative outcome', 'かねない warns that something undesirable could happen. It implies the speaker sees a real possibility of the negative outcome. Not used for positive outcomes. Contrasts with かねる (reluctance to do).', '[{"japanese":"このままでは失敗しかねません。","reading":"このままではしっぱいしかねません。","english":"At this rate, there is a risk of failure."},{"japanese":"そんなことを言うと、誤解されかねませんよ。","reading":"そんなことをいうと、ごかいされかねませんよ。","english":"If you say something like that, you might be misunderstood."},{"japanese":"無理をすると、倒れかねない。","reading":"むりをすると、たおれかねない。","english":"If you push yourself too hard, you might collapse."}]', 'auxiliary', 0, 11);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜かねる (cannot bring myself to / reluctant)', 'V-stem + かねる / かねます', 'Cannot bring myself to / find it difficult — reluctance or difficulty doing something', 'かねる expresses that the speaker finds it difficult, inappropriate, or impossible to do something. It is polite and indirect — often used in business to decline requests without saying no directly. More formal than できない.', '[{"japanese":"その件については、お答えしかねます。","reading":"そのけんについては、おこたえしかねます。","english":"I am unable to answer regarding that matter."},{"japanese":"ご要望にはお応えしかねる場合があります。","reading":"ごようぼうにはおこたえしかねるばあいがあります。","english":"There may be cases where we cannot accommodate your request."},{"japanese":"一人で決めかねています。","reading":"ひとりできめかねています。","english":"I find it difficult to decide on my own."}]', 'auxiliary', 1, 12);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ざるを得ない (cannot help but / have no choice)', 'V-ない stem + ざるを得ない (する → せざるを得ない)', 'Cannot help but / have no choice but to — compelled by circumstances', 'ざるを得ない is a formal expression indicating there is no alternative. The speaker is compelled by external circumstances. する becomes せざるを得ない. More formal and literary than しかたなく or なければならない.', '[{"japanese":"証拠を見せられて、認めざるを得ませんでした。","reading":"しょうこをみせられて、みとめざるをえませんでした。","english":"Shown the evidence, I had no choice but to admit it."},{"japanese":"予算の関係で、計画を縮小せざるを得ない。","reading":"よさんのかんけいで、けいかくをしゅくしょうせざるをえない。","english":"Due to budget constraints, I have no choice but to scale down the plan."},{"japanese":"状況を考えると、賛成せざるを得ません。","reading":"じょうきょうをかんがえると、さんせいせざるをえません。","english":"Considering the situation, I have no choice but to agree."}]', 'expression', 0, 13);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜得る / 得ない (can / cannot happen — possibility)', 'V-stem + 得る (うる/える) / 得ない (えない)', 'Can happen / cannot happen — logical possibility or impossibility', '得る (sometimes read うる, sometimes える) expresses logical or theoretical possibility. 得ない means it is impossible or cannot occur. More formal than できる. ありえる = it is possible; ありえない = impossible.', '[{"japanese":"そんなことがあり得るとは思いませんでした。","reading":"そんなことがありえるとはおもいませんでした。","english":"I didn''t think such a thing could happen."},{"japanese":"完全に安全とは言い得ません。","reading":"かんぜんにあんぜんとはいいえません。","english":"It cannot be said to be completely safe."},{"japanese":"この計画は実現し得ると思います。","reading":"このけいかくはじつげんしえるとおもいます。","english":"I think this plan can be realised."}]', 'auxiliary', 0, 14);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜べきだ (should / ought to — moral obligation)', 'V (plain non-past) + べきだ / すべきだ', 'Should / ought to — strong moral or logical obligation', 'べきだ expresses a moral or logical obligation stronger than ほうがいい. It implies the action is the right or correct thing to do. する becomes すべき or するべき. べきではない = should not (strong prohibition).', '[{"japanese":"約束は守るべきです。","reading":"やくそくはまもるべきです。","english":"One should keep promises."},{"japanese":"もっと早く謝るべきでした。","reading":"もっとはやくあやまるべきでした。","english":"I should have apologised sooner."},{"japanese":"そのような行動はすべきではありません。","reading":"そのようなこうどうはすべきではありません。","english":"You should not take such actions."}]', 'auxiliary', 0, 15);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜っぽい (seeming like / -ish — casual)', 'V-stem / N / Adj-stem + っぽい', 'Seeming like / -ish / tending to — casual impression or tendency', 'っぽい is a casual suffix meaning ''seeming like'' or ''tends to''. It can attach to nouns (子供っぽい = childish), verb stems (飽きっぽい = prone to getting bored), or colour words (白っぽい = whitish). Colloquial and informal.', '[{"japanese":"この服、ちょっと子供っぽくない？","reading":"このふく、ちょっとこどもっぽくない？","english":"Isn''t this outfit a bit childish?"},{"japanese":"彼女は忘れっぽいですね。","reading":"かのじょはわすれっぽいですね。","english":"She tends to be forgetful."},{"japanese":"この壁、少し白っぽい色ですね。","reading":"このかべ、すこししろっぽいいろですね。","english":"This wall has a whitish colour."}]', 'auxiliary', 0, 16);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜くらいなら (rather than — lesser of two evils)', 'V (plain non-past) + くらいなら / ぐらいなら', 'Rather than / if it comes to that — prefers something else over the stated option', 'くらいなら presents a choice where the speaker finds the stated option so bad they would prefer even a worse-seeming alternative. It expresses a strong aversion to the first option.', '[{"japanese":"あんな人に頼むくらいなら、一人でやります。","reading":"あんなひとにたのむくらいなら、ひとりでやります。","english":"Rather than asking that person, I''d rather do it alone."},{"japanese":"負けるくらいなら、最初からやらない。","reading":"まけるくらいなら、さいしょからやらない。","english":"Rather than losing, I wouldn''t start in the first place."},{"japanese":"そんな仕事を続けるくらいなら、辞めたほうがいい。","reading":"そんなしごとをつづけるくらいなら、やめたほうがいい。","english":"Rather than continuing that kind of work, you''d better quit."}]', 'conditional', 0, 17);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜てまで (even going so far as to)', 'V-て + まで', 'Even to the point of doing — emphasises an extreme or undesirable means', 'てまで emphasises that the speaker or someone went to an extreme or undesirable length to achieve something. It often implies the action is excessive or the speaker disapproves. Compare with てでも (willingness to use extreme means).', '[{"japanese":"嘘をついてまで、勝ちたくない。","reading":"うそをついてまで、かちたくない。","english":"I don''t want to win even if it means lying."},{"japanese":"そこまでしてまで、続ける必要はあるの？","reading":"そこまでしてまで、つづけるひつようはあるの？","english":"Is there really a need to continue even going that far?"},{"japanese":"無理してまで参加しなくていいです。","reading":"むりしてまでさんかしなくていいです。","english":"You don''t need to participate even if it means pushing yourself."}]', 'expression', 0, 18);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜だけあって (as expected of / no wonder)', 'N / V (plain) + だけあって', 'As expected of / no wonder — justifies an observation given the known quality', 'だけあって expresses that a result is expected or unsurprising given a known quality or fact. It carries an admiring or confirming tone: ''given that X is true, it makes sense that Y''.', '[{"japanese":"プロだけあって、演奏が素晴らしかった。","reading":"プロだけあって、えんそうがすばらしかった。","english":"As expected of a professional, the performance was wonderful."},{"japanese":"10年間練習しただけあって、上手ですね。","reading":"10ねんかんれんしゅうしただけあって、じょうずですね。","english":"No wonder you''re good — you''ve practiced for 10 years."},{"japanese":"高いだけあって、品質がいいですね。","reading":"たかいだけあって、ひんしつがいいですね。","english":"No wonder the quality is good — it is expensive."}]', 'expression', 0, 19);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜だけに (precisely because / all the more)', 'N / V (plain) + だけに', 'Precisely because / all the more — the result is amplified by the quality or circumstance', 'だけに means ''because of exactly that quality, the result is even more so''. It highlights that a result (often negative or unfortunate) is especially poignant given the circumstances. Similar to だけあって but often with a heavier emotional weight.', '[{"japanese":"長年の夢だっただけに、失敗してとても残念でした。","reading":"ながねんのゆめだっただけに、しっぱいしてとてもざんねんでした。","english":"Precisely because it was a long-held dream, the failure was all the more disappointing."},{"japanese":"努力しただけに、結果が出なくて悔しかった。","reading":"どりょくしただけに、けっかがでなくてくやしかった。","english":"Because of all the effort put in, not getting results was frustrating."},{"japanese":"期待が大きかっただけに、失望も大きかった。","reading":"きたいがおおきかっただけに、しつぼうもおおきかった。","english":"The greater the expectation, the greater the disappointment."}]', 'expression', 0, 20);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ながら (although / despite — concessive)', 'V-stem / N + ながら', 'Although / while (concessive) — acknowledges a fact but goes against expectation', 'This concessive ながら (distinct from the simultaneous-action ながら) means ''although'' or ''despite''. It is used in patterns like 残念ながら (unfortunately) and 知りながら (even though knowing). More formal than が or けど.', '[{"japanese":"残念ながら、ご要望にお応えできません。","reading":"ざんねんながら、ごようぼうにおこたえできません。","english":"Unfortunately, we cannot accommodate your request."},{"japanese":"知りながら、何も言わなかった。","reading":"しりながら、なにもいわなかった。","english":"Despite knowing, he said nothing."},{"japanese":"小さいながら、とても使いやすいです。","reading":"ちいさいながら、とてもつかいやすいです。","english":"Although small, it is very easy to use."}]', 'conjunction', 0, 21);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜つつ (while / although — formal simultaneous or concessive)', 'V-stem + つつ / つつも', 'While (simultaneous) / although (concessive) — formal literary version of ながら', 'つつ is the formal/literary equivalent of ながら. つつも adds a concessive nuance (''even while / although''). Not used in casual conversation. Common in writing, formal speeches, and classical-influenced prose.', '[{"japanese":"音楽を聴きつつ、仕事をしています。","reading":"おんがくをききつつ、しごとをしています。","english":"I am working while listening to music."},{"japanese":"悪いと知りつつも、やめられません。","reading":"わるいとしりつつも、やめられません。","english":"Even while knowing it''s bad, I can''t stop."},{"japanese":"時代が変わりつつある。","reading":"じだいがかわりつつある。","english":"The era is in the process of changing."}]', 'conjunction', 0, 22);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜つつある (in the process of / gradually)', 'V-stem + つつある', 'In the process of / gradually — marks ongoing change or progression', 'つつある marks a process currently underway, often describing gradual social, environmental, or personal change. It is formal and commonly found in written Japanese, news, and academic writing.', '[{"japanese":"経済が回復しつつあります。","reading":"けいざいがかいふくしつつあります。","english":"The economy is in the process of recovering."},{"japanese":"彼の体調は改善しつつある。","reading":"かれのたいちょうはかいぜんしつつある。","english":"His physical condition is gradually improving."},{"japanese":"日本の少子化は深刻化しつつあります。","reading":"にほんのしょうしかはしんこくかしつつあります。","english":"Japan''s declining birth rate is becoming increasingly serious."}]', 'conjunction', 0, 23);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にあたって (when / on the occasion of — careful action)', 'V (plain non-past) + にあたって / N + にあたって', 'When / on the occasion of — marks a significant moment requiring care or preparation', 'にあたって is similar to に際して but slightly less ceremonial. It marks an important occasion or action, implying care, consideration, or preparation. Common in speeches, official texts, and formal writing.', '[{"japanese":"新しいプロジェクトを始めるにあたって、計画を立てました。","reading":"あたらしいプロジェクトをはじめるにあたって、けいかくをたてました。","english":"When starting the new project, I made a plan."},{"japanese":"卒業にあたって、先生に感謝の言葉を述べました。","reading":"そつぎょうにあたって、せんせいにかんしゃのことばをのべました。","english":"On the occasion of graduation, I expressed my gratitude to the teacher."},{"japanese":"この仕事を引き受けるにあたって、条件があります。","reading":"このしごとをひきうけるにあたって、じょうけんがあります。","english":"When accepting this work, there are conditions."}]', 'formal', 0, 24);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を中心に (centred on / focusing on)', 'N + を中心に / を中心として', 'Centred on / focused on — marks the central element around which things revolve', 'を中心に marks the focal point of activity, attention, or organisation. を中心にした or を中心とする is the attributive form. Common in describing projects, initiatives, geographic arrangements, and group activities.', '[{"japanese":"東京を中心に、全国で講演を行います。","reading":"とうきょうをちゅうしんに、ぜんこくでこうえんをおこないます。","english":"We will hold lectures nationwide, centred on Tokyo."},{"japanese":"若者を中心に、スマートフォンの利用が増えています。","reading":"わかものをちゅうしんに、スマートフォンのりようがふえています。","english":"Centred on young people, smartphone usage is increasing."},{"japanese":"彼を中心としたチームが結成されました。","reading":"かれをちゅうしんとしたチームがけっせいされました。","english":"A team centred around him was formed."}]', 'expression', 0, 25);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に過ぎない (nothing more than / merely)', 'V/Adj (plain) + に過ぎない / N + に過ぎない', 'Nothing more than / merely — downplays or limits the significance of something', 'に過ぎない states that something is ''no more than'' a certain thing, often downplaying exaggeration or limiting scope. It implies the speaker is correcting an overestimation or providing a humble qualification.', '[{"japanese":"これは私の個人的な意見に過ぎません。","reading":"これはわたしのこじんてきないけんにすぎません。","english":"This is nothing more than my personal opinion."},{"japanese":"それは偶然に過ぎないと思います。","reading":"それはぐうぜんにすぎないとおもいます。","english":"I think that''s merely a coincidence."},{"japanese":"私はただのサラリーマンに過ぎない。","reading":"わたしはただのサラリーマンにすぎない。","english":"I am nothing more than an ordinary office worker."}]', 'expression', 0, 26);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にほかならない (none other than / nothing but)', 'N / V (plain) + にほかならない', 'None other than / is precisely — strong formal assertion of identity or cause', 'にほかならない is a formal, emphatic expression meaning ''is precisely X and nothing else''. It identifies the true nature or cause of something definitively. More formal and emphatic than だ alone.', '[{"japanese":"これは皆さんの努力の結果にほかならない。","reading":"これはみなさんのどりょくのけっかにほかならない。","english":"This is none other than the result of everyone''s efforts."},{"japanese":"彼が成功したのは才能があるからにほかならない。","reading":"かれがせいこうしたのはさいのうがあるからにほかならない。","english":"The reason he succeeded is none other than his talent."},{"japanese":"それは愛情にほかならないと思います。","reading":"それはあいじょうにほかならないとおもいます。","english":"That is nothing other than love, I believe."}]', 'expression', 0, 27);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜というものだ (that''s what ... is / it''s only natural)', 'V/Adj (plain) + というものだ', 'That''s what X is / it''s only natural — states a general truth or norm assertively', 'というものだ asserts a general truth or social norm. It often carries a tone of ''that''s the nature of things'' or ''that''s exactly what something is''. More emphatic than ものだ alone.', '[{"japanese":"苦労してこそ、本当の喜びというものだ。","reading":"くろうしてこそ、ほんとうのよろこびというものだ。","english":"True joy is something that comes through hardship."},{"japanese":"親ならば子供を守るというものだ。","reading":"おやならばこどもをまもるというものだ。","english":"It''s only natural for a parent to protect their child."},{"japanese":"失敗から学ぶというものですよ。","reading":"しっぱいからまなぶというものですよ。","english":"That''s what learning from failure is all about."}]', 'expression', 0, 28);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜といったN (... type things / things like)', '「list」 + といった + N', 'Such ... as / things like — lists examples of the type of noun that follows', 'といった precedes a noun to list examples of that category. Similar to というような but slightly more formal. Common in written Japanese, academic texts, and formal speech.', '[{"japanese":"経済や政治といった問題について話しました。","reading":"けいざいやせいじといったもんだいについてはなしました。","english":"We talked about issues such as economics and politics."},{"japanese":"サッカーや野球といったスポーツが好きです。","reading":"サッカーややきゅうといったスポーツがすきです。","english":"I like sports such as football and baseball."},{"japanese":"環境といった問題に取り組む必要があります。","reading":"かんきょうといったもんだいにとりくむひつようがあります。","english":"We need to tackle issues like environmental problems."}]', 'expression', 0, 29);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ないわけにはいかない (cannot avoid — obligated to do)', 'V-ない + わけにはいかない', 'Cannot avoid doing / must do — obligated by social or moral reason', 'ないわけにはいかない is the negative form: you cannot avoid doing it. The social or moral situation compels the action. It implies reluctance but inevitability. Distinguish from ないわけがない (there''s no way it''s not true).', '[{"japanese":"頼まれたのだから、断らないわけにはいきません。","reading":"たのまれたのだから、ことわらないわけにはいきません。","english":"Since I was asked, I cannot avoid not refusing (= I must accept)."},{"japanese":"事実を知ったなら、報告しないわけにはいかない。","reading":"じじつをしったなら、ほうこくしないわけにはいかない。","english":"Now that I know the facts, I cannot avoid reporting them."},{"japanese":"お世話になった方の結婚式には出席しないわけにはいかない。","reading":"おせわになったかたのけっこんしきにはしゅっせきしないわけにはいかない。","english":"I cannot avoid attending the wedding of someone who has looked after me."}]', 'expression', 0, 30);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に基づいて (based on / in accordance with)', 'N + に基づいて / に基づく + N', 'Based on / in accordance with — marks the foundation or evidence for an action', 'に基づいて expresses that an action or decision is based on a specific foundation (rules, data, evidence, law). に基づく is the attributive form. More formal and precise than をもとに.', '[{"japanese":"データに基づいて分析しました。","reading":"データにもとづいてぶんせきしました。","english":"I analysed based on the data."},{"japanese":"法律に基づいて処罰されます。","reading":"ほうりつにもとづいてしょばつされます。","english":"Punishment will be carried out in accordance with the law."},{"japanese":"事実に基づく報告書を提出してください。","reading":"じじつにもとづくほうこくしょをていしゅつしてください。","english":"Please submit a report based on the facts."}]', 'expression', 0, 31);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に照らして (in light of / based on)', 'N + に照らして / に照らし合わせて', 'In light of / judged against — evaluating by comparing to a standard or criterion', 'に照らして means to evaluate or judge something by holding it up against a standard, rule, or reference. に照らし合わせて is a stronger form emphasising direct comparison. Common in legal, academic, and evaluative contexts.', '[{"japanese":"規則に照らして考えると、これは問題です。","reading":"きそくにてらしてかんがえると、これはもんだいです。","english":"In light of the rules, this is a problem."},{"japanese":"過去の事例に照らして判断しました。","reading":"かこのじれいにてらしてはんだんしました。","english":"I made a judgement in light of past cases."},{"japanese":"現実に照らし合わせて、計画を修正します。","reading":"げんじつにてらしあわせて、けいかくをしゅうせいします。","english":"I will revise the plan by comparing it against reality."}]', 'formal', 0, 32);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にしても〜にしても (whether ... or)', 'N/V + にしても + N/V + にしても', 'Whether ... or — the result holds in both cases', 'にしても〜にしても states that regardless of which of two options applies, the result or conclusion is the same. It covers both cases to show the conclusion is unavoidable.', '[{"japanese":"賛成にしても反対にしても、意見を述べてください。","reading":"さんせいにしてもはんたいにしても、いけんをのべてください。","english":"Whether you agree or disagree, please state your opinion."},{"japanese":"行くにしても行かないにしても、早めに決めてください。","reading":"いくにしてもいかないにしても、はやめにきめてください。","english":"Whether you go or not, please decide early."},{"japanese":"成功にしても失敗にしても、挑戦することに意味があります。","reading":"せいこうにしてもしっぱいにしても、ちょうせんすることにいみがあります。","english":"Whether you succeed or fail, there is meaning in trying."}]', 'conjunction', 0, 33);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に限らず (not limited to / not only)', 'N + に限らず', 'Not limited to / not only — broadens the scope beyond the stated example', 'に限らず means ''not limited to / not only X''. It extends the statement to include other things beyond the one mentioned. Formal, often found in written Japanese.', '[{"japanese":"日本に限らず、世界中で問題になっています。","reading":"にほんにかぎらず、せかいじゅうでもんだいになっています。","english":"Not limited to Japan, it has become a problem worldwide."},{"japanese":"大人に限らず、子供も楽しめるイベントです。","reading":"おとなにかぎらず、こどももたのしめるイベントです。","english":"It''s an event not limited to adults — children can enjoy it too."},{"japanese":"女性に限らず、男性も参加できます。","reading":"じょせいにかぎらず、だんせいもさんかできます。","english":"Not limited to women, men can also participate."}]', 'expression', 0, 34);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ことなく (without doing — formal)', 'V (plain non-past) + ことなく', 'Without doing — formal version of ずに/ないで', 'ことなく is a formal literary expression meaning ''without doing''. It is more formal than ずに and found in written Japanese, formal speech, and literary contexts. Often appears in set phrases expressing continuous effort.', '[{"japanese":"諦めることなく、最後まで頑張りました。","reading":"あきらめることなく、さいごまでがんばりました。","english":"Without giving up, I persevered to the end."},{"japanese":"休むことなく、24時間働き続けました。","reading":"やすむことなく、24じかんはたらきつづけました。","english":"Without resting, I continued working for 24 hours."},{"japanese":"変わることなく、ずっとそこにある。","reading":"かわることなく、ずっとそこにある。","english":"Without changing, it has always been there."}]', 'conjunction', 0, 35);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ことに (to my ... / the fact is — emotional emphasis)', 'V-た / Adj (plain) + ことに', 'To my [emotion] / the fact is — marks an emotional reaction to a fact', 'ことに follows an adjective or past verb to express the speaker''s emotional response to a situation. Common patterns: 残念なことに (regrettably), 嬉しいことに (happily), 驚いたことに (surprisingly).', '[{"japanese":"残念なことに、彼は来られなかった。","reading":"ざんねんなことに、かれはこられなかった。","english":"Regrettably, he was unable to come."},{"japanese":"嬉しいことに、試験に合格しました。","reading":"うれしいことに、しけんにごうかくしました。","english":"Happily, I passed the exam."},{"japanese":"驚いたことに、彼女はすでに知っていた。","reading":"おどろいたことに、かのじょはすでにしっていた。","english":"Surprisingly, she already knew."}]', 'expression', 0, 36);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に沿って (along / in line with)', 'N + に沿って / に沿った + N', 'Along / in line with / following — proceeds parallel to or in accordance with', 'に沿って means to go along a physical path or to follow a plan, policy, or wish. に沿った is the attributive form. More concrete (along a river) or figurative (along the plan) uses are both common.', '[{"japanese":"川に沿って歩きました。","reading":"かわにそってあるきました。","english":"I walked along the river."},{"japanese":"計画に沿って進めましょう。","reading":"けいかくにそってすすめましょう。","english":"Let''s proceed in line with the plan."},{"japanese":"方針に沿った対応が求められます。","reading":"ほうしんにそったたいおうがもとめられます。","english":"A response in line with the policy is required."}]', 'expression', 0, 37);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜からすると / からすれば (from the perspective of / judging from)', 'N + からすると / からすれば / からして', 'From the perspective of / judging from — marks the basis for a judgement or inference', 'からすると/からすれば marks the standpoint from which a judgement is made. It is used when inferring or evaluating based on available information or someone''s perspective. からして can stress the starting point (''even from just X...'').', '[{"japanese":"外見からすると、彼は若く見えます。","reading":"がいけんからすると、かれはわかくみえます。","english":"Judging from his appearance, he looks young."},{"japanese":"専門家の立場からすれば、この方法は危険です。","reading":"せんもんかのたちばからすれば、このほうほうはきけんです。","english":"From the perspective of an expert, this method is dangerous."},{"japanese":"声からして、彼女だとわかった。","reading":"こえからして、かのじょだとわかった。","english":"Just from her voice, I knew it was her."}]', 'expression', 0, 38);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜てでも (even by doing — determination)', 'V-て + でも', 'Even by doing — willingness to use extreme or undesirable means', 'てでも expresses strong determination to achieve a goal, even if the means are difficult or undesirable. The speaker declares they will do whatever it takes. Contrasts with てまで (which expresses reluctance).', '[{"japanese":"借金をしてでも、この家を買いたい。","reading":"しゃっきんをしてでも、このいえをかいたい。","english":"Even if I have to borrow money, I want to buy this house."},{"japanese":"徹夜してでも、この仕事を終わらせます。","reading":"てつやしてでも、このしごとをおわらせます。","english":"Even if I have to pull an all-nighter, I''ll finish this work."},{"japanese":"どんな手を使ってでも、勝ちに行く。","reading":"どんなてをつかってでも、かちにいく。","english":"I''ll go for the win using whatever means it takes."}]', 'expression', 0, 39);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にしたって / にしても (even for / even if — extended scope)', 'N + にしたって / にしても', 'Even for / even if — broadens a statement to include an additional case', 'にしても and にしたって (casual) introduce an additional case that also applies, or acknowledge a concession while maintaining the main point. Similar to even if / even for. にしたって is slightly more colloquial.', '[{"japanese":"彼にしたって、問題を知っていたはずだ。","reading":"かれにしたって、もんだいをしっていたはずだ。","english":"Even for him, he must have known about the problem."},{"japanese":"忙しいにしても、連絡くらいすべきでした。","reading":"いそがしいにしても、れんらくくらいすべきでした。","english":"Even if you were busy, you should have at least contacted me."},{"japanese":"子供にしても、それくらいは分かります。","reading":"こどもにしても、それくらいはわかります。","english":"Even a child would understand that much."}]', 'conjunction', 0, 40);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を契機に (taking ... as an opportunity / triggered by)', 'N + を契機に / を契機として', 'Taking ... as an opportunity / triggered by — marks a turning point event', 'を契機に marks an event that served as a trigger or turning point for a change. It implies the change was significant and the event that caused it was a clear catalyst.', '[{"japanese":"その失敗を契機に、生活を見直しました。","reading":"そのしっぱいをけいきに、せいかつをみなおしました。","english":"Taking that failure as an opportunity, I reassessed my life."},{"japanese":"この事件を契機として、法律が改正されました。","reading":"このじけんをけいきとして、ほうりつがかいせいされました。","english":"Triggered by this incident, the law was revised."},{"japanese":"留学を契機に、将来の方向が変わりました。","reading":"りゅうがくをけいきに、しょうらいのほうこうがかわりました。","english":"Studying abroad served as a turning point that changed my future direction."}]', 'expression', 0, 41);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を踏まえて (based on / taking ... into account)', 'N + を踏まえて / を踏まえた + N', 'Based on / taking into account — acts with awareness of existing facts or context', 'を踏まえて means to proceed based on or taking into account relevant existing information, results, or context. It implies the information has been properly considered before acting.', '[{"japanese":"前回の結果を踏まえて、計画を修正しました。","reading":"ぜんかいのけっかをふまえて、けいかくをしゅうせいしました。","english":"Based on last time''s results, I revised the plan."},{"japanese":"現状を踏まえた上で、対策を考えましょう。","reading":"げんじょうをふまえたうえで、たいさくをかんがえましょう。","english":"Let''s consider countermeasures based on the current situation."},{"japanese":"ご意見を踏まえて対応します。","reading":"ごいけんをふまえてたいおうします。","english":"I will respond taking your opinion into account."}]', 'expression', 0, 42);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に鑑みて (in view of / considering — very formal)', 'N + に鑑みて / に鑑みた + N', 'In view of / considering — very formal, used in official documents', 'に鑑みて is a very formal expression meaning to consider or evaluate something in light of a standard, precedent, or important fact. Found in legal documents, official speeches, and formal writing. Rarely used in daily conversation.', '[{"japanese":"昨今の状況に鑑みて、方針を変更します。","reading":"さっこんのじょうきょうにかんがみて、ほうしんをへんこうします。","english":"In view of the current situation, we are changing our policy."},{"japanese":"過去の実績に鑑みて、彼を選びました。","reading":"かこのじっせきにかんがみて、かれをえらびました。","english":"In view of past results, we chose him."},{"japanese":"社会情勢に鑑みた対応が必要です。","reading":"しゃかいじょうせいにかんがみたたいおうがひつようです。","english":"A response in view of the social situation is necessary."}]', 'formal', 0, 43);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜かといえば / かというと (if I were to say / speaking of)', '疑問詞 + かといえば / かというと', 'If asked whether / if I were to say — introduces an explanation or qualification', '〜かといえば/かというと introduces an answer or clarification to the question implied. Often used to partially agree then add nuance: 好きかといえば、そうでもない = if you ask if I like it, not really. Common in explanatory or reflective speech.', '[{"japanese":"なぜそうしたかといえば、心配だったからです。","reading":"なぜそうしたかといえば、しんぱいだったからです。","english":"If you ask why I did that, it''s because I was worried."},{"japanese":"うまいかというと、そうでもないですね。","reading":"うまいかというと、そうでもないですね。","english":"If you ask whether it''s good, not particularly."},{"japanese":"好きかといえば、まあそうでもないかな。","reading":"すきかといえば、まあそうでもないかな。","english":"If asked if I like it, well, not really I suppose."}]', 'expression', 0, 44);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜というより (rather than / more like)', 'S + というより', 'Rather than / more accurately — corrects or refines what was just said', 'というより replaces or refines the preceding description with a more accurate one. The speaker says X, then corrects or clarifies: ''rather, it''s Y''. Used when a more precise term exists or to soften an assertion.', '[{"japanese":"彼は怒っているというより、悲しんでいる。","reading":"かれはおこっているというより、かなしんでいる。","english":"Rather than angry, he seems sad."},{"japanese":"これは便利というより、必要不可欠です。","reading":"これはべんりというより、ひつようふかけつです。","english":"Rather than convenient, this is indispensable."},{"japanese":"疲れているというより、眠いんです。","reading":"つかれているというより、ねむいんです。","english":"Rather than tired, I''m actually sleepy."}]', 'expression', 0, 45);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に反する (to go against — attributive)', 'N + に反する + N', 'That goes against / contrary to — attributive form modifying a noun', 'に反する is the attributive (noun-modifying) form of に反して. Used when modifying a noun: 規則に反する行為 = conduct contrary to the rules. Common in legal, ethical, and formal contexts.', '[{"japanese":"規則に反する行為は許されません。","reading":"きそくにはんするこういはゆるされません。","english":"Conduct contrary to the rules is not permitted."},{"japanese":"命令に反する行動を取ってしまいました。","reading":"めいれいにはんするこうどうをとってしまいました。","english":"I ended up taking action contrary to orders."},{"japanese":"常識に反する判断に驚きました。","reading":"じょうしきにはんするはんだんにおどろきました。","english":"I was surprised by the judgement contrary to common sense."}]', 'formal', 0, 46);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ものがある (there is a sense of / something about it)', 'V/Adj (plain) + ものがある', 'There is a certain quality / something about it — expresses an indescribable sense', 'ものがある expresses that there is some inherent quality or feeling about something that is hard to fully articulate. It is used when the speaker perceives a notable or strong quality. More formal than 感じがする.', '[{"japanese":"彼の演奏には感動するものがある。","reading":"かれのえんそうにはかんどうするものがある。","english":"There is something moving about his performance."},{"japanese":"この問題には考えさせられるものがある。","reading":"このもんだいにはかんがえさせられるものがある。","english":"There is something thought-provoking about this problem."},{"japanese":"彼女の言葉には人を引きつけるものがある。","reading":"かのじょのことばにはひとをひきつけるものがある。","english":"There is something attractive about her words."}]', 'expression', 0, 47);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ようがない / ようもない (no way to / cannot possibly)', 'V-stem + ようがない / ようもない', 'There is no way to / impossible to — complete impossibility of method', 'ようがない expresses that there is absolutely no means or way to do something. Unlike できない (lack of ability), ようがない emphasises the absence of any possible method at all.', '[{"japanese":"あの人の言っていることは、理解しようがない。","reading":"あのひとのいっていることは、りかいしようがない。","english":"There''s no way to understand what that person is saying."},{"japanese":"連絡先も知らないから、知らせようがない。","reading":"れんらくさきもしらないから、しらせようがない。","english":"I don''t even know their contact information, so there''s no way to notify them."},{"japanese":"証拠がないと、証明しようがありません。","reading":"しょうこがないと、しょうめいしようがありません。","english":"Without evidence, there''s no way to prove it."}]', 'expression', 0, 48);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に足りない / 足る (worth doing / not worth)', 'V (plain non-past) + に足る / に足りない', 'Worth doing / not worth — something merits or does not merit the action', 'に足る/に足りる means ''worthy of / sufficient for''. に足らない/足りない means ''not worth / not sufficient''. Formal and literary expressions used in evaluative contexts.', '[{"japanese":"信頼するに足る人物です。","reading":"しんらいするにたるじんぶつです。","english":"He is a person worthy of trust."},{"japanese":"そんなことは相手にするに足りない。","reading":"そんなことはあいてにするにたりない。","english":"That''s not worth dealing with."},{"japanese":"彼の意見は検討するに値します。","reading":"かれのいけんはけんとうするにあたいします。","english":"His opinion is worth considering."}]', 'formal', 0, 49);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を皮切りに (beginning with / starting with — first in a series)', 'N + を皮切りに / を皮切りとして', 'Beginning with / starting with — marks the first event in a series', 'を皮切りに marks the opening event that starts a series of similar events. It implies subsequent events will follow. より formal than から, and carries a sense of momentum or occasion.', '[{"japanese":"東京公演を皮切りに、全国ツアーが始まります。","reading":"とうきょうこうえんをかわきりに、ぜんこくツアーがはじまります。","english":"Starting with the Tokyo performance, a nationwide tour begins."},{"japanese":"この商品の発売を皮切りに、新展開が続きます。","reading":"このしょうひんのはつばいをかわきりに、しんてんかいがつづきます。","english":"Beginning with this product launch, new developments will follow."},{"japanese":"彼女の一言を皮切りとして、議論が始まった。","reading":"かのじょのひとことをかわきりとして、ぎろんがはじまった。","english":"Starting with her single remark, a debate began."}]', 'expression', 0, 50);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜といえども (even though / even if — formal concession)', 'N / V (plain) + といえども', 'Even though / even if — formal concessive acknowledging a fact while contrasting', 'といえども is a formal/literary concessive meaning ''even though / even if''. It acknowledges a fact or quality but then presents a contrasting outcome. More elevated in register than ても or のに.', '[{"japanese":"ベテランといえども、失敗することはある。","reading":"ベテランといえども、しっぱいすることはある。","english":"Even a veteran can make mistakes."},{"japanese":"子供といえども、罰せられることがある。","reading":"こどもといえども、ばっせられることがある。","english":"Even a child can be punished."},{"japanese":"冗談といえども、傷つく言葉はよくない。","reading":"じょうだんといえども、きずつくことばはよくない。","english":"Even as a joke, hurtful words are not good."}]', 'formal', 0, 51);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜をもって (with / by means of — formal)', 'N + をもって', 'With / by means of / as of — formal marker for means, reason, or time limit', 'をもって is a formal expression with two main uses: (1) by means of / with (tool or quality); (2) as of [date/time] — often used in formal announcements: 本日をもって. More formal than で.', '[{"japanese":"本日をもって、受付を終了いたします。","reading":"ほんじつをもって、うけつけをしゅうりょういたします。","english":"As of today, we will close the reception."},{"japanese":"誠意をもって対応いたします。","reading":"せいいをもってたいおうしたします。","english":"We will respond with sincerity."},{"japanese":"努力をもって、困難を乗り越えました。","reading":"どりょくをもって、こんなんをのりこえました。","english":"With effort, I overcame the difficulty."}]', 'formal', 1, 52);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜いかんによって / いかんでは (depending on — formal)', 'N + のいかんによって / いかんでは', 'Depending on — formal expression for outcome contingent on a factor', 'いかん is a formal/written word meaning ''the state of / what it is like''. のいかんによって/いかんでは expresses that the outcome depends on how things turn out or what the situation is. Formal and bureaucratic in register.', '[{"japanese":"結果のいかんによっては、計画を変更します。","reading":"けっかのいかんによっては、けいかくをへんこうします。","english":"Depending on the results, we may change the plan."},{"japanese":"経緯のいかんによって、対応が異なります。","reading":"けいいのいかんによって、たいおうがことなります。","english":"The response differs depending on the circumstances."},{"japanese":"態度のいかんでは、入学を拒否することがあります。","reading":"たいどのいかんでは、にゅうがくをきょひすることがあります。","english":"Depending on the attitude, admission may be refused."}]', 'formal', 0, 53);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜とは (definition / surprise — formal clause marker)', 'N / S (plain) + とは', 'As for / what is called — defines, explains, or expresses surprise about something', 'とは introduces a definition or explanation (〜とは〜のことです) or expresses surprise/disbelief when something unexpected occurs (まさかこんなことになるとは！). Formal; casual version is って or というのは.', '[{"japanese":"自由とは、責任を伴うものです。","reading":"じゆうとは、せきにんをともなうものです。","english":"Freedom is something that comes with responsibility."},{"japanese":"まさかここで会うとは思いませんでした。","reading":"まさかここであうとはおもいませんでした。","english":"I never thought I would meet you here."},{"japanese":"信頼とはどういうものか、考えさせられました。","reading":"しんらいとはどういうものか、かんがえさせられました。","english":"I was made to think about what trust really is."}]', 'expression', 0, 54);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜として扱う / 〜として見る (treat as / see as)', 'N + として扱う / として見る / として認める', 'Treat as / regard as / recognise as — applies a category or status to something', 'として followed by action verbs like 扱う (treat), 見る (see/view), 認める (recognise) expresses how something is classified or treated. It is the evaluative use of として, applied in formal contexts.', '[{"japanese":"この件は緊急事態として扱います。","reading":"このけんはきんきゅうじたいとしてあつかいます。","english":"We will treat this matter as an emergency."},{"japanese":"彼の行動は問題として見ています。","reading":"かれのこうどうはもんだいとしてみています。","english":"We view his actions as a problem."},{"japanese":"このシステムを正式なものとして認めました。","reading":"このシステムをせいしきなものとしてみとめました。","english":"We have recognised this system as an official one."}]', 'expression', 0, 55);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜からといって (just because ... doesn''t mean)', 'S (plain) + からといって + negative or limiting conclusion', 'Just because ... doesn''t mean — dismisses a naive inference from a given fact', 'からといって warns against drawing an automatic conclusion from a premise. It says ''just because A, it doesn''t follow that B''. The main clause typically contains a negative or limiting statement.', '[{"japanese":"お金があるからといって、幸せとは限りません。","reading":"おかねがあるからといって、しあわせとはかぎりません。","english":"Just because you have money doesn''t mean you''re happy."},{"japanese":"知っているからといって、何でも言っていいわけじゃない。","reading":"しっているからといって、なんでもいっていいわけじゃない。","english":"Just because you know something doesn''t mean you can say anything."},{"japanese":"有名だからといって、いい映画とは限りません。","reading":"ゆうめいだからといって、いいえいがとはかぎりません。","english":"Just because it''s famous doesn''t mean it''s a good film."}]', 'conjunction', 0, 56);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に相違ない (without doubt — very formal)', 'S (plain) + に相違ない', 'Without doubt / certainly — formal equivalent of に違いない', 'に相違ない is the formal/written equivalent of に違いない. It expresses certainty or strong conviction. Used in formal writing, legal contexts, and official documents rather than spoken Japanese.', '[{"japanese":"これは本物に相違ない。","reading":"これはほんものにそういない。","english":"This is without doubt the real thing."},{"japanese":"彼が犯人に相違ないと確信しています。","reading":"かれがはんにんにそういないとかくしんしています。","english":"I am convinced that he is without doubt the culprit."},{"japanese":"その事実は誤りに相違ありません。","reading":"そのじじつはあやまりにそういありません。","english":"That fact is without doubt an error."}]', 'formal', 0, 57);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜向きだ / 向きの (suitable for / facing)', 'N + 向きだ / 向きの + N', 'Suitable for / oriented toward — matches or is appropriate for the target', '向きだ indicates suitability or orientation toward something. 〜向きの modifies a noun. Distinct from 向けに (aimed at / intended for which marks design intent) — 向きだ marks natural suitability or fit.', '[{"japanese":"この仕事は彼女向きだと思います。","reading":"このしごとはかのじょむきだとおもいます。","english":"I think this job suits her."},{"japanese":"これは初心者向きの参考書です。","reading":"これはしょしんしゃむきのさんこうしょです。","english":"This is a reference book suitable for beginners."},{"japanese":"南向きの部屋は日当たりがいいです。","reading":"みなみむきのへやはひあたりがいいです。","english":"A south-facing room gets good sunlight."}]', 'expression', 0, 58);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に越したことはない (nothing better than / best to)', 'V (plain non-past) + に越したことはない / Adj + に越したことはない', 'Nothing is better than / best to — states the ideal option', 'に越したことはない means that while not strictly necessary, X is the best course of action. It is often used as advice: the more, the better; the safer, the better. Casual shortening is に越したことない.', '[{"japanese":"健康は大切にするに越したことはない。","reading":"けんこうはたいせつにするにこしたことはない。","english":"There is nothing better than taking care of your health."},{"japanese":"早めに準備するに越したことはありません。","reading":"はやめにじゅんびするにこしたことはありません。","english":"Nothing is better than preparing early."},{"japanese":"安全に越したことはないですよ。","reading":"あんぜんにこしたことはないですよ。","english":"Nothing is better than being safe."}]', 'expression', 0, 59);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜てはじめて (only after doing / not until)', 'V-て + はじめて', 'Only after doing / not until — something becomes true or understood only after the action', 'てはじめて expresses that something is only realised, possible, or true after a specific experience or action has occurred. It often carries the nuance of appreciation or understanding gained through experience.', '[{"japanese":"失って初めて、その大切さがわかります。","reading":"うしなってはじめて、そのたいせつさがわかります。","english":"Only after losing it do you understand its importance."},{"japanese":"実際にやってみて初めて、難しさがわかりました。","reading":"じっさいにやってみてはじめて、むずかしさがわかりました。","english":"Only after actually trying did I understand the difficulty."},{"japanese":"日本に来て初めて、本当の日本語を学べました。","reading":"にほんにきてはじめて、ほんとうのにほんごをまなべました。","english":"Only after coming to Japan was I able to learn real Japanese."}]', 'conjunction', 0, 60);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜に際し (on the occasion of — ultra-formal)', 'V (plain non-past) + に際し / N + に際し', 'On the occasion of — extremely formal, used in official texts and ceremonies', 'に際し is the shortened (pre-noun/pre-clause) form of に際して. It is even more formal and often appears in written texts, official proclamations, and formal speeches where に際して would also be appropriate.', '[{"japanese":"ご入学に際し、心よりお祝い申し上げます。","reading":"ごにゅうがくにさいし、こころよりおいわいもうしあげます。","english":"On the occasion of your enrollment, I offer my sincere congratulations."},{"japanese":"プロジェクト開始に際し、説明会を行います。","reading":"プロジェクトかいしにさいし、せつめいかいをおこないます。","english":"On the occasion of the project start, we will hold a briefing."},{"japanese":"渡航に際し、必要な書類を準備してください。","reading":"とこうにさいし、ひつようなしょるいをじゅんびしてください。","english":"On the occasion of your departure, please prepare the necessary documents."}]', 'formal', 1, 61);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を通じて / 通して (through / throughout)', 'N + を通じて / を通して', 'Through / by way of / throughout — marks a medium, channel, or entire duration', 'These two forms are nearly interchangeable. Both mean ''through (a medium)'' or ''throughout (a period)''. を通じて has a slightly more formal nuance and can emphasise the mediating function; を通して can be more literal (physically through) or metaphorical.', '[{"japanese":"スポーツを通じて、友情が育まれます。","reading":"スポーツをつうじて、ゆうじょうがはぐくまれます。","english":"Through sports, friendship is nurtured."},{"japanese":"一年を通して、平均気温は高いです。","reading":"いちねんをとおして、へいきんきおんはたかいです。","english":"Throughout the year, the average temperature is high."},{"japanese":"メールを通じて申し込んでください。","reading":"メールをつうじてもうしこんでください。","english":"Please apply through email."}]', 'expression', 0, 62);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜にあたる (to correspond to / be equivalent to)', 'N / V (plain) + にあたる', 'Correspond to / be equivalent to / fall on — marks equivalence or classification', 'にあたる expresses that something falls into a certain category, corresponds to something, or falls on a particular date. It can also mean ''be equivalent to'' in a conceptual or structural sense.', '[{"japanese":"今日は創立記念日にあたります。","reading":"きょうはそうりつきねんびにあたります。","english":"Today falls on the founding anniversary."},{"japanese":"この役職は部長にあたります。","reading":"このやくしょくはぶちょうにあたります。","english":"This position corresponds to the department head."},{"japanese":"英語の ''uncle'' は日本語で叔父にあたります。","reading":"えいごの ''uncle'' はにほんごでおじにあたります。","english":"The English ''uncle'' corresponds to 叔父 in Japanese."}]', 'expression', 0, 63);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜反面 (on the other hand / while)', 'V/Adj (plain) + 反面 / N の + 反面', 'On the other hand / while — presents contrasting aspects of the same subject', '反面 presents two contrasting sides of the same person, thing, or situation. The same subject has both qualities simultaneously. More formal than が or 一方で, and the contrast is usually presented as a natural trade-off.', '[{"japanese":"便利な反面、プライバシーの問題があります。","reading":"べんりなはんめん、プライバシーのもんだいがあります。","english":"While convenient, there are privacy issues."},{"japanese":"彼は優しい反面、優柔不断なところがある。","reading":"かれはやさしいはんめん、ゆうじゅうふだんなところがある。","english":"While he is kind, he has an indecisive side."},{"japanese":"都会は便利な反面、自然が少ないです。","reading":"とかいはべんりなはんめん、しぜんがすくないです。","english":"While cities are convenient, there is little nature."}]', 'conjunction', 0, 64);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜一方だ (keeps getting more and more)', 'V (plain non-past) + 一方だ', 'Keeps getting more and more — unidirectional continuous change', '一方だ indicates a trend that is continuously moving in one direction with no sign of stopping. Usually used for negative trends but can describe positive ones. Distinct from 一方で (on the other hand).', '[{"japanese":"物価が上がる一方です。","reading":"ぶっかがあがるいっぽうです。","english":"Prices just keep going up."},{"japanese":"状況が悪化する一方だ。","reading":"じょうきょうがあっかするいっぽうだ。","english":"The situation just keeps getting worse."},{"japanese":"仕事は増える一方で、休めません。","reading":"しごとはふえるいっぽうで、やすめません。","english":"Work just keeps increasing and I can''t rest."}]', 'expression', 0, 65);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜一方で (on the other hand / while)', 'V/Adj (plain) + 一方で / N の + 一方で', 'On the other hand / while — presents a contrast or two simultaneous aspects', '一方で presents a contrasting view, a parallel situation, or two things happening at the same time. It can mean ''while doing A, B'' or ''on the other hand''. More neutral than 反面 and widely used in spoken and written Japanese.', '[{"japanese":"仕事をする一方で、趣味も大切にしています。","reading":"しごとをするいっぽうで、しゅみもたいせつにしています。","english":"While working, I also cherish my hobbies."},{"japanese":"科学が進歩する一方で、新たな問題も出てきた。","reading":"かがくがしんぽするいっぽうで、あらたなもんだいもでてきた。","english":"While science advances, new problems have also emerged."},{"japanese":"賛成する人がいる一方で、反対意見もあります。","reading":"さんせいするひとがいるいっぽうで、はんたいいけんもあります。","english":"While some people agree, there are also opposing views."}]', 'conjunction', 0, 66);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ているところを (catching someone in the act of)', 'V-ている + ところを', 'Catching in the act of — marking the moment someone is caught doing something', 'ているところを expresses that someone is caught, seen, or disturbed in the middle of doing something. Often used in passive constructions: 見られた (was seen), つかまった (was caught). The act was in progress when discovered.', '[{"japanese":"サボっているところを上司に見られてしまいました。","reading":"サボっているところをじょうしにみられてしまいました。","english":"I was caught slacking by my boss."},{"japanese":"寝ているところを起こされました。","reading":"ねているところをおこされました。","english":"I was woken up while I was sleeping."},{"japanese":"食べているところを写真に撮られました。","reading":"たべているところをしゃしんにとられました。","english":"I was photographed in the act of eating."}]', 'expression', 0, 67);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜を抜きにして (setting aside / without)', 'N + を抜きにして / を抜きにしては', 'Setting aside / without — removing or leaving out a factor for the purpose of the statement', 'を抜きにして means ''setting X aside / without counting X''. を抜きにしては means ''without X it would be impossible (for the following to be true)''. Often used to acknowledge what is being left out.', '[{"japanese":"冗談を抜きにして、真剣に話しましょう。","reading":"じょうだんをぬきにして、しんけんにはなしましょう。","english":"Setting jokes aside, let''s talk seriously."},{"japanese":"皆さんの協力を抜きにしては、成功できませんでした。","reading":"みなさんのきょうりょくをぬきにしては、せいこうできませんでした。","english":"Without everyone''s cooperation, we could not have succeeded."},{"japanese":"この問題を抜きにして、進めることはできません。","reading":"このもんだいをぬきにして、すすめることはできません。","english":"We cannot proceed without addressing this issue."}]', 'expression', 0, 68);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ぶりに (for the first time in [period])', 'Time period + ぶりに', 'For the first time in [period] — returning to something after an interval', '〜ぶりに marks how long it has been since something last occurred. 3年ぶりに = for the first time in 3 years. Can only follow time expressions. Expresses the gap between the previous occurrence and the current one.', '[{"japanese":"3年ぶりに故郷に帰りました。","reading":"3ねんぶりにこきょうにかえりました。","english":"I returned home for the first time in 3 years."},{"japanese":"久しぶりに会えて嬉しいです。","reading":"ひさしぶりにあえてうれしいです。","english":"I''m happy to see you after such a long time."},{"japanese":"1週間ぶりにゆっくり眠れました。","reading":"1しゅうかんぶりにゆっくりねむれました。","english":"I was able to sleep properly for the first time in a week."}]', 'expression', 0, 69);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N2', '〜ないことには (unless / without doing)', 'V-ない + ことには', 'Unless / without doing — states a necessary condition without which something cannot happen', 'ないことには expresses a necessary prerequisite: unless X happens, Y is impossible. It is stronger and more formal than なければ. The main clause is usually negative or expresses impossibility.', '[{"japanese":"実際にやってみないことには、わかりません。","reading":"じっさいにやってみないことには、わかりません。","english":"Unless you actually try it, you won''t know."},{"japanese":"許可をもらわないことには、始められません。","reading":"きょかをもらわないことには、はじめられません。","english":"Unless we get permission, we cannot start."},{"japanese":"直接話さないことには、解決できません。","reading":"ちょくせつはなさないことには、かいけつできません。","english":"Unless we talk directly, we can''t resolve this."}]', 'conditional', 0, 70);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜いかんだ / いかんにかかわらず (depending on / regardless of)', 'N + のいかんだ / のいかんにかかわらず', 'Depending on the state of / regardless of — very formal bureaucratic expression', 'いかん is a formal/written word meaning ''what the situation is'' or ''how things are''. のいかんだ means ''it depends on how X turns out''. のいかんにかかわらず means ''regardless of the state of X''. Both are formal/bureaucratic.', '[{"japanese":"結果のいかんにかかわらず、全力を尽くします。","reading":"けっかのいかんにかかわらず、ぜんりょくをつくします。","english":"Regardless of the result, I will give my all."},{"japanese":"対応のいかんによっては、法的措置を取ります。","reading":"たいおうのいかんによっては、ほうてきそちをとります。","english":"Depending on the response, legal measures will be taken."},{"japanese":"理由のいかんを問わず、遅刻は禁止です。","reading":"りゆうのいかんをとわず、ちこくはきんしです。","english":"Regardless of the reason, being late is prohibited."}]', 'formal', 0, 1);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜まじ (must not — literary prohibition)', 'V (plain non-past) + まじ / まじき + N', 'Must not / should not — literary/archaic prohibition', 'まじ is a classical auxiliary expressing prohibition or strong negative intention. まじき is the attributive form. Found in literary texts, formal writing, and set expressions. The modern equivalent is べきではない.', '[{"japanese":"教師としてあるまじき行為だ。","reading":"きょうしとしてあるまじきこういだ。","english":"It is conduct unbefitting a teacher."},{"japanese":"人として許すまじき行為だ。","reading":"ひととしてゆるすまじきこういだ。","english":"It is conduct that must not be forgiven as a human being."},{"japanese":"その秘密は明かすまじ。","reading":"そのひみつはあかすまじ。","english":"That secret must not be revealed."}]', 'formal', 0, 2);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜べく (in order to — formal/literary purpose)', 'V (plain non-past) + べく', 'In order to / with the aim of — formal/literary purpose marker', 'べく is the literary/classical equivalent of ために for expressing purpose. It is followed by an action the subject takes in pursuit of the goal. More literary than ために; found in news, formal essays, and classical-influenced writing.', '[{"japanese":"夢を実現すべく、毎日努力しています。","reading":"ゆめをじつげんすべく、まいにちどりょくしています。","english":"In order to realise my dream, I work hard every day."},{"japanese":"問題を解決すべく、会議が開かれました。","reading":"もんだいをかいけつすべく、かいぎがひらかれました。","english":"A meeting was held in order to resolve the problem."},{"japanese":"合格すべく、必死で勉強しました。","reading":"ごうかくすべく、ひっしでべんきょうしました。","english":"I studied desperately in order to pass."}]', 'formal', 0, 3);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜んがため(に) (for the purpose of — literary)', 'V-ない stem + んがために / んがための + N', 'For the purpose of — archaic/literary purpose expression', 'んがため(に) is a classical grammar pattern expressing strong purpose. ん is the archaic negative auxiliary form serving as a volitional here. Very literary and not used in modern conversation; appears in formal essays, historical texts.', '[{"japanese":"勝たんがために、あらゆる努力をした。","reading":"かたんがために、あらゆるどりょくをした。","english":"For the purpose of winning, every effort was made."},{"japanese":"生き残らんがための戦いが続いた。","reading":"いきのこらんがためのたたかいがつづいた。","english":"The struggle for the purpose of survival continued."},{"japanese":"真実を知らんがため、彼は危険を冒した。","reading":"しんじつをしらんがため、かれはきけんをおかした。","english":"For the purpose of knowing the truth, he took risks."}]', 'formal', 0, 4);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜んばかりに (as if about to / so much that it seems)', 'V-ない stem + んばかりに', 'As if about to / seemingly on the verge of — extreme degree or appearance', 'んばかりに expresses that something is on the verge of happening or looks as if it is about to. It describes an extreme state or appearance. The ん is classical (related to む). Often describes emotional or physical extremity.', '[{"japanese":"泣かんばかりに、頼み込みました。","reading":"なかんばかりに、たのみこみました。","english":"He pleaded as if he were about to cry."},{"japanese":"爆発せんばかりの怒りを抑えた。","reading":"ばくはつせんばかりのいかりをおさえた。","english":"He suppressed anger that was on the verge of exploding."},{"japanese":"溢れんばかりの笑顔で迎えてくれました。","reading":"あふれんばかりのえがおでむかえてくれました。","english":"She greeted us with a smile so big it seemed to overflow."}]', 'formal', 0, 5);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜かと思いきや (contrary to expectation, ...)', 'S (plain) + かと思いきや', 'Just when you thought / contrary to expectation — surprising reversal', 'かと思いきや expresses a sudden reversal of expectation. The speaker thought X was the case, but then Y (the opposite or something surprising) happened. Always followed by an unexpected outcome. Conversational and slightly literary.', '[{"japanese":"試験は難しいかと思いきや、意外と簡単だった。","reading":"しけんはむずかしいかとおもいきや、いがいとかんたんだった。","english":"Just when I thought the exam would be hard, it was surprisingly easy."},{"japanese":"雨かと思いきや、急に晴れてきた。","reading":"あめかとおもいきや、きゅうにはれてきた。","english":"Just when I thought it would rain, it suddenly cleared up."},{"japanese":"怒っているかと思いきや、笑い出した。","reading":"おこっているかとおもいきや、わらいだした。","english":"Just when I thought he was angry, he burst out laughing."}]', 'expression', 0, 6);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ならでは (unique to / only possible with)', 'N + ならでは (の + N / できない)', 'Unique to / only possible with — something is special and exclusive to X', 'ならでは expresses that something is uniquely characteristic of X and could only be found there or done by X. ならではの + N is the attributive form. Carries a positive, admiring tone.', '[{"japanese":"京都ならではの風景が楽しめます。","reading":"きょうとならではのふうけいがたのしめます。","english":"You can enjoy scenery unique to Kyoto."},{"japanese":"プロならではの技術に驚きました。","reading":"プロならではのぎじゅつにおどろきました。","english":"I was amazed by the skill unique to a professional."},{"japanese":"日本ならでは、こんな細かいサービスはできない。","reading":"にほんならでは、こんなこまかいサービスはできない。","english":"Such detailed service is only possible in Japan."}]', 'expression', 0, 7);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ともなると / ともなれば (when it comes to that level)', 'N + ともなると / ともなれば', 'When it comes to / at the level of — marks an elevated status that entails certain expectations', 'ともなると/ともなれば expresses that when someone or something reaches a certain level or status, certain things naturally follow. It implies that at that level, the associated consequences, duties, or characteristics are expected.', '[{"japanese":"社長ともなると、責任が大きいですね。","reading":"しゃちょうともなると、せきにんがおおきいですね。","english":"When it comes to being a company president, the responsibility is great."},{"japanese":"プロともなれば、そのくらいできて当然だ。","reading":"プロともなれば、そのくらいできてとうぜんだ。","english":"When you''re a professional, being able to do that much is only natural."},{"japanese":"有名人ともなると、プライバシーがなくなる。","reading":"ゆうめいじんともなると、プライバシーがなくなる。","english":"When you become a celebrity, you lose your privacy."}]', 'expression', 0, 8);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ともなく / ともなしに (without particular intent)', 'V (plain) + ともなく / ともなしに', 'Without particularly intending to — doing something vaguely or absent-mindedly', 'ともなく/ともなしに expresses that an action is done without clear intent or purpose, often absent-mindedly. Common patterns: 誰ともなく (from no one in particular), 見るともなく見る (gaze without really looking). Literary.', '[{"japanese":"聞くともなく、隣の会話が耳に入った。","reading":"きくともなく、となりのかいわがみにはいった。","english":"Without particularly listening, the conversation next to me entered my ears."},{"japanese":"見るともなく窓の外を眺めていた。","reading":"みるともなくまどのそとをながめていた。","english":"I was gazing outside the window without particularly looking."},{"japanese":"誰ともなく拍手が起こりました。","reading":"だれともなくはくしゅがおこりました。","english":"Applause arose from no one in particular."}]', 'expression', 0, 9);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜なしに(は) (without / cannot do without)', 'V (plain non-past) + ことなしに / N + なしに(は)', 'Without — marks an indispensable condition; something cannot be done without X', 'なしに marks a condition without which something is impossible. なしには makes it conditional: ''without X, it is not possible''. More emphatic than ないで. Often used in formal or rhetorical contexts.', '[{"japanese":"準備なしには、成功はあり得ない。","reading":"じゅんびなしには、せいこうはありえない。","english":"Without preparation, success is impossible."},{"japanese":"彼の協力なしには、このプロジェクトは完成しなかった。","reading":"かれのきょうりょくなしには、このプロジェクトはかんせいしなかった。","english":"Without his cooperation, this project would not have been completed."},{"japanese":"苦労なしに得た成功は、長続きしないものだ。","reading":"くろうなしにえたせいこうは、ながつづきしないものだ。","english":"Success obtained without hardship does not last."}]', 'conjunction', 0, 10);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にして (at the stage of / being — formal emphasis)', 'N + にして', 'At the level/stage of / being that — marks an impressive stage or simultaneous quality', 'にして has several literary uses: (1) ''at the level/age of'' (emphasising a remarkable achievement at that stage); (2) ''being both X and Y'' (〜にして〜でもある); (3) ''and yet / even for''. All are formal.', '[{"japanese":"30歳にして、すでに世界的な芸術家だ。","reading":"30さいにして、すでにせかいてきなげいじゅつかだ。","english":"At the age of 30, he is already a world-renowned artist."},{"japanese":"彼は科学者にして哲学者でもある。","reading":"かれはかがくしゃにしてていがくしゃでもある。","english":"He is both a scientist and a philosopher."},{"japanese":"ベテランにしてなお、失敗することがある。","reading":"ベテランにしてなお、しっぱいすることがある。","english":"Even for a veteran, there are still times of failure."}]', 'formal', 0, 11);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜において / における (at / in — formal location/context)', 'N + において / における + N', 'At / in / in the context of — formal location or field of activity', 'において is the formal/written equivalent of で for marking location or field. における is the attributive form. Very common in academic writing, business documents, and formal speech. The casual equivalent is で.', '[{"japanese":"グローバル化が進む現代において、英語力は不可欠です。","reading":"グローバルかがすすむげんだいにおいて、えいごりょくはふかけつです。","english":"In the modern era of advancing globalisation, English ability is indispensable."},{"japanese":"教育における格差は大きな問題です。","reading":"きょういくにおけるかくさはおおきなもんだいです。","english":"Disparity in education is a major problem."},{"japanese":"スポーツの世界においても、メンタルは重要です。","reading":"スポーツのせかいにおいても、メンタルはじゅうようです。","english":"Even in the world of sports, mental strength is important."}]', 'formal', 0, 12);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に即して (in accordance with / strictly following)', 'N + に即して / に即した + N', 'In strict accordance with / closely following — acts or evaluates exactly according to a standard', 'に即して means to act in strict accordance with or closely following something (rules, reality, facts). に即した is the attributive form. Slightly different from に沿って (which implies going along a path/direction); に即して implies strict conformity.', '[{"japanese":"現実に即した解決策が必要です。","reading":"げんじつにそくしたかいけつさくがひつようです。","english":"A solution that closely follows reality is necessary."},{"japanese":"事実に即して報告してください。","reading":"じじつにそくしてほうこくしてください。","english":"Please report in strict accordance with the facts."},{"japanese":"法律に即した対応が求められます。","reading":"ほうりつにそくしたたいおうがもとめられます。","english":"A response in strict accordance with the law is required."}]', 'formal', 0, 13);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜をおいてほかにない (there is no one/nothing but)', 'N + をおいて(ほかに)ない', 'There is no one / nothing other than — emphatic assertion of uniqueness', 'をおいてほかにない asserts that there is nothing or no one else that can fill the role or match the quality. It is emphatic and positive. More literary and formal than 〜しかない.', '[{"japanese":"この役を演じられるのは彼をおいてほかにない。","reading":"このやくをえんじられるのはかれをおいてほかにない。","english":"There is no one other than him who can play this role."},{"japanese":"今の状況を打開できるのは、彼女をおいてほかにいない。","reading":"いまのじょうきょうをだかいできるのは、かのじょをおいてほかにいない。","english":"There is no one other than her who can break through the current situation."},{"japanese":"この計画を実現できるのは、我々をおいてほかにない。","reading":"このけいかくをじつげんできるのは、われわれをおいてほかにない。","english":"There is no one other than us who can realise this plan."}]', 'expression', 0, 14);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜をよそに (ignoring / indifferent to)', 'N + をよそに', 'Ignoring / indifferent to — proceeds despite or regardless of someone''s concern/situation', 'をよそに expresses that someone carries on with their own affairs while ignoring or being indifferent to the situation or feelings of others nearby. Often carries a critical nuance — the person is insensitively disregarding others.', '[{"japanese":"親の心配をよそに、子供は平気な顔をしていた。","reading":"おやのしんぱいをよそに、こどもはへいきなかおをしていた。","english":"Ignoring their parents'' worries, the child looked unconcerned."},{"japanese":"周囲の反対をよそに、彼は計画を進めた。","reading":"しゅういのはんたいをよそに、かれはけいかくをすすめた。","english":"Indifferent to the opposition around him, he pushed the plan forward."},{"japanese":"世間の批判をよそに、彼らは活動を続けた。","reading":"せけんのひはんをよそに、かれらはかつどうをつづけた。","english":"Ignoring society''s criticism, they continued their activities."}]', 'expression', 0, 15);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ずにはいられない (cannot help but — involuntary feeling)', 'V-ない stem + ずにはいられない', 'Cannot help but / can''t resist — involuntary feeling or action', 'ずにはいられない expresses an action that the speaker cannot help but do — it is an uncontrollable urge or feeling. More literary than ないではいられない. する becomes せずにはいられない.', '[{"japanese":"この映画を見ると、泣かずにはいられない。","reading":"このえいがをみると、なかずにはいられない。","english":"When I watch this movie, I can''t help but cry."},{"japanese":"そんな不条理を見ると、怒らずにはいられない。","reading":"そんなふじょうりをみると、おこらずにはいられない。","english":"Seeing such injustice, I can''t help but get angry."},{"japanese":"彼女の笑顔を見ると、微笑まずにはいられない。","reading":"かのじょのえがおをみると、ほほえまずにはいられない。","english":"When I see her smile, I can''t help but smile too."}]', 'expression', 0, 16);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜まい (probably not / will not — volitional negative)', 'V (plain non-past) + まい / するまい / くるまい', 'Probably not / definitely will not — negative conjecture or strong negative intention', 'まい is a classical auxiliary expressing negative conjecture (probably won''t) or strong negative volitional intent (I will not). Group 1 verbs: plain form + まい; Group 2: drop る + まい or plain + まい; する → するまい; くる → くるまい. Formal/literary.', '[{"japanese":"あの人はもう二度と来るまいと思います。","reading":"あのひとはもうにどとくるまいとおもいます。","english":"I think that person will probably not come again."},{"japanese":"二度とこんな失敗はすまいと決意した。","reading":"にどとこんなしっぱいはすまいとけついした。","english":"I resolved that I would never make such a mistake again."},{"japanese":"彼はそんなことをするまいと思っていたが、した。","reading":"かれはそんなことをするまいとおもっていたが、した。","english":"I thought he probably wouldn''t do such a thing, but he did."}]', 'auxiliary', 0, 17);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜や否や (as soon as — literary)', 'V (plain non-past) + や否や', 'The moment / as soon as — literary expression for immediate succession', 'や否や is a literary expression meaning ''the very moment X happened, Y happened immediately''. It emphasises the instantaneous nature of the succession. More dramatic and literary than とたんに or たとたん. The second action happens before the first is fully complete.', '[{"japanese":"チャイムが鳴るや否や、生徒たちは飛び出した。","reading":"チャイムがなるやいなや、せいとたちはとびだした。","english":"The very moment the bell rang, the students burst out."},{"japanese":"彼は名前を呼ばれるや否や、立ち上がった。","reading":"かれはなまえをよばれるやいなや、たちあがった。","english":"The moment his name was called, he stood up."},{"japanese":"目が覚めるや否や、彼女は走り出した。","reading":"めがさめるやいなや、かのじょははしりだした。","english":"The very moment she woke up, she started running."}]', 'conjunction', 0, 18);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜が早いか (as soon as — with urgency)', 'V (plain non-past) + が早いか', 'No sooner ... than / the instant — extremely rapid succession, often physical action', 'が早いか describes an action that happens with extreme immediacy — no sooner than X happened, Y already happened. More emphatic than や否や and typically describes rapid physical actions. Literary.', '[{"japanese":"ドアが開くが早いか、彼は飛び出した。","reading":"ドアがあくがはやいか、かれはとびだした。","english":"No sooner did the door open than he jumped out."},{"japanese":"授業が終わるが早いか、生徒たちは帰り始めた。","reading":"じゅぎょうがおわるがはやいか、せいとたちはかえりはじめた。","english":"No sooner did the class end than students began leaving."},{"japanese":"電話が鳴るが早いか、彼女は飛びついた。","reading":"でんわがなるがはやいか、かのじょはとびついた。","english":"No sooner did the phone ring than she grabbed it."}]', 'conjunction', 0, 19);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ものを (if only / could have — regret)', 'V-た / Adj (plain) + ものを', 'If only / could have — regret that something should have been different', 'ものを expresses regret or complaint that things didn''t go as they should have. The ものを clause states what should have been done, but wasn''t. Carries strong emotional weight — frustration or lament. More formal and literary than のに.', '[{"japanese":"もっと早く言ってくれればよかったものを。","reading":"もっとはやくいってくれればよかったものを。","english":"If only you had told me sooner."},{"japanese":"素直に謝ればよかったものを、意地を張ってしまった。","reading":"すなおにあやまればよかったものを、いじをはってしまった。","english":"If only he had sincerely apologised, but he was stubborn."},{"japanese":"準備さえしていれば成功したものを。","reading":"じゅんびさえしていればせいこうしたものを。","english":"If only we had prepared, we would have succeeded."}]', 'expression', 0, 20);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜もさることながら (not to mention / and of course)', 'N + もさることながら', 'Not to mention / X is a given, but also Y — acknowledges X then adds Y as equally important', 'もさることながら acknowledges that X is certainly true or important, but goes on to say Y is also (or even more) important. The first item is taken as a given; the second is the additional point. Formal.', '[{"japanese":"デザインもさることながら、使い心地も重要です。","reading":"デザインもさることながら、つかいごこちもじゅうようです。","english":"Not to mention the design, usability is also important."},{"japanese":"外見もさることながら、内面が大切だと思います。","reading":"がいけんもさることながら、ないめんがたいせつだとおもいます。","english":"Not to mention appearance, inner character is important."},{"japanese":"費用もさることながら、時間の問題もあります。","reading":"ひようもさることながら、じかんのもんだいもあります。","english":"Not to mention the cost, there is also the issue of time."}]', 'expression', 0, 21);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜たる(もの) (for one who is — formal expectation)', 'N + たる + N / たるもの', 'For one who is / as a [status] — formal assertion of the standards expected of a role', 'たる is the classical attributive copula. N + たるもの = ''for something/someone that is N, the following is expected''. It asserts that a certain standard is required by virtue of one''s role or status. Formal and literary.', '[{"japanese":"教師たる者、常に学び続けるべきだ。","reading":"きょうしたるもの、つねにまなびつづけるべきだ。","english":"For one who is a teacher, one should always keep learning."},{"japanese":"リーダーたる者は、責任から逃げてはならない。","reading":"リーダーたるものは、せきにんからにげてはならない。","english":"For one who is a leader, one must not run from responsibility."},{"japanese":"社会人たる者、礼儀を知るべきだ。","reading":"しゃかいじんたるもの、れいぎをしるべきだ。","english":"For one who is a member of society, one should know proper manners."}]', 'formal', 0, 22);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜たりとも (not even one / even a single)', '数量 + たりとも + negative', 'Not even a single / not one — extreme emphasis on zero tolerance', 'たりとも follows a small quantity (一人, 一秒, 一円) to emphasise absolute zero: ''not even one''. Always followed by a negative. Literary and emphatic. Similar to さえ but more absolute.', '[{"japanese":"一秒たりとも無駄にできない。","reading":"いちびょうたりともむだにできない。","english":"I cannot waste even a single second."},{"japanese":"一人たりとも取り残してはならない。","reading":"ひとりたりともとりのこしてはならない。","english":"Not even a single person must be left behind."},{"japanese":"一円たりとも使わせない。","reading":"いちえんたりともつかわせない。","english":"I won''t let them spend even a single yen."}]', 'expression', 0, 23);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜であれ〜であれ (whether ... or — formal)', 'N/V + であれ + N/V + であれ', 'Whether ... or — formal expression covering both alternatives', 'であれ〜であれ is the formal equivalent of にしても〜にしても or でも〜でも. It states that the result holds regardless of which alternative applies. Found in formal writing, speeches, and literary contexts.', '[{"japanese":"賛成であれ反対であれ、意見を述べてください。","reading":"さんせいであれはんたいであれ、いけんをのべてください。","english":"Whether you agree or disagree, please state your opinion."},{"japanese":"成功であれ失敗であれ、全力を尽くすことが大切だ。","reading":"せいこうであれしっぱいであれ、ぜんりょくをつくすことがたいせつだ。","english":"Whether you succeed or fail, giving your all is important."},{"japanese":"どんな状況であれ、諦めてはいけない。","reading":"どんなじょうきょうであれ、あきらめてはいけない。","english":"Whatever the situation, you must not give up."}]', 'formal', 0, 24);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とあって (because / since — special circumstance)', 'S (plain) + とあって', 'Because / given that — marks a special circumstance that explains an unusual result', 'とあって presents a special or notable circumstance that justifies or explains the following result. The circumstance is noteworthy — it explains why something unusual is happening. More formal and specific than から or ので.', '[{"japanese":"連休とあって、観光地は大変混んでいます。","reading":"れんきゅうとあって、かんこうちはたいへんこんでいます。","english":"Given that it''s a long holiday, the tourist spots are very crowded."},{"japanese":"有名アーティストの公演とあって、チケットはすぐに売り切れた。","reading":"ゆうめいアーティストのこうえんとあって、チケットはすぐにうりきれた。","english":"Because it was a performance by a famous artist, tickets sold out immediately."},{"japanese":"初めての海外とあって、彼女は緊張していた。","reading":"はじめてのかいがいとあって、かのじょはきんちょうしていた。","english":"Given that it was her first time abroad, she was nervous."}]', 'conjunction', 0, 25);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とあれば (if it''s for / when it comes to — strong motivation)', 'S (plain) + とあれば / N + とあれば', 'If it''s for / when it comes to — strong motivation driving an action', 'とあれば expresses that if the condition stated is the case, the speaker is strongly motivated or obligated to act. It implies willingness to go to great lengths for that specific cause.', '[{"japanese":"あなたのためとあれば、どんなことでもします。","reading":"あなたのためとあれば、どんなことでもします。","english":"If it''s for you, I''ll do anything."},{"japanese":"命令とあれば、従わなければならない。","reading":"めいれいとあれば、したがわなければならない。","english":"If it''s an order, I must comply."},{"japanese":"家族のためとあれば、私は戦うことができます。","reading":"かぞくのためとあれば、わたしはたたかうことができます。","english":"If it''s for my family, I am able to fight."}]', 'conditional', 0, 26);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とばかりに (as if to say / with the attitude of)', 'S (plain) + とばかりに', 'As if to say / with an attitude of — non-verbal behaviour that implies something', 'とばかりに describes an action or attitude that strongly implies a feeling or message, even though it isn''t stated in words. Often used to describe facial expressions, gestures, or behaviour that communicates something clearly.', '[{"japanese":"「どうぞ」とばかりに、彼はドアを大きく開けた。","reading":"「どうぞ」とばかりに、かれはドアをおおきくあけた。","english":"As if to say ''go ahead'', he opened the door wide."},{"japanese":"待ってましたとばかりに、彼は立ち上がった。","reading":"まってましたとばかりに、かれはたちあがった。","english":"As if to say ''I''ve been waiting for this'', he stood up."},{"japanese":"違うとばかりに、彼女は首を横に振った。","reading":"ちがうとばかりに、かのじょはくびをよこにふった。","english":"As if to say ''that''s wrong'', she shook her head."}]', 'expression', 0, 27);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とはいえ (even so / that said — concession)', 'S (plain) / N + とはいえ', 'Even so / that said / although — acknowledges a fact then qualifies it', 'とはいえ acknowledges the preceding statement as true, then presents a qualification or contrasting reality. Similar to ''that said'' or ''even so'' in English. More formal than とはいっても or けど.', '[{"japanese":"冬とはいえ、今日は暖かいですね。","reading":"ふゆとはいえ、きょうはあたたかいですね。","english":"Even so, it''s warm today for winter."},{"japanese":"失敗したとはいえ、挑戦したことは評価すべきだ。","reading":"しっぱいしたとはいえ、ちょうせんしたことはひょうかすべきだ。","english":"Even though he failed, the fact that he tried should be acknowledged."},{"japanese":"小さいとはいえ、機能は十分にあります。","reading":"ちいさいとはいえ、きのうはじゅうぶんにあります。","english":"Even so, despite being small, it has sufficient functionality."}]', 'conjunction', 0, 28);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ではあるまいか (could it be that — formal conjecture)', 'S (plain) + ではあるまいか', 'Could it be that / perhaps — formal rhetorical question expressing conjecture', 'ではあるまいか is a formal rhetorical expression inviting the listener to consider a conjecture. It expresses the speaker''s tentative belief as a question. More literary and formal than ではないかと思う. まいか adds uncertainty.', '[{"japanese":"これが真実ではあるまいか。","reading":"これがしんじつではあるまいか。","english":"Could this perhaps be the truth?"},{"japanese":"彼こそが最適な人物ではあるまいか。","reading":"かれこそがさいてきなじんぶつではあるまいか。","english":"Could it be that he is the most suitable person?"},{"japanese":"その考え方は時代遅れではあるまいか。","reading":"そのかんがえかたはじだいおくれではあるまいか。","english":"Could that way of thinking perhaps be outdated?"}]', 'formal', 0, 29);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜のみならず (not only — formal)', 'V/Adj (plain) + のみならず / N + のみならず', 'Not only ... but also — formal equivalent of だけでなく', 'のみならず is the formal/written equivalent of だけでなく (not only). Found in academic writing, formal speech, and literary contexts. More emphatic and elevated in register than だけでなく.', '[{"japanese":"その影響は国内のみならず、海外にも及んでいます。","reading":"そのえいきょうはこくないのみならず、かいがいにもおよんでいます。","english":"The impact extends not only domestically but also internationally."},{"japanese":"彼は成績が優秀なのみならず、人柄も素晴らしい。","reading":"かれはせいせきがゆうしゅうなのみならず、ひとがらもすばらしい。","english":"Not only is he academically excellent, but his character is also wonderful."},{"japanese":"環境問題は政府のみならず、個人の問題でもある。","reading":"かんきょうもんだいはせいふのみならず、こじんのもんだいでもある。","english":"Environmental issues are not only a government matter but also a personal one."}]', 'formal', 0, 30);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ばこそ (precisely because — emphasis)', 'V-ば / Adj-ければ + こそ', 'Precisely because — highlights the reason as the essential and exclusive cause', 'ばこそ emphasises that X is the precise and exclusive reason for Y. It stresses the indispensability of the reason. More emphatic than から alone. Often expresses that the speaker wants to make the reason explicit.', '[{"japanese":"あなたが好きなればこそ、こんなことを言うのです。","reading":"あなたがすきなればこそ、こんなことをいうのです。","english":"Precisely because I care about you, I say such things."},{"japanese":"難しければこそ、挑戦する価値がある。","reading":"むずかしければこそ、ちょうせんするかちがある。","english":"Precisely because it is difficult, it is worth challenging."},{"japanese":"信頼しているからこそ、厳しく指導します。","reading":"しんらいしているからこそ、きびしくしどうします。","english":"Precisely because I trust you, I guide you strictly."}]', 'conjunction', 0, 31);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜こそあれ (although there is / though)', 'V-stem / N + こそあれ', 'Although there is / though — acknowledges one aspect while asserting the opposite', 'こそあれ is a literary concessive acknowledging one aspect (often a minor or expected quality) while emphasising a contrasting larger truth. It is formal and rarely used in conversation.', '[{"japanese":"多少の不安こそあれ、自信はあります。","reading":"たしょうのふあんこそあれ、じしんはあります。","english":"Although there is some anxiety, I have confidence."},{"japanese":"困難こそあれ、必ず道はある。","reading":"こんなんこそあれ、かならずみちはある。","english":"Though there are difficulties, there is always a way."},{"japanese":"失敗こそあれ、成長しているのは確かだ。","reading":"しっぱいこそあれ、せいちょうしているのはたしかだ。","english":"Although there are failures, it is certain that growth is happening."}]', 'formal', 0, 32);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に至って(は) (now that it has come to / having reached the point)', 'V (plain non-past) + に至って / に至っては / に至るまで', 'Now that it has come to / having reached — marks an extreme or final point', 'に至って expresses that a situation has reached a critical or noteworthy point. に至っては emphasises an extreme or unexpected case within a range. に至るまで = ''up to and including / ranging all the way to''.', '[{"japanese":"事態がここに至っては、対策を講じるしかない。","reading":"じたいがここにいたっては、たいさくをこうじるしかない。","english":"Now that the situation has come to this, there is nothing to do but take measures."},{"japanese":"子供に至っては、大人より詳しいほどだ。","reading":"こどもにいたっては、おとなよりくわしいほどだ。","english":"Even children know more about it than adults."},{"japanese":"細部に至るまで、丁寧に仕上げました。","reading":"さいぶにいたるまで、ていねいにしあげました。","english":"I finished it carefully, right down to the finest details."}]', 'formal', 0, 33);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にとどまらず (not limited to / beyond)', 'N / V (plain) + にとどまらず', 'Not limited to / extending beyond — marks that something goes further than expected', 'にとどまらず expresses that the scope or effect is not confined to X but extends beyond it. Formal equivalent of だけでなく for expressing wider scope or greater extent than stated.', '[{"japanese":"その問題は一個人にとどまらず、社会全体に関わる。","reading":"そのもんだいはいちこじんにとどまらず、しゃかいぜんたいにかかわる。","english":"That problem is not limited to one individual but involves society as a whole."},{"japanese":"影響は国内にとどまらず、世界に広がっています。","reading":"えいきょうはこくないにとどまらず、せかいにひろがっています。","english":"The impact is not limited to domestic but is spreading worldwide."},{"japanese":"彼の才能はスポーツにとどまらず、芸術にも及ぶ。","reading":"かれのさいのうはスポーツにとどまらず、げいじゅつにもおよぶ。","english":"His talent is not limited to sports but extends to the arts as well."}]', 'formal', 0, 34);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にもまして (more than / above all)', 'N + にもまして / 何にもまして', 'More than / above all — marks something as exceeding even the reference point', 'にもまして means ''more than / even more than X''. 何にもまして = ''more than anything else / above all''. It emphasises that the following is at an even higher degree than the comparison point. Formal.', '[{"japanese":"以前にもまして、努力が必要な時代です。","reading":"いぜんにもまして、どりょくがひつようなじだいです。","english":"More than ever before, it is an era that requires effort."},{"japanese":"何にもまして、健康が一番大切です。","reading":"なににもまして、けんこうがいちばんたいせつです。","english":"Above all else, health is the most important."},{"japanese":"昨年にもまして、今年は忙しいです。","reading":"さくねんにもまして、ことしはいそがしいです。","english":"I am even busier this year than last year."}]', 'expression', 0, 35);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜こそすれ (far from / if anything — opposite emphasis)', 'V-stem + こそすれ + negative conclusion', 'If anything / far from — asserts the opposite is more true; the stated action is more likely than its contrary', 'こそすれ asserts that if anything, the opposite is happening rather than the negative. It emphasises that X (often a more extreme version) is what is actually occurring. Always followed by a negative or contrary statement. Literary.', '[{"japanese":"状況は改善こそすれ、悪化はしていない。","reading":"じょうきょうはかいぜんこそすれ、あっかはしていない。","english":"If anything, the situation is improving, not worsening."},{"japanese":"感謝こそすれ、恨む気持ちはありません。","reading":"かんしゃこそすれ、うらむきもちはありません。","english":"If anything, I feel gratitude, not resentment."},{"japanese":"増えこそすれ、減ることはないだろう。","reading":"ふえこそすれ、へることはないだろう。","english":"If anything, it will increase; it will not decrease."}]', 'formal', 0, 36);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にせよ〜にせよ (whether ... or — formal)', 'N/V + にせよ + N/V + にせよ', 'Whether ... or — formal expression covering both alternatives', 'にせよ〜にせよ is a slightly less formal alternative to であれ〜であれ for expressing that the result holds regardless of which of two options applies. Also used alone as a concessive: にせよ (even if / even though).', '[{"japanese":"賛成にせよ反対にせよ、行動が必要です。","reading":"さんせいにせよはんたいにせよ、こうどうがひつようです。","english":"Whether you agree or disagree, action is necessary."},{"japanese":"成功にせよ失敗にせよ、経験になります。","reading":"せいこうにせよしっぱいにせよ、けいけんになります。","english":"Whether success or failure, it becomes an experience."},{"japanese":"どんな結果になるにせよ、後悔しない選択をしたい。","reading":"どんなけっかになるにせよ、こうかいしないせんたくをしたい。","english":"Whatever the result, I want to make a choice I won''t regret."}]', 'formal', 0, 37);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜というものではない (it''s not necessarily / not that simple)', 'V/Adj (plain) + というものではない', 'It''s not simply the case that / not necessarily — rejects an oversimplified view', 'というものではない pushes back against a simplistic or naive assumption. It says that just because X appears true or simple, it doesn''t mean the conclusion automatically follows. More emphatic than ではない.', '[{"japanese":"お金があれば幸せというものではない。","reading":"おかねがあればしあわせというものではない。","english":"Having money doesn''t simply mean you''re happy."},{"japanese":"努力すれば必ず報われるというものではありません。","reading":"どりょくすればかならずむくわれるというものではありません。","english":"It''s not necessarily the case that effort will always be rewarded."},{"japanese":"謝れば全て解決するというものではない。","reading":"あやまればすべてかいけつするというものではない。","english":"It''s not as simple as saying that apologising will resolve everything."}]', 'expression', 0, 38);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜いざしらず / はいざしらず (I don''t know about X, but)', 'N + はいざしらず / はいざ知らず', 'I don''t know about X, but / setting X aside — focuses attention away from X onto Y', 'はいざしらず (or はいざ知らず) dismisses or sets aside one element (X) to focus on another (Y). It implies: ''I can''t speak to X, but Y is certainly the case''. Formal and literary. Often used to contrast a doubtful case with a certain one.', '[{"japanese":"昔はいざ知らず、今はそんなことは通用しない。","reading":"むかしはいざしらず、いまはそんなことはつうようしない。","english":"I don''t know about the past, but such things don''t work today."},{"japanese":"専門家はいざしらず、私には難しすぎます。","reading":"せんもんかはいざしらず、わたしにはむずかしすぎます。","english":"Setting aside experts, it is too difficult for me."},{"japanese":"他の人はいざ知らず、私は賛成できません。","reading":"ほかのひとはいざしらず、わたしはさんせいできません。","english":"I don''t know about others, but I cannot agree."}]', 'formal', 0, 39);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に即した (strictly in accordance with — attributive)', 'N + に即した + N', 'Strictly in accordance with — attributive form of に即して', 'に即した is the attributive (noun-modifying) form of に即して. Used when modifying a noun: 現実に即した計画 = a plan that closely follows reality. More precise than に沿った (which implies following a path).', '[{"japanese":"現場に即した研修が必要です。","reading":"げんばにそくしたけんしゅうがひつようです。","english":"Training that is in strict accordance with on-the-job reality is needed."},{"japanese":"時代に即した教育改革を進めます。","reading":"じだいにそくしたきょういくかいかくをすすめます。","english":"We will advance educational reform in strict accordance with the times."},{"japanese":"実態に即した政策が求められています。","reading":"じったいにそくしたせいさくがもとめられています。","english":"Policies that strictly follow the actual situation are being called for."}]', 'formal', 0, 40);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜をして (using / by means of — classical instrumental)', 'N + をして + V', 'Using / having [someone/something] do — classical causative or instrumental', 'をして is a classical/literary construction with two uses: (1) instrumental — by means of / using (〜の口をして言わしめれば); (2) causative — have/make [someone] do (〜をして〜せしめる). Found in classical literature and formal historical writing.', '[{"japanese":"彼をして語らしめれば、真実が分かるだろう。","reading":"かれをしてかたらしめれば、しんじつがわかるだろう。","english":"If we have him speak, the truth will become clear."},{"japanese":"神をして嘆かせるほどの悲劇だった。","reading":"かみをしてなげかせるほどのひげきだった。","english":"It was a tragedy so great that even the gods would lament."},{"japanese":"力をして平和を維持することはできない。","reading":"ちからをしてへいわをいじすることはできない。","english":"Peace cannot be maintained by force."}]', 'formal', 0, 41);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ずじまい (ended up not doing)', 'V-ない stem + ずじまい(だった)', 'Ended up not doing — an intended action that was never carried out', 'ずじまい expresses that something the speaker intended to do was never actually done. It carries a nuance of regret or resignation. The full form is ずじまいだった (ended up not doing) or ずじまいになった.', '[{"japanese":"結局、彼に会えずじまいでした。","reading":"けっきょく、かれにあえずじまいでした。","english":"In the end, I never got to meet him."},{"japanese":"買おうと思っていたが、買わずじまいだった。","reading":"かおうとおもっていたが、かわずじまいだった。","english":"I intended to buy it, but ended up not buying it."},{"japanese":"言いたいことがあったが、言えずじまいで終わった。","reading":"いいたいことがあったが、いえずじまいでおわった。","english":"I had something I wanted to say, but ended up not saying it."}]', 'expression', 0, 42);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に足る (worthy of / sufficient for)', 'V (plain non-past) + に足る / に値する', 'Worthy of / sufficient for — something merits the action or consideration', 'に足る expresses that something meets the standard required for the action. に値する (to be worth) is closely related. Both are formal. 信頼するに足る = worthy of trust; 検討するに値する = worth considering.', '[{"japanese":"彼女は信頼するに足る人物だ。","reading":"かのじょはしんらいするにたるじんぶつだ。","english":"She is a person worthy of trust."},{"japanese":"この作品は高く評価するに足ります。","reading":"このさくひんはたかくひょうかするにたります。","english":"This work is worthy of high evaluation."},{"japanese":"その提案は検討するに値します。","reading":"そのていあんはけんとうするにあたいします。","english":"That proposal is worth considering."}]', 'formal', 0, 43);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜かたがた (while doing / as well as — formal dual purpose)', 'N + かたがた / V-stem + かたがた', 'While doing / as well as — doing one thing while also taking the opportunity to do another (formal)', 'かたがた expresses doing something while also taking the opportunity to do something else. More formal than ついでに and used in set expressions. お礼かたがた = to express thanks while also... Often used in business or formal correspondence.', '[{"japanese":"お礼かたがた、ご挨拶に伺いました。","reading":"おれいかたがた、ごあいさつにうかがいました。","english":"I visited both to express my thanks and to pay my respects."},{"japanese":"散歩かたがた、用事を済ませてきました。","reading":"さんぽかたがた、ようじをすませてきました。","english":"I took a walk and also took care of some errands."},{"japanese":"ご報告かたがた、ご相談させていただきます。","reading":"ごほうこくかたがた、ごそうだんさせていただきます。","english":"I would like to both report to you and also consult with you."}]', 'formal', 1, 44);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜からして (even from / judging even from)', 'N + からして', 'Even from / judging from — marks a striking starting point that implies more beyond it', 'からして marks the most basic or obvious example, implying that even this minimum case supports the conclusion. ''Even from X alone, one can tell Y''. Often carries a mildly critical or emphatic tone.', '[{"japanese":"声からして、彼は怒っているのが分かった。","reading":"こえからして、かれはおこっているのがわかった。","english":"Even from his voice alone, I could tell he was angry."},{"japanese":"タイトルからして、面白そうな本ですね。","reading":"タイトルからして、おもしろそうなほんですね。","english":"Even just from the title, it seems like an interesting book."},{"japanese":"態度からして、やる気がないのが見え見えだ。","reading":"たいどからして、やるきがないのがみえみえだ。","english":"Even from his attitude alone, it''s obvious he has no motivation."}]', 'expression', 0, 45);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜といったところだ (it''s about / at most)', 'N / V (plain) + といったところだ', 'It''s about / at most / something like — gives an approximate or limiting estimate', 'といったところだ gives an approximate or maximum estimate, often downplaying expectations. ''It''s about X at most'' or ''something like X''. Similar to 〜くらいのものだ but more colloquial and common in conversation.', '[{"japanese":"この仕事で稼げるのは月10万円といったところです。","reading":"このしごとでかせげるのはつき10まんえんといったところです。","english":"At most you can earn about 100,000 yen a month from this work."},{"japanese":"メンバーは10人といったところでしょう。","reading":"メンバーは10にんといったところでしょう。","english":"There are about 10 members, give or take."},{"japanese":"今の技術では、その程度といったところが限界だ。","reading":"いまのぎじゅつでは、そのていどといったところがげんかいだ。","english":"With current technology, that level is about the limit."}]', 'expression', 0, 46);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜かいもなく (despite efforts / despite hopes — futility)', 'N の + かいもなく', 'Despite efforts / despite hopes — the effort or intention was in vain', 'かいもなく expresses that an effort, wish, or care was to no avail. The noun before it is usually the thing that should have helped (努力の甲斐もなく, 祈りの甲斐もなく). Formal and literary; expresses futility with solemnity.', '[{"japanese":"医者の努力のかいもなく、患者は亡くなりました。","reading":"いしゃのどりょくのかいもなく、かんじゃはなくなりました。","english":"Despite the doctor''s efforts, the patient passed away."},{"japanese":"必死の看護のかいもなく、彼は回復しなかった。","reading":"ひっしのかんごのかいもなく、かれはかいふくしなかった。","english":"Despite desperate nursing care, he did not recover."},{"japanese":"祈りのかいもなく、試合に負けてしまった。","reading":"いのりのかいもなく、しあいにまけてしまった。","english":"Despite our prayers, we lost the match."}]', 'expression', 0, 47);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜手前 (in front of / given that — obligation from position)', 'N の + 手前 / V-た + 手前', 'In front of / given that — creates obligation due to one''s stated position or actions', '手前 expresses that the speaker is obligated to follow through because of what they said, did, or who they are in front of. The obligation is socially or situationally imposed by the precedent set. Casual: 〜てしまった手前.', '[{"japanese":"みんなの前で宣言した手前、やり遂げなければならない。","reading":"みんなのまえでせんげんしたてまえ、やりとげなければならない。","english":"Having declared it in front of everyone, I have to follow through."},{"japanese":"上司の手前、文句は言えない。","reading":"じょうしのてまえ、もんくはいえない。","english":"In front of my boss, I can''t complain."},{"japanese":"そんな大口を叩いた手前、失敗するわけにはいかない。","reading":"そんなおおぐちをたたいたてまえ、しっぱいするわけにはいかない。","english":"Having boasted so much, I cannot afford to fail."}]', 'expression', 0, 48);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ともあろう (for someone as important as)', 'N + ともあろう + N (person) + が / ともあろう者が', 'For someone of your/their calibre — expresses surprise or reproach at behaviour unbecoming of one''s status', 'ともあろう expresses that the behaviour described is surprising or inappropriate given the person''s status or reputation. It carries reproach or astonishment. 〜ともあろう人が〜するとは = ''for someone of X''s calibre to do Y is...''', '[{"japanese":"大学教授ともあろう人が、そんなことを言うとは。","reading":"だいがくきょうじゅともあろうひとが、そんなことをいうとは。","english":"For someone of the calibre of a university professor to say such a thing..."},{"japanese":"あなたともあろう人が、なぜそんな失敗をしたのですか。","reading":"あなたともあろうひとが、なぜそんなしっぱいをしたのですか。","english":"Why did someone of your calibre make such a mistake?"},{"japanese":"リーダーともあろうものが、逃げ出すとは情けない。","reading":"リーダーともあろうものが、にげだすとはなさけない。","english":"How pathetic for someone who is supposed to be a leader to run away."}]', 'expression', 0, 49);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜をもってすれば (if with the power/means of)', 'N + をもってすれば', 'If with the power/means of — asserts that X is sufficient to achieve the result', 'をもってすれば is the conditional form of をもって (by means of). It expresses that if a certain power, ability, or means is applied, the result can be achieved. Formal and emphatic.', '[{"japanese":"現代の技術をもってすれば、それは実現できる。","reading":"げんだいのぎじゅつをもってすれば、それはじつげんできる。","english":"With modern technology, that can be realised."},{"japanese":"彼の能力をもってすれば、この問題は解決できるはずだ。","reading":"かれののうりょくをもってすれば、このもんだいはかいけつできるはずだ。","english":"With his ability, this problem should be solvable."},{"japanese":"チーム全員の力をもってすれば、不可能はない。","reading":"チームぜんいんのちからをもってすれば、ふかのうはない。","english":"With the power of the entire team, nothing is impossible."}]', 'formal', 0, 50);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜極まりない / 極まる (extremely / the height of)', 'Adj-na stem + 極まりない / 極まる', 'Extremely / the height of — formal, strong negative emphasis on an extreme degree', '極まりない (also 極まる) expresses an extreme degree, usually negative. 非常識極まりない = the height of rudeness/absurdity. Formal and often used in written complaints or formal criticism. ない reinforces the sense of beyond all limits.', '[{"japanese":"その態度は失礼極まりない。","reading":"そのたいどはしつれいきわまりない。","english":"That attitude is the height of rudeness."},{"japanese":"危険極まりない行為は絶対に禁止です。","reading":"きけんきわまりないこういはぜったいにきんしです。","english":"Acts that are in the extreme of danger are absolutely prohibited."},{"japanese":"そのような不誠実極まる対応には呆れました。","reading":"そのようなふせいじつきわまるたいおうにはあきれました。","english":"I was appalled by such an extremely insincere response."}]', 'formal', 0, 51);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ならいざしらず (if X, that''s one thing, but)', 'N + ならいざ知らず / ならいざしらず', 'If it were X, that might be understandable, but — dismisses X as the case and focuses on Y', 'ならいざしらず presents X as something that would be understandable or acceptable, then contrasts it with the actual situation (Y) which is not. Used to make a strong contrast between an acceptable case and the unacceptable reality.', '[{"japanese":"子供ならいざ知らず、大人がそんな言い訳はおかしい。","reading":"こどもならいざしらず、おとながそんないいわけはおかしい。","english":"That excuse might be understandable from a child, but it''s strange coming from an adult."},{"japanese":"昔ならいざ知らず、今はそんな方法は通用しません。","reading":"むかしならいざしらず、いまはそんなほうほうはつうようしません。","english":"That method might have worked in the past, but not today."},{"japanese":"初心者ならいざ知らず、プロがこんなミスをするとは。","reading":"しょしんしゃならいざしらず、プロがこんなミスをするとは。","english":"A mistake like this might be expected from a beginner, but from a professional..."}]', 'expression', 0, 52);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ものがある (there is an indescribable quality of)', 'V/Adj (plain) + ものがある', 'There is something about it / a certain quality exists — hard-to-articulate impression', 'ものがある expresses that there is a notable, hard-to-put-into-words quality about something. The speaker perceives something significant. Formal and literary, used in evaluation or deep observation.', '[{"japanese":"彼の演技には何か惹きつけるものがある。","reading":"かれのえんぎにはなにかひきつけるものがある。","english":"There is something captivating about his performance."},{"japanese":"この風景には心を打つものがある。","reading":"このふうけいにはこころをうつものがある。","english":"There is something moving about this scenery."},{"japanese":"彼女の言葉には人を動かすものがある。","reading":"かのじょのことばにはひとをうごかすものがある。","english":"There is something in her words that moves people."}]', 'expression', 0, 53);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に至るまで (up to and including / ranging all the way to)', 'N から N + に至るまで / N + に至るまで', 'All the way up to / ranging to — marks the extreme end of a range', 'に至るまで marks the furthest extent of a range, often after から: ''from X all the way to Y''. Used to show comprehensiveness or extremity. The item after に至るまで is the most extreme or unexpected end of the range.', '[{"japanese":"基礎から応用に至るまで、丁寧に教えます。","reading":"きそからおうようにいたるまで、ていねいにおしえます。","english":"I will teach carefully from the basics all the way to applications."},{"japanese":"日常の小さなことから人生の大きな決断に至るまで、相談してください。","reading":"にちじょうのちいさなことからじんせいのおおきなけつだんにいたるまで、そうだんしてください。","english":"Please consult me on everything from small daily matters all the way to major life decisions."},{"japanese":"あらゆる細部に至るまで確認しました。","reading":"あらゆるさいぶにいたるまでかくにんしました。","english":"I confirmed everything right down to every detail."}]', 'expression', 0, 54);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜のみか (not only ... but even)', 'N / V (plain) + のみか', 'Not only ... but even — formal; the second point is even more surprising than the first', 'のみか is the formal/literary equivalent of だけでなく, with an added sense that the second element is particularly surprising or extreme. The second element often exceeds expectations more than the first.', '[{"japanese":"謝らないのみか、相手を責め始めた。","reading":"あやまらないのみか、あいてをせめはじめた。","english":"Not only did he not apologise, but he even started blaming the other person."},{"japanese":"彼女は日本語のみか、中国語と英語も話せる。","reading":"かのじょはにほんごのみか、ちゅうごくごとえいごもはなせる。","english":"Not only Japanese, but she can even speak Chinese and English."},{"japanese":"失敗したのみか、会社に損害まで与えてしまった。","reading":"しっぱいしたのみか、かいしゃにそんがいまであたえてしまった。","english":"Not only did I fail, but I even caused damage to the company."}]', 'formal', 0, 55);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とみえて / とみえる (it appears that — inference)', 'S (plain) + とみえて / とみえる', 'It appears / it seems — inference based on observable evidence', 'とみえて and とみえる express an inference based on what the speaker observes. The speaker draws a conclusion from what they can see. Similar to ようで but carries a slightly stronger sense of deduction from visual evidence.', '[{"japanese":"疲れているとみえて、すぐ眠ってしまいました。","reading":"つかれているとみえて、すぐねむってしまいました。","english":"It appeared that he was tired, as he fell asleep immediately."},{"japanese":"気に入ったとみえて、何度も読み返しています。","reading":"きにいったとみえて、なんどもよみかえしています。","english":"It appears she liked it, as she keeps re-reading it."},{"japanese":"嬉しかったとみえて、顔が輝いていました。","reading":"うれしかったとみえて、かおがかがやいていました。","english":"It appeared she was happy, as her face was glowing."}]', 'auxiliary', 0, 56);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜そばから (as fast as one does / right after)', 'V (plain non-past / た) + そばから', 'As fast as / right after doing — what was just done is immediately undone or followed', 'そばから expresses that something happens immediately after (and often undoes or contradicts) the preceding action. Carries a slightly frustrated or exasperated tone — ''as soon as I do X, Y already happens''.', '[{"japanese":"片付けるそばから、子供が散らかす。","reading":"かたづけるそばから、こどもがちらかす。","english":"As fast as I tidy up, the children make a mess again."},{"japanese":"覚えるそばから忘れてしまいます。","reading":"おぼえるそばからわすれてしまいます。","english":"Right after learning something, I forget it."},{"japanese":"教えたそばから、また同じミスをしました。","reading":"おしえたそばから、またおなじミスをしました。","english":"Right after I taught him, he made the same mistake again."}]', 'conjunction', 0, 57);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜が最後 (once ... happens, it''s all over)', 'V-たが最後', 'Once that happens, it''s all over — an action that sets off an irreversible chain', 'たが最後 expresses that once a certain action occurs, something undesirable (and usually irreversible) will follow. It implies a point of no return. Similar in structure to やいなや but always with a negative or irrevocable outcome.', '[{"japanese":"彼に話しかけたが最後、1時間は帰れない。","reading":"かれにはなしかけたがさいご、1じかんはかえれない。","english":"Once you start talking to him, you won''t be able to leave for an hour."},{"japanese":"その薬を飲んだが最後、もう戻れない。","reading":"そのくすりをのんだがさいご、もうもどれない。","english":"Once you take that medicine, there''s no going back."},{"japanese":"彼女に頼まれたが最後、断れなくなってしまう。","reading":"かのじょにたのまれたがさいご、ことわれなくなってしまう。","english":"Once she asks you, you won''t be able to refuse."}]', 'expression', 0, 58);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ないまでも (if not X, at least Y)', 'V-ない + までも', 'If not ... at least / even if not fully — a lesser degree is still acceptable or possible', 'ないまでも expresses that while the full extent may not be achieved, at least a lesser degree is possible or acceptable. ''Even if not X, at least Y''. Used to present a realistic minimum expectation.', '[{"japanese":"完璧でないまでも、なんとか形にはなりました。","reading":"かんぺきでないまでも、なんとかかたちにはなりました。","english":"Even if not perfect, it at least took shape somehow."},{"japanese":"毎日でないまでも、週に一度は連絡してください。","reading":"まいにちでないまでも、しゅうにいちどはれんらくしてください。","english":"If not every day, at least contact me once a week."},{"japanese":"理解できないまでも、努力することは大切だ。","reading":"りかいできないまでも、どりょくすることはたいせつだ。","english":"Even if you can''t fully understand, it''s important to try."}]', 'expression', 0, 59);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ようが〜ようが / ようと〜ようと (no matter how / regardless)', 'V-volitional + が + V-volitional + が / ようと〜ようと', 'No matter how / regardless of what — expresses that the result holds regardless of any effort or variation', 'ようが〜ようが (or ようと〜ようと) covers all possibilities of effort or variation, saying the result is the same regardless. More formal and emphatic than ても. Often lists two contrasting options.', '[{"japanese":"どんなに反対しようが、私は行きます。","reading":"どんなにはんたいしようが、わたしはいきます。","english":"No matter how much you oppose it, I will go."},{"japanese":"雨が降ろうが雪が降ろうが、試合は続けます。","reading":"あめがふろうがゆきがふろうが、しあいはつづけます。","english":"Whether it rains or snows, the match will continue."},{"japanese":"何を言われようと、気にしません。","reading":"なにをいわれようと、きにしません。","english":"No matter what is said, I don''t care."}]', 'conditional', 0, 60);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜といわず〜といわず (whether it''s ... or ... everywhere/everything)', 'N + といわず + N + といわず', 'Whether it''s ... or ... / everywhere — total coverage without exception', 'といわず〜といわず covers all cases comprehensively, meaning ''not just X or Y, but everything''. It implies that something applies universally, not limited to the items named. More emphatic than も〜も.', '[{"japanese":"手といわず顔といわず、泥だらけになった。","reading":"てといわずかおといわず、どろだらけになった。","english":"His hands, face — everything was covered in mud."},{"japanese":"平日といわず休日といわず、働き続けた。","reading":"へいじつといわずきゅうじつといわず、はたらきつづけた。","english":"Whether weekdays or holidays, he kept working."},{"japanese":"男といわず女といわず、皆が参加した。","reading":"おとこといわずおんなといわず、みながさんかした。","english":"Whether men or women, everyone participated."}]', 'expression', 0, 61);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜とは裏腹に (contrary to / in contrast to)', 'N / S (plain) + とは裏腹に', 'Contrary to / in contrast to — reality is the opposite of what was expected or stated', 'とは裏腹に means the reality is ironically contrary to the stated expectation, appearance, or claim. Similar to に反して but carries a stronger sense of irony or unexpected reversal.', '[{"japanese":"笑顔とは裏腹に、心の中は悲しかった。","reading":"えがおとはうらはらに、こころのなかはかなしかった。","english":"Contrary to the smile, the heart was sad."},{"japanese":"外見とは裏腹に、とても優しい人です。","reading":"がいけんとはうらはらに、とてもやさしいひとです。","english":"Contrary to appearances, he is a very kind person."},{"japanese":"予想とは裏腹に、試験結果は悪かった。","reading":"よそうとはうらはらに、しけんけっかはわるかった。","english":"Contrary to expectations, the exam results were poor."}]', 'expression', 0, 62);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ことのないよう (so that ... will not happen — preventive care)', 'V (plain non-past) + ことのないよう / ことのないように', 'So that ... will not happen — taking care to prevent an undesirable outcome', 'ことのないよう expresses that one takes care or prepares so that an undesirable event will not occur. More formal than ないように and often used in instructions, warnings, or careful planning contexts.', '[{"japanese":"怪我のないよう、気をつけてください。","reading":"けがのないよう、きをつけてください。","english":"Please be careful so that no injuries occur."},{"japanese":"同じミスが起こることのないよう、対策を講じます。","reading":"おなじミスがおこることのないよう、たいさくをこうじます。","english":"I will take measures so that the same mistake will not occur again."},{"japanese":"不満が生じることのないよう、丁寧に対応します。","reading":"ふまんがしょうじることのないよう、ていねいにたいおうします。","english":"I will respond carefully so that no dissatisfaction arises."}]', 'formal', 0, 63);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にひきかえ (in contrast to / unlike)', 'N + にひきかえ', 'In contrast to / unlike — sharp contrast between two things or people', 'にひきかえ expresses a sharp contrast between two things, often with an evaluative nuance. It highlights that Y is notably different (usually better or worse) compared to X. More emphatic than に比べて or 一方で.', '[{"japanese":"兄にひきかえ、弟はよく勉強します。","reading":"あににひきかえ、おとうとはよくべんきょうします。","english":"In contrast to his older brother, the younger brother studies a lot."},{"japanese":"去年にひきかえ、今年は天気がいいですね。","reading":"きょねんにひきかえ、ことしはてんきがいいですね。","english":"In contrast to last year, the weather is nice this year."},{"japanese":"あの人にひきかえ、あなたは本当に誠実ですね。","reading":"あのひとにひきかえ、あなたはほんとうにせいじつですね。","english":"In contrast to that person, you are truly sincere."}]', 'expression', 0, 64);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ないではすまない (won''t do without / obligated)', 'V-ない + ではすまない', 'Won''t be resolved without / obligated — situation demands the action be done', 'ないではすまない expresses that the situation demands the action; without it, things will not be settled or resolved properly. Social, moral, or situational pressure compels the action. More formal than なければならない and emphasises the external pressure.', '[{"japanese":"こんな大きなミスは謝らないではすまない。","reading":"こんなおおきなミスはあやまらないではすまない。","english":"For such a large mistake, it won''t do without an apology."},{"japanese":"彼が傷ついたなら、説明しないではすまないだろう。","reading":"かれがきずついたなら、せつめいしないではすまないだろう。","english":"If he was hurt, it won''t do without an explanation."},{"japanese":"規則を破ったからには、何らかの責任を取らないではすまない。","reading":"きそくをやぶったからには、なんらかのせきにんをとらないではすまない。","english":"Having broken the rules, it won''t do without taking some form of responsibility."}]', 'expression', 0, 65);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜いかんを問わず (regardless of — very formal)', 'N + のいかんを問わず', 'Regardless of / irrespective of — very formal absolute non-condition', 'いかんを問わず is the most formal way to say ''regardless of''. 問わず adds ''without questioning'', making it absolute. Used in official policies, proclamations, and formal documents. More emphatic than にかかわらず.', '[{"japanese":"理由のいかんを問わず、遅刻は認められません。","reading":"りゆうのいかんをとわず、ちこくはみとめられません。","english":"Regardless of the reason, tardiness is not permitted."},{"japanese":"性別のいかんを問わず、全員が参加できます。","reading":"せいべつのいかんをとわず、ぜんいんがさんかできます。","english":"Regardless of gender, everyone can participate."},{"japanese":"国籍のいかんを問わず、応募を受け付けます。","reading":"こくせきのいかんをとわず、おうぼをうけつけます。","english":"Applications will be accepted regardless of nationality."}]', 'formal', 0, 66);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にかかわる (to involve / to be at stake)', 'N + にかかわる + N', 'Involving / at stake / concerning — marks something as vitally related to', 'にかかわる as an attributive verb means ''involving / concerning / that affects''. It indicates the noun is implicated or at stake. 命にかかわる = life-threatening; 名誉にかかわる = involving one''s honour. Used in serious contexts.', '[{"japanese":"これは命にかかわる問題です。","reading":"これはいのちにかかわるもんだいです。","english":"This is a matter that involves life and death."},{"japanese":"会社の信頼にかかわる不祥事が発覚した。","reading":"かいしゃのしんらいにかかわるふしょうじがはっかくした。","english":"A scandal involving the company''s trust was uncovered."},{"japanese":"名誉にかかわる問題は慎重に扱うべきだ。","reading":"めいよにかかわるもんだいはしんちょうにあつかうべきだ。","english":"Matters involving one''s honour should be handled carefully."}]', 'expression', 0, 67);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に事欠かない (never short of / there is no lack of)', 'N + に事欠かない', 'Never lacking in / there is no shortage of — something is abundantly present', 'に事欠かない means ''there is no shortage of X'' or ''X is abundantly available''. Often used when there are more examples, opportunities, or instances than needed. Can be used with a slightly sarcastic tone when referring to problems.', '[{"japanese":"話題に事欠かない賑やかな場所です。","reading":"わだいにことかかないにぎやかなばしょです。","english":"It is a lively place that is never short of topics of conversation."},{"japanese":"問題に事欠かない職場で働いています。","reading":"もんだいにことかかないしょくばではたらいています。","english":"I work in a workplace that never lacks for problems."},{"japanese":"この街は観光スポットに事欠きません。","reading":"このまちはかんこうスポットにことかきません。","english":"This town never lacks tourist attractions."}]', 'expression', 0, 68);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜にかたくない (not hard to / easy to imagine/understand)', 'V (plain non-past) + にかたくない', 'Not hard to / easy to — something is easily imaginable or understandable', 'にかたくない (not difficult to) expresses that an action (usually imagining, understanding, or guessing) is easy given the circumstances. Common pattern: 想像にかたくない = not hard to imagine. Formal and literary.', '[{"japanese":"彼の苦しみは想像にかたくない。","reading":"かれのくるしみはそうぞうにかたくない。","english":"His suffering is not hard to imagine."},{"japanese":"その結果が失望をもたらしたことは理解にかたくない。","reading":"そのけっかがしつぼうをもたらしたことはりかいにかたくない。","english":"It is not hard to understand that the result brought disappointment."},{"japanese":"合格した彼女の喜びは察するにかたくない。","reading":"ごうかくしたかのじょのよろこびはさっするにかたくない。","english":"Her joy at passing is not hard to sense."}]', 'formal', 0, 69);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜だに (even — emphasis on a minimal case)', 'N + だに / V-stem + だに', 'Even / just the thought of — formal emphasis that even the minimal degree is significant', 'だに is a classical/formal particle meaning ''even''. 考えるだに恐ろしい = even the thought of it is frightening. It marks a minimal degree that is still sufficient to trigger the following reaction. Literary and rarely conversational.', '[{"japanese":"考えるだに恐ろしい出来事があった。","reading":"かんがえるだにおそろしいできごとがあった。","english":"There was an event that was frightening even to think about."},{"japanese":"想像するだに背筋が寒くなります。","reading":"そうぞうするだにせすじがさむくなります。","english":"Even imagining it sends a chill down my spine."},{"japanese":"その恐怖はいまだに思い出すだに震えが来る。","reading":"そのきょうふはいまだにおもいだすだにふるえがくる。","english":"That fear — even now, just recalling it makes me tremble."}]', 'formal', 0, 70);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ては〜ては (repeatedly doing — cycle of actions)', 'V-て + は + V-て + は', 'Doing X and Y repeatedly — describes a repeated cycle of actions', 'ては〜ては describes a recurring pattern of two alternating actions. It can also express a repeated problematic cycle (失敗しては立ち上がる = failing and getting back up, over and over). Emphasises the repetitive nature.', '[{"japanese":"書いては消し、書いては消しを繰り返した。","reading":"かいてはけし、かいてはけしをくりかえした。","english":"I kept writing and erasing, writing and erasing."},{"japanese":"転んでは立ち上がり、何度も挑戦しました。","reading":"ころんではたちあがり、なんどもちょうせんしました。","english":"Falling and getting back up, I challenged again and again."},{"japanese":"読んでは考え、考えては読むという学び方です。","reading":"よんではかんがえ、かんがえてはよむというまなびかたです。","english":"It is a learning style of reading and thinking, thinking and reading."}]', 'verb-form', 0, 71);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜を禁じ得ない (cannot suppress / cannot help feeling)', 'N + を禁じ得ない / V-stem + を禁じ得ない', 'Cannot suppress / cannot help but feel — an emotion that arises unstoppably', 'を禁じ得ない means the speaker cannot suppress or hold back the emotion named. More formal and literary than ずにはいられない for emotions. Common with 涙 (tears), 怒り (anger), 同情 (sympathy), 驚き (surprise).', '[{"japanese":"その話を聞いて、涙を禁じ得ませんでした。","reading":"そのはなしをきいて、なみだをきんじえませんでした。","english":"Hearing that story, I could not suppress my tears."},{"japanese":"彼の態度には怒りを禁じ得ない。","reading":"かれのたいどにはいかりをきんじえない。","english":"I cannot suppress my anger at his attitude."},{"japanese":"その惨状には同情を禁じ得ませんでした。","reading":"そのさんじょうにはどうじょうをきんじえませんでした。","english":"I could not help but feel sympathy for that tragic situation."}]', 'formal', 0, 72);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜をかわきりに (beginning with — first triggering event in a series)', 'N + をかわきりに(して)', 'Starting with / beginning from — the first event that triggered a series', 'をかわきりに marks the opening act that set off a chain of events. Same as を皮切りに but written differently (both are read をかわきりに). Used in formal and journalistic contexts to describe momentum building from a starting point.', '[{"japanese":"彼のスピーチをかわきりに、各国の代表が発言した。","reading":"かれのスピーチをかわきりに、かっこくのだいひょうがはつげんした。","english":"Starting with his speech, representatives from each country began to speak."},{"japanese":"一人の抗議をかわきりに、大きなデモが始まった。","reading":"ひとりのこうぎをかわきりに、おおきなデモがはじまった。","english":"Starting with one person''s protest, a large demonstration began."},{"japanese":"この発見をかわきりにして、研究が加速した。","reading":"このはっけんをかわきりにして、けんきゅうがかそくした。","english":"Starting from this discovery, research accelerated."}]', 'expression', 0, 73);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ことだから (given that it''s ... / knowing ...)', 'N + のことだから', 'Given that it''s [person/thing] / knowing [their nature] — inference based on known character', 'のことだから (usually with a person''s name or character type) means ''given that it''s [person], it''s natural to expect...''. The speaker reasons based on what they know about the person''s character or the nature of the thing. Familiar and confident inference.', '[{"japanese":"田中さんのことだから、きっとうまくやるでしょう。","reading":"たなかさんのことだから、きっとうまくやるでしょう。","english":"Knowing Tanaka-san, he will surely handle it well."},{"japanese":"彼のことだから、約束の時間には絶対に来ると思います。","reading":"かれのことだから、やくそくのじかんにはぜったいにくるとおもいます。","english":"Knowing him, I''m sure he''ll come at the promised time."},{"japanese":"この店のことだから、品質は保証できます。","reading":"このみせのことだから、ひんしつはほしょうできます。","english":"Knowing this shop, I can guarantee the quality."}]', 'expression', 0, 74);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜べくもない (there is no way / cannot possibly)', 'V (plain non-past) + べくもない', 'There is no way to / cannot possibly — complete impossibility of action or outcome', 'べくもない is a formal/literary expression for impossibility. 知るべくもない = there is no way to know; 想像するべくもない = it cannot possibly be imagined. More literary than できない or ようがない.', '[{"japanese":"当時の状況は想像するべくもありません。","reading":"とうじのじょうきょうはそうぞうするべくもありません。","english":"There is no way to imagine the situation at that time."},{"japanese":"真実は私たちには知るべくもない。","reading":"しんじつはわたしたちにはしるべくもない。","english":"The truth is something we have no way of knowing."},{"japanese":"そのような才能は凡人には持つべくもない。","reading":"そのようなさいのうはぼんじんにはもつべくもない。","english":"Such talent is something ordinary people cannot possibly possess."}]', 'formal', 0, 75);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜なくして(は) (without ... it is impossible)', 'N + なくして(は) / V-ない + なくして(は)', 'Without — formal assertion that something is absolutely indispensable', 'なくして(は) is the formal literary equivalent of なしに(は), meaning ''without X, Y is impossible''. The は adds a conditional sense. More emphatic and literary than なしに. Often used in speeches and formal writing.', '[{"japanese":"信頼なくして、友情は成り立たない。","reading":"しんらいなくして、ゆうじょうはなりたたない。","english":"Without trust, friendship cannot exist."},{"japanese":"努力なくして、成功はあり得ない。","reading":"どりょくなくして、せいこうはありえない。","english":"Without effort, success is impossible."},{"japanese":"お互いの理解なくしては、解決できません。","reading":"おたがいのりかいなくしては、かいけつできません。","english":"Without mutual understanding, there can be no resolution."}]', 'formal', 0, 76);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜に相まって (combined with / together with — synergistic)', 'N + に相まって', 'Combined with / along with — two positive elements combine to produce a stronger effect', 'に相まって expresses that two factors combine or interact to produce an enhanced effect. Both elements reinforce each other. Used in formal and journalistic contexts to describe synergistic combinations.', '[{"japanese":"才能に相まって、努力が実を結びました。","reading":"さいのうにあいまって、どりょくがみをむすびました。","english":"Combined with talent, effort bore fruit."},{"japanese":"暖かい気候に相まって、農業が盛んです。","reading":"あたたかいきこうにあいまって、のうぎょうがさかんです。","english":"Combined with the warm climate, agriculture is thriving."},{"japanese":"SNSの普及に相まって、情報の拡散が速くなっています。","reading":"SNSのふきゅうにあいまって、じょうほうのかくさんがはやくなっています。","english":"Combined with the spread of social media, information is spreading more quickly."}]', 'expression', 0, 77);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜ずとも (even without / even if not)', 'V-ない stem + ずとも', 'Even without / even if not — formal; even if the condition doesn''t hold, the result follows', 'ずとも is the formal/literary equivalent of なくても (even without). 言わずとも = even without saying; 見ずとも = even without seeing. Common in set expressions and literary contexts. する → せずとも.', '[{"japanese":"言わずとも、彼には分かっていると思います。","reading":"いわずとも、かれにはわかっているとおもいます。","english":"Even without saying it, I think he already knows."},{"japanese":"急がずとも、時間は十分にあります。","reading":"いそがずとも、じかんはじゅうぶんにあります。","english":"Even without hurrying, there is plenty of time."},{"japanese":"説明せずとも、状況は明らかです。","reading":"せつめいせずとも、じょうきょうはあきらかです。","english":"Even without explanation, the situation is clear."}]', 'formal', 0, 78);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜よしもない (there is no way to / no means to)', 'V (plain non-past) + よしもない', 'There is no way to / no means of — complete impossibility from lack of means', 'よしもない (also: よしがない) is a formal/literary expression meaning ''there is no means / no way''. Similar to ようがない but more literary. 知るよしもない = there is no way of knowing. Yoshimono as ''means/method''.', '[{"japanese":"真相を知るよしもなかった。","reading":"しんそうをしるよしもなかった。","english":"There was no way to know the truth."},{"japanese":"彼がどこにいるか、今となっては知るよしもない。","reading":"かれがどこにいるか、いまとなってはしるよしもない。","english":"Where he is now, there is no way to know at this point."},{"japanese":"当時は将来がどうなるか、知るよしもなかった。","reading":"とうじはしょうらいがどうなるか、しるよしもなかった。","english":"At that time, there was no way of knowing what the future would hold."}]', 'formal', 0, 79);
INSERT OR IGNORE INTO grammar_points (jlpt_level, title, pattern, meaning, explanation, examples_json, category, is_keigo, frequency_rank) VALUES ('N1', '〜すら (even — formal emphasis on extreme case)', 'N + すら / V-stem + すら', 'Even — marks an extreme or surprising case; formal equivalent of さえ', 'すら is a formal/literary particle meaning ''even'', equivalent to casual さえ. It marks a surprising or extreme case: if even this (the minimum or most surprising) is true, how much more so others. Used in formal and literary writing.', '[{"japanese":"彼は自分の名前すら書けない状態だった。","reading":"かれはじぶんのなまえすらかけないじょうたいだった。","english":"He was in a state where he couldn''t even write his own name."},{"japanese":"専門家すら解けない問題です。","reading":"せんもんかすらとけないもんだいです。","english":"It is a problem that even experts cannot solve."},{"japanese":"一瞬すら気を抜けない状況が続いています。","reading":"いっしゅんすらきをぬけないじょうきょうがつづいています。","english":"A situation where I cannot let my guard down even for an instant continues."}]', 'particle', 0, 80);

INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N5', 'fill_blank', '田中さん___学生です。', '["は","が","を","に"]', 'は', 'は marks the topic of the sentence.', 'pregenerated');
