INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N5', 'fill_blank', 'これは何___すか。', '["で","が","は","を"]', 'で', '何ですか uses で as part of the copula.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N5', 'fill_blank', '毎朝ご飯を食べ___。', '["ます","です","だ","る"]', 'ます', 'ます is the polite non-past verb ending.', 'pregenerated');
