INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N5', 'fill_blank', '彼は結婚し___います。', '["て","で","に","は"]', 'て', 'ています expresses a resulting state: he is married.', 'pregenerated');
