INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '空が暗くなってきた。雨が降り___。', '["そうだ","ようだ","みたいだ","らしい"]', 'そうだ', 'そうだ (looks like it''s about to ~) — the sky has gotten dark. It looks like it''s going to rain.', 'pregenerated');
