INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼女の詩は、彼女自身の経験___書かれている。', '["をもとに","を通して","によって","のために"]', 'をもとに', 'をもとに (based on) — her poems are written based on her own experiences.', 'pregenerated');
