INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '宿題を終わらせ___、ゲームをしてはいけない。', '["ないうちは","ないなら","ないから","ないので"]', 'ないうちは', 'ないうちは (as long as you haven''t ~) — as long as you haven''t finished your homework, you can''t play games.', 'pregenerated');
