INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この問題について、一度専門家___みた。', '["に聞いて","を聞いて","が聞いて","で聞いて"]', 'に聞いて', 'に聞く (ask ~) — I tried asking an expert about this problem.', 'pregenerated');
