INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この問題は簡単___ので、すぐに解けた。', '["だった","のだった","だろう","だから"]', 'だった', '簡単だったので (because it was easy) — because this problem was easy, I solved it immediately.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この薬を飲ん___でも、痛みが止まらない。', '["で","も","から","のに"]', 'で', '飲んでも (even if I take / even after taking) — even after taking this medicine, the pain doesn''t stop.', 'pregenerated');
