INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'コーヒーを飲み___、本を読んでいた。', '["ながら","つつ","まま","ばかりで"]', 'ながら', 'ながら (while ~ing) — I was reading a book while drinking coffee.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '難しい試験でも、合格でき___のではないか。', '["る","た","る","て"]', 'る', 'のではないか (I wonder if ~ / don''t you think ~?) — even for a difficult exam, I wonder if you can pass it.', 'pregenerated');
