INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '良い習慣を___、生活の質が上がる。', '["身につけることで","身につけてから","身につけるために","身につけるなら"]', '身につけることで', 'ことで (by / through ~ing) — by developing good habits, the quality of life improves.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼は料理が上手い___、手際もいい。', '["うえに","のに","くせに","ながら"]', 'うえに', '上に (in addition to / on top of) — in addition to being good at cooking, he is also skillful.', 'pregenerated');
