INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '試合が近づく___、練習の量を増やした。', '["につれて","にとって","によって","として"]', 'につれて', 'につれて (as ~ / in proportion to) — as the match approached, I increased the amount of practice.', 'pregenerated');
