INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼女はこの会社のトップ___、全員から尊敬されている。', '["として","にとって","によって","に対して"]', 'として', 'として (as / in the role of) — as the top of this company, she is respected by everyone.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '寒い___も、毎日外に出て運動している。', '["くて","くても","くなく","くなくて"]', 'くても', 'くても (even if it''s ~ / even though it''s ~) — even though it''s cold, I go outside and exercise every day.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この法律___、全ての人が平等に扱われるべきだ。', '["によれば","によって","に従って","に応じて"]', 'によれば', 'によれば (according to) — according to this law, all people should be treated equally.', 'pregenerated');
