INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この施設は高齢者___設計されている。', '["向けに","のために","として","によって"]', '向けに', '向けに (aimed at / designed for) — this facility is designed for elderly people.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼は転んで___いたが、すぐに立ち上がった。', '["し","み","き","お"]', 'し', 'てしまっていた (had ~ed completely) — he had fallen, but he got right back up.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '今年こそ、試験に___てみせる。', '["合格し","合格して","合格する","合格した"]', '合格し', 'てみせる (will definitely do ~ / will show that I can) — this year for sure, I will show that I can pass the exam.', 'pregenerated');
