INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼の作品は世界___に展示されている。', '["中","じゅう","の中","全体"]', '中', '世界中 (throughout the world / all over the world) — his works are displayed throughout the world.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', 'この資料___、発表の準備をした。', '["をもとに","を通して","によって","として"]', 'をもとに', 'をもとに (based on) — I prepared the presentation based on these materials.', 'pregenerated');
INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '彼女は___ながら、一生懸命働いた。', '["病気であり","病気で","病気なのに","病気だから"]', '病気であり', 'でありながら (while being ~ / despite being ~) — despite being sick, she worked hard.', 'pregenerated');
