INSERT INTO questions (grammar_point_id, jlpt_level, question_type, prompt, options_json, answer, explanation, source) VALUES (NULL, 'N3', 'fill_blank', '忙しい___、少しだけ手伝ってもらえますか。', '["ところ","から","ので","のに"]', 'ところ', 'ところ (while in the middle of ~ / I know you''re busy but) — I know you''re busy, but could you help me just a little?', 'pregenerated');
